mapper.select:
        SELECT /*+ PARALLEL(4)*/ COUNT(A.RNMCNO) AS TOTALCOUNT
          FROM NIC01B A
              ,NIC35B C
         WHERE A.RNMCNO = C.RNMCNO

           AND C.RNMCNO =  #{RNMCNO}


           AND A.CS_NM =#{CS_INPUT}


		   AND C.RSK_GRD_CD = #{RSK_GRD_CD} 


           AND A.CS_MANAG_BRN_CD = #{CS_EDD_EXCTN_BRN_CD}


           AND A.INDV_CORP_CCD  = #{INDV_CORP_CCD}


           AND C.AML_CRT_DT BETWEEN  #{RSK_GRD_RGST_DT_SD} AND  #{RSK_GRD_RGST_DT_ED}


           AND C.RSK_GRD_CD <>  FN_NVL( C.PRV_RSK_GRD_CD, '-')

SELECT * FROM ( SELECT COUNT(*) OVER() AS TOTALCOUNT, ROWNUM AS NU, V.* FROM ( SELECT /*+ PARALLEL(4)*/ A.CS_NM , A.CS_NO , A.CS_NO AS AML_CUST_ID , C.AML_CRT_DT AS RSK_GRD_RGST_DT , (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = A.CS_EXCTN_BRN_CD) CS_EXCTN_BRN_NM , (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = A.CS_MANAG_BRN_CD) CS_MANAG_BRN_NM , A.CS_EXCTN_BRN_CD , A.CS_MANAG_BRN_CD , CASE C.CS_EDD_MNG_F WHEN '1' THEN 'Y' ELSE '' END AS CS_EDD_MNG_F , C.WL_TRD_CON_F AS TRD_CON , (SELECT CD_NM FROM NIC92B WHERE CD = 'A006' AND CNTNT = C.WL_TRD_CON_F) AS TRD_CON_F , C.RSK_GRD_CD AS RSK_GRD_CD_NM , C.RSK_GRD_CD AS RSK_GRD_CD , C.LST_RSK_EAL_SOR , A.RNMCNO , CASE A.RNM_CNFR_CCD WHEN '01' THEN SUBSTR(A.RNMCNO, 0,6) || '-' ||SUBSTR(A.RNMCNO, 7,7) WHEN '02' THEN SUBSTR(A.RNMCNO, 0,3) || '-' ||SUBSTR(A.RNMCNO, 4,2) || '-' || SUBSTR(A.RNMCNO, 6,5) ELSE A.RNMCNO END AS RNMCNO_VIEW , A.INDV_CORP_CCD -- 개인법인구분 , A.CS_TYP_CD -- 고객유형 , C.PRV_RSK_GRD_CD -- 이전 위험등급 , FN_REQ_ING_NM(A.RNMCNO,#{LANG_CD}) AS REQ_ING_NM , C.CS_EDD_STS_CD AS EDD_REG , GET_CODE_NAME('A002',C.CS_EDD_STS_CD) AS EDD_REG_YN -- EDD 등록 상태 , C.AML_CRT_DT FROM NIC01B A , NIC35B C WHERE A.RNMCNO = C.RNMCNO
ORDER BY
CS_NM CS_NO RSK_GRD_RGST_DT CS_MANAG_BRN_CD CS_EXCTN_BRN_CD LST_RSK_EAL_SOR DECODE(RSK_GRD_CD_NM, 'H', 1, 'M', 2, 'L', 3) DECODE(PRV_RSK_GRD_CD, 'H', 1, 'M', 2, 'L', 3)
ASCDESC
ORDER BY C.AML_CRT_DT DESC, A.CS_NM
)V WHERE 1=1
AND V.RNMCNO = #{RNMCNO}
AND V.CS_NM =#{CS_INPUT}
AND V.RSK_GRD_CD = #{RSK_GRD_CD}
AND V.CS_MANAG_BRN_CD = #{CS_EDD_EXCTN_BRN_CD}
AND V.INDV_CORP_CCD = #{INDV_CORP_CCD}
AND V.AML_CRT_DT BETWEEN #{RSK_GRD_RGST_DT_SD} AND #{RSK_GRD_RGST_DT_ED}
AND V.RSK_GRD_CD <> FN_NVL( V.PRV_RSK_GRD_CD,'-')
)T WHERE 1=1
AND T.NU >= ( ( #{thisPage} - 1 ) * #{pageCount} + 1 ) AND T.NU <= ( #{thisPage} * #{pageCount} )

SELECT * FROM ( SELECT COUNT(*) OVER() AS TOTALCOUNT, ROWNUM AS NU, V.* FROM ( SELECT C.LST_RSK_EAL_DT ,A.CS_NM ,A.AML_CUST_ID ,C.AML_CRT_DT AS RSK_GRD_RGST_DT ,(SELECT E.DPRT_NM FROM NIC41B E WHERE E.DPRT_CD = A.CS_EXCTN_BRN_CD) CS_EXCTN_BRN_CD ,(SELECT F.DPRT_NM FROM NIC41B F WHERE F.DPRT_CD = A.CS_MANAG_BRN_CD) CS_MANAG_BRN_CD ,CASE C.CS_EDD_MNG_F WHEN '1' THEN 'Y' ELSE '' END AS CS_EDD_MNG_F ,C.WL_TRD_CON_F AS TRD_CON ,(SELECT G.CD_NM FROM NIC92B G WHERE G.CD = 'A006' AND G.CNTNT = C.WL_TRD_CON_F) AS TRD_CON_F ,D.AI_RA_GRD_CD AS AI_GRD_CD ,C.RSK_GRD_CD AS RSK_GRD_CD_NM ,C.RSK_GRD_CD AS RSK_GRD_CD ,C.LST_RSK_EAL_SOR ,A.RNMCNO ,A.RNMCNO AS RNMCNO_VIEW ,A.INDV_CORP_CCD -- 개인법인구분 ,GET_CODE_NAME('M012', A.CS_TYP_CD) AS CS_TYP_CD_NM ,A.CS_TYP_CD -- 고객유형 ,C.PRV_RSK_GRD_CD -- 이전 위험등급 ,C.CS_EDD_STS_CD AS EDD_REG ,GET_CODE_NAME('A002',C.CS_EDD_STS_CD) AS EDD_REG_YN -- EDD 등록 상태 ,C.AML_CRT_DT FROM NIC01B A ,NIC35B C LEFT JOIN AI_RA_RSLT D ON C.AML_CUST_ID = D.AML_CUST_ID WHERE A.AML_CUST_ID = C.AML_CUST_ID
ORDER BY
CS_NM RSK_GRD_RGST_DT CS_EXCTN_BRN_CD CS_MANAG_BRN_CD LST_RSK_EAL_SOR DECODE(AI_GRD_CD, 'H', 1, 'M', 2, 'L', 3) DECODE(RSK_GRD_CD_NM, 'H', 1, 'M', 2, 'L', 3) DECODE(PRV_RSK_GRD_CD, 'H', 1, 'M', 2, 'L', 3)
ASCDESC
ORDER BY LST_RSK_EAL_DT DESC, CS_NM
) V WHERE 1=1
AND V.AML_CUST_ID = #{AML_CUST_ID}
AND V.CS_NM = #{CS_INPUT}
AND V.CS_MANAG_BRN_CD = #{CS_EDD_EXCTN_BRN_CD}
AND V.CS_TYP_CD = #{CS_TYP_CD}
AND V.RSK_GRD_RGST_DT BETWEEN #{RSK_GRD_RGST_DT_SD} AND #{RSK_GRD_RGST_DT_ED}
AND V.RSK_GRD_CD <> FN_NVL( V.PRV_RSK_GRD_CD,'-')
) T WHERE 1=1
AND T.NU >= ( ( #{thisPage} - 1 ) * #{pageCount} + 1 ) AND T.NU <= ( #{thisPage} * #{pageCount} )

SELECT A.CS_NM -- 고객명 ,A.AML_CUST_ID -- 실명번호 ,CASE A.RNM_CNFR_CCD WHEN '01' THEN SUBSTR(A.RNMCNO, 0,6) || '-' ||SUBSTR(A.RNMCNO, 7,7) WHEN '02' THEN SUBSTR(A.RNMCNO, 0,3) || '-' ||SUBSTR(A.RNMCNO, 4,2) || '-' || SUBSTR(A.RNMCNO, 6,5) ELSE A.RNMCNO END AS RNMCNO_VIEW ,(SELECT M.CD_NM FROM NIC92B M WHERE M.CD='A002' AND M.CNTNT = A.CS_EDD_STS_CD) CS_EDD_ST_CD -- 고객EDD 상태코드 ,A.CS_EDD_REG_DT AS EDD_REG_DT -- EDD 등록일자 ,A.CS_EDD_RFSL_DT AS EDD_REP_DT -- EDD 거부일자 ,CASE WHEN NVL(A.CTR_RPR_TNO, 0) + NVL(A.STR_RPR_TNO, 0) > 0 THEN 'Y' ELSE 'N' END AS FIU_RPR_F --FIU 보고여부 ,( SELECT N.CD_NM FROM NIC92B N WHERE N.CD = 'M002' AND N.CNTNT = A.RNM_CNFR_CCD) RNM_CNFR_CCD -- 실명확인구분 ,GET_DEP_NAME( B.BRN_CD ) AS CS_EDD_ST_UPT_BRN_CD_NM -- EDD 요청 지점 ,A.CS_EDD_MK_DT -- EDD승인일 ,A.RNMCNO ,A.CTR_RPR_TNO ,A.STR_RPR_TNO ,A.INDV_CORP_CCD -- 개인법인구분 ,A.RSK_GRD_RGST_DT -- 위험등급등록일 FROM VIC01B A LEFT OUTER JOIN NIC36B B ON (A.AML_CUST_ID = B.AML_CUST_ID AND B.HNDL_DT = A.CS_EDD_MK_DT AND B.KYC_CCD = 'E' ) WHERE A.CS_EDD_MNG_F = '1' AND A.WL_TRD_CON_F = 0
AND A.INDV_CORP_CCD = #{INDV_CORP_CCD}
AND A.CS_EDD_STS_CD = #{CS_EDD_ST_CD}
AND A.AML_CUST_ID IN ( SELECT X.AML_CUST_ID FROM NIC17B X WHERE X.MN_DL_DPRT_CD = #{CS_EDD_ST_UPT_BRN_CD} )
AND A.RSK_GRD_CD = #{RSK_GRD_CD}
AND A.CS_EDD_MK_DT BETWEEN #{CS_EDD_MK_DT_SD} || '000000' AND #{CS_EDD_MK_DT_ED} || '235959'

SELECT /*+ FULL(A) FULL(B) PARALLEL(A 4) PARALLEL(B 4) */ (SELECT M.DPRT_NM FROM NIC41B M WHERE M.DPRT_CD = A.CS_EXCTN_BRN_CD) BRANCH ,A.TOT_CNT ,A.CNT1 ,TRIM(TO_CHAR(A.CNT1/A.TOT_CNT*100,'990.00')) RATE1 ,A.CNT2 ,TRIM(TO_CHAR(A.CNT2/A.TOT_CNT*100,'990.00')) RATE2 ,A.CNT3 ,TRIM(TO_CHAR(A.CNT3/A.TOT_CNT*100,'990.00')) RATE3 ,A.CS_EXCTN_BRN_CD FROM ( SELECT A.CS_EXCTN_BRN_CD ,COUNT(*) TOT_CNT ,SUM(CASE WHEN (B.CS_EDD_STS_CD='A' OR B.CS_EDD_MNG_F IS NULL) THEN 1 ELSE 0 END) CNT1 ,SUM(CASE WHEN B.CS_EDD_STS_CD='B' THEN 1 ELSE 0 END) CNT2 ,SUM(CASE WHEN B.CS_EDD_STS_CD='C' THEN 1 ELSE 0 END) CNT3 FROM NIC01B A, NIC35B B WHERE A.AML_CUST_ID = B.AML_CUST_ID AND B.CS_EDD_MNG_F='1' AND B.WL_TRD_CON_F='0'
AND A.CS_EXCTN_BRN_CD LIKE #{CS_EDD_ST_UPT_BRN_CD} || '%'
AND B.RSK_GRD_CD = #{RSK_GRD_CD}
AND A.INDV_CORP_CCD = #{CS_TYPE}
GROUP BY A.CS_EXCTN_BRN_CD ) A ORDER BY A.CS_EXCTN_BRN_CD

