mapper.insert:
INSERT INTO NIC12B
            (AML_CUST_ID                        -- 실명확인번호
            ,MAIN_ACTN_ZONE_NM                  -- 주요활동지역구분코드
            ,CMPNY_ORGNZTN_AND_STRCT_CNTNT      -- 회사체계및구조내용
            ,FNDTN_OBJ_NM                       -- 설립목적명
            ,OTR_NPRFT_OGN_CNCT_RLTNS_CNTNT     -- 타비영리기관협력관계내용
            ,CRNBTN_P_INFO                      -- 기부자정보코드
            ,BNFCR_INFO                         -- 수익자정보코드
            ,FNDS_FND_OPRT_EXCT_INFO            -- 자금펀드운영집행정보코드
            )
     VALUES ( #{AML_CUST_ID_HIDDEN}, #{MAIN_ACTN_ZONE_NM}, #{CMPNY_ORGNZTN_AND_STRCT_CNTNT}, #{FNDTN_OBJ_NM}
             ,#{OTR_NPRFT_OGN_CNCT_RLTNS_CNTNT}, #{CRNBTN_P_INFO}, #{BNFCR_INFO}, #{FNDS_FND_OPRT_EXCT_INFO}
            )

INSERT INTO NIC13B
            (AML_CUST_ID        -- 실명확인번호
            ,PEP_RLTNS_P_CCD    -- 정치적인물관계자구분코드
            ,SQ                 -- 일련번호
            ,PEP_NM             -- 정치적인물성명
            ,PEP_RNM_NO         -- 정치적인물실명번호
            ,PEP_RLTNS_CD       -- 정치적인물관계코드
            ,PEP_ADDR           -- 정치적인물주소
            ,PEP_CNTC_NO        -- 정치적인물연락번호
            )
     VALUES ( #{AML_CUST_ID_HIDDEN}, #{PEP_RLTNS_P_CCD}, #{SQ}, #{PEP_NM}, #{PEP_RNM_NO}
              ,#{PEP_RLTNS_CD}, #{PEP_ADDR}, #{PEP_CNTC_NO}
            )

mapper.update:
MERGE INTO NIC14B T
USING DUAL
   ON ( T.AML_CUST_ID = #{AML_CUST_ID_HIDDEN} )
 WHEN MATCHED THEN
            UPDATE SET T.CORP_CCD = TO_NUMBER(#{CORP_CCD})
                                   ,T.LSTNG_CLSF_DMSTC_CD = #{LSTNG_CLSF_DMSTC_CD}
                                   ,T.LSTNG_CLSF_ABRD_CD = #{LSTNG_CLSF_ABRD_CD}
                                   ,T.HMPG_ADDR = #{HMPG_ADDR}
 WHEN NOT MATCHED THEN
                INSERT (T.AML_CUST_ID                -- 실명확인번호
                       ,T.CORP_CCD                   -- 법인구분코드
                       ,T.LSTNG_CLSF_DMSTC_CD        -- 상장구분국내코드
                       ,T.LSTNG_CLSF_ABRD_CD         -- 상장구분국외코드
                       ,T.HMPG_ADDR                  -- 홈페이지주소
                       )
                VALUES ( #{AML_CUST_ID_HIDDEN}, TO_NUMBER(#{CORP_CCD})
                        ,#{LSTNG_CLSF_DMSTC_CD}, #{LSTNG_CLSF_ABRD_CD}, #{HMPG_ADDR}
                       )

mapper.insert:
INSERT INTO NIC15B ( AML_CUST_ID    -- 실명확인번호
                    ,STKHD_CCD      -- 주주구분코드
                    ,SQ             -- 일련번호
                    ,STKHD_NM       -- 주주명
                    ,QTA_R          -- 지분율
                    ,RNM_CNFR_CCD   -- 실명확인구분코드
                    ,STKHD_RNMCNO   -- 주주실명확인번호
                    ,PST_NO         -- 우편번호
                    ,ADDR           -- 주소
                    ,TEL_NO         -- 연락처
                    ,NTNLT_CD       -- 국적코드
                   )
     VALUES ( #{AML_CUST_ID_HIDDEN}, #{STKHD_CCD}, #{SQ}, #{STKHD_NM}, #{QTA_R}
             ,#{RNM_CNFR_CCD}, #{STKHD_RNMCNO}, #{PST_NO}, #{ADDR}, #{TEL_NO}
             ,#{NTNLT_CD}
            )

mapper.select:
SELECT A.*
  FROM NIC14B A
 WHERE A.AML_CUST_ID = #{AML_CUST_ID}

SELECT * FROM ( SELECT /*+USE_NL(A, B)*/ A.RQRM_DT ,FN_DATE_FORMAT(A.RQRM_DT) AS RQRM_DT_F ,A.RQRM_GRP_NO ,A.SEQ ,A.RQRM_DEP_CD ,(SELECT I.DPRT_NM FROM NIC41B I WHERE I.DPRT_CD = A.RQRM_DEP_CD) AS RQRM_DEP_CD_NM ,A.CS_NM ,A.EMP_NO ,A.ENG_NM ,A.NTNLT_CD ,GET_CODE_NAME('M004', A.NTNLT_CD) AS NTNLT_CD_NM ,FN_DATE_FORMAT(A.BIRTHDAY) AS BIRTHDAY ,(CASE WHEN B.CNT = B.WL_MAT_YN_CNT THEN 'Y' WHEN B.CNT != B.WL_MAT_YN_CNT THEN 'N' WHEN B.CNT = 0 AND B.WL_MAT_YN_CNT = 0 THEN '' ELSE '미추출' END ) AS WL_MAT_YN ,A.RQRM_ID ,A.WL_CRT_DT ,FN_DATE_FORMAT(A.WL_CRT_DT) AS WL_CRT_DT_F ,NVL(B.CNT,0) AS WL_MAT_YN_CNT ,P.SN_CCD ,SUBSTR(P.REG_DT,1,4) ||'-'|| SUBSTR(P.REG_DT,5,2)||'-'||SUBSTR(P.REG_DT,7,2) AS APP_DT -- 결재일자 ,CASE WHEN P.SN_CCD IS NULL THEN '미결재' ELSE (SELECT J.CD_NM FROM NIC92B J WHERE J.CD = 'A038' AND J.CNTNT = P.SN_CCD ) -- A038 결재상태코드 END AS APP_ST -- 결재상태 ,P.GYLJ_ROLE_NM AS APP_NM -- 결재자 ,P.APPR_ROLE_NM -- 결재한사람 ,P.TARGET_ROLE_NM -- 결재할사람 ,A.APP_NO AS APP_NO -- 결재번호 ,P.SNO ,P.NUM_SQ ,'KYE' AS GYLJ_LINE_G_C ,P.WLR_SQ ,A.RSN_CNTNT ,A.WLF_DCD AS WLF_DCD -- WLF결과코드_A505 FROM NIC51B A ,(SELECT D.RQRM_DT, D.RQRM_GRP_NO, D.SEQ ,COUNT(*) AS CNT ,SUM(CASE WHEN D.WL_MAT_YN IS NOT NULL THEN 1 ELSE 0 END) AS WL_MAT_YN_CNT FROM NIC52B D WHERE 1=1 GROUP BY D.RQRM_DT, D.RQRM_GRP_NO, D.SEQ ) B ,(SELECT M.SNO ,M.APP_DT ,M.WLR_SQ ,M.REG_DT ,M.SN_CCD ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.APPR_ROLE_ID) AS APPR_ROLE_NM -- 결재한사람 ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.TARGET_ROLE_ID) AS TARGET_ROLE_NM -- 결재할사람 ,S.GYLJ_ROLE_ID -- 결재한 사람ID ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = S.GYLJ_ROLE_ID) AS GYLJ_ROLE_NM ,M.NUM_SQ ,M.GYLJ_LINE_G_C ,M.APP_NO FROM AML_APPR M ,C_GYLJ_D S WHERE S.GYLJ_LINE_G_C = 'KYE' AND S.GYLJ_LINE_G_C = M.GYLJ_LINE_G_C AND S.SNO = M.SNO AND (M.APP_NO, M.NUM_SQ) IN (SELECT /*+ INDEX(T PK_AML_APPR)*/ T.APP_NO, MAX(T.NUM_SQ) FROM AML_APPR T WHERE T.APP_NO = M.APP_NO AND T.GYLJ_LINE_G_C = 'KYE' GROUP BY T.APP_NO ) ) P WHERE 1 = 1 AND A.RQRM_DT = B.RQRM_DT(+) AND A.RQRM_GRP_NO = B.RQRM_GRP_NO(+) AND A.SEQ = B.SEQ(+) AND A.APP_NO = P.APP_NO(+)
AND A.RQRM_DT BETWEEN #{RQRM_DT_SD} AND #{RQRM_DT_ED}
AND A.RQRM_DEP_CD = #{RQRM_DEP_CD}
AND P.SN_CCD = #{SN_CCD}
AND P.SN_CCD = #{SN_CCD}
AND P.SN_CCD = #{SN_CCD}
AND A.APP_NO IS NULL
AND A.CS_NM LIKE '%'||#{CS_NM}||'%'
) X WHERE 1=1
AND X.WL_MAT_YN = #{WL_MAT_YN}
ORDER BY X.RQRM_DT DESC, X.RQRM_GRP_NO, X.SEQ

SELECT A.RQRM_DT ,FN_DATE_FORMAT(A.RQRM_DT) AS RQRM_DT_F ,A.RQRM_GRP_NO ,A.SEQ ,A.RQRM_DEP_CD ,(SELECT I.DPRT_NM FROM NIC41B I WHERE I.DPRT_CD = A.RQRM_DEP_CD) AS RQRM_DEP_CD_NM ,B.MNG_SNO ,A.CS_NM ,A.EMP_NO ,A.ENG_NM ,A.NTNLT_CD ,GET_CODE_NAME('M004', A.NTNLT_CD) AS NTNLT_CD_NM ,B.MNG_SNO ,B.WC_LIST_CCD ,B.WL_CS_NM ,B.WL_NTNLT_CD ,GET_CODE_NAME('M004', B.WL_NTNLT_CD) AS WL_NTNLT_CD_NM ,B.WL_HIT_R ,B.WL_MAT_YN ,B.APVL_YN FROM NIC51B A ,NIC52B B WHERE A.RQRM_DT = B.RQRM_DT AND A.RQRM_GRP_NO = B.RQRM_GRP_NO AND A.SEQ = B.SEQ AND B.WL_MAT_YN IS NOT NULL
AND A.RQRM_DT BETWEEN #{RQRM_DT_SD} AND #{RQRM_DT_ED}
AND A.RQRM_DEP_CD = #{RQRM_DEP_CD}
AND NVL(B.APVL_YN, 'N') = #{APVL_YN}
ORDER BY A.RQRM_DT DESC, A.RQRM_GRP_NO, A.SEQ, B.MNG_SNO

WITH NIC40_D AS ( /* 추출일자 범위의 고객 중 최종 추출에 포함된 고객 조회 */ SELECT X.EVL_BAS_YYMM ,X.AML_CUST_ID /* 고객별 당월 이후 최초 결재일자 */ ,NVL( (SELECT MIN(I.EVL_BAS_YYMM) AS EVL_BAS_YYMM FROM NIC40B I WHERE 1 = 1 AND I.EVL_BAS_YYMM > X.EVL_BAS_YYMM AND I.USE_YN = 'Y' AND I.APP_NO IS NOT NULL AND 'Y' = NVL( ( SELECT CASE WHEN A.SN_CCD = 'R' THEN 'N' ELSE 'Y' END FROM AML_APPR A WHERE A.GYLJ_LINE_G_C = 'LAP' AND A.APP_DT = I.EVL_BAS_YYMM AND A.APP_NO = I.APP_NO AND A.NUM_SQ = ( SELECT MAX(B.NUM_SQ) FROM AML_APPR B WHERE B.GYLJ_LINE_G_C = 'LAP' AND B.APP_DT = A.APP_DT AND B.APP_NO = A.APP_NO) ), 'N') AND I.AML_CUST_ID = X.AML_CUST_ID), '999912') AS MIN_EVL_BAS_YYMM /* 당월 결재일자 */ ,CASE WHEN X.APP_NO IS NOT NULL THEN NVL( ( SELECT CASE WHEN H.SN_CCD = 'R' THEN '999912' ELSE H.APP_DT END FROM AML_APPR H WHERE H.GYLJ_LINE_G_C = 'LAP' AND H.APP_DT = X.EVL_BAS_YYMM AND H.APP_NO = X.APP_NO AND H.NUM_SQ = ( SELECT MAX(G.NUM_SQ) FROM AML_APPR G WHERE G.GYLJ_LINE_G_C = 'LAP' AND G.APP_DT = H.APP_DT AND G.APP_NO = H.APP_NO) ), '999912') ELSE '999912' END AS CUR_EVL_BAS_YYMM /* 고객별 당월 이전 최종 결재일자 */ ,NVL( (SELECT MAX(K.EVL_BAS_YYMM) AS EVL_BAS_YYMM FROM NIC40B K WHERE 1 = 1 AND K.EVL_BAS_YYMM < X.EVL_BAS_YYMM AND K.USE_YN = 'Y' AND K.APP_NO IS NOT NULL AND 'Y' = NVL( ( SELECT CASE WHEN F.SN_CCD = 'R' THEN 'N' ELSE 'Y' END FROM AML_APPR F WHERE F.GYLJ_LINE_G_C = 'LAP' AND F.APP_DT = K.EVL_BAS_YYMM AND F.APP_NO = K.APP_NO AND F.NUM_SQ = ( SELECT MAX(J.NUM_SQ) FROM AML_APPR J WHERE J.GYLJ_LINE_G_C = 'LAP' AND J.APP_DT = F.APP_DT AND J.APP_NO = F.APP_NO) ), 'N') AND K.AML_CUST_ID = X.AML_CUST_ID), '999912') AS MAX_EVL_BAS_YYMM FROM (SELECT E.AML_CUST_ID ,MAX(E.EVL_BAS_YYMM) AS EVL_BAS_YYMM FROM NIC40B E WHERE 1 = 1
AND E.LGA_AST_EVL_DT >= TO_CHAR(#{START_DATE } || '000000') AND E.LGA_AST_EVL_DT < TO_CHAR(#{END_DATE} || '235959')
AND E.INDV_CORP_CCD = #{INDV_CORP_CCD }
GROUP BY E.AML_CUST_ID) M ,NIC40B X WHERE X.EVL_BAS_YYMM = M.EVL_BAS_YYMM AND X.AML_CUST_ID = M.AML_CUST_ID ) ,NIC40_APPR AS ( /* 조회할 고객별 결재 키 조회 */ SELECT Y.EVL_BAS_YYMM, Y.AML_CUST_ID /* 고객별 최종 결재순번 */ ,NVL( ( SELECT MAX(R.NUM_SQ) FROM NIC40B S ,AML_APPR R WHERE S.AML_CUST_ID = Y.AML_CUST_ID AND S.EVL_BAS_YYMM = CASE WHEN Y.CUR_EVL_BAS_YYMM != '999912' THEN Y.EVL_BAS_YYMM WHEN Y.MAX_EVL_BAS_YYMM != '999912' THEN CASE WHEN MONTHS_BETWEEN( TO_DATE(Y.EVL_BAS_YYMM, 'YYYYMM') , TO_DATE(Y.MAX_EVL_BAS_YYMM, 'YYYYMM') ) = ( SELECT COUNT(*) FROM NIC40B N WHERE N.AML_CUST_ID = Y.AML_CUST_ID AND N.EVL_BAS_YYMM <= Y.EVL_BAS_YYMM AND N.EVL_BAS_YYMM > Y.MAX_EVL_BAS_YYMM ) THEN Y.MAX_EVL_BAS_YYMM ELSE Y.EVL_BAS_YYMM END WHEN Y.MIN_EVL_BAS_YYMM != '999912' THEN CASE WHEN MONTHS_BETWEEN( TO_DATE(Y.MIN_EVL_BAS_YYMM, 'YYYYMM') , TO_DATE(Y.EVL_BAS_YYMM, 'YYYYMM') ) = ( SELECT COUNT(*) FROM NIC40B Q WHERE Q.AML_CUST_ID = Y.AML_CUST_ID AND Q.EVL_BAS_YYMM >= Y.EVL_BAS_YYMM AND Q.EVL_BAS_YYMM < Y.MIN_EVL_BAS_YYMM) THEN Y.MIN_EVL_BAS_YYMM ELSE Y.EVL_BAS_YYMM END ELSE Y.EVL_BAS_YYMM END AND R.APP_DT = S.EVL_BAS_YYMM AND R.APP_NO = S.APP_NO), -1) AS NUM_SQ FROM NIC40_D Y ) SELECT Z.EVL_BAS_YYMM ,Z.CS_NM AS CS_NM ,Z.AML_CUST_ID ,Z.AML_CUST_ID AS AML_CUST_ID2 ,Z.INDV_CORP_CCD ,CASE WHEN Z.INDV_CORP_CCD = '1' THEN '개인' WHEN Z.INDV_CORP_CCD = '2' THEN '법인' ELSE '' END AS INDV_CORP_CCD_NM ,Z.AVR_WON_CVS_AMT ,Z.AVR_FC_AMT ,NVL( (SELECT V.REG_DT FROM AML_APPR V WHERE V.GYLJ_LINE_G_C = 'LAP' AND V.NUM_SQ = W.NUM_SQ), '') AS APPR_DT ,P.SN_CCD ,CASE WHEN P.SN_CCD IS NULL THEN '미결재' ELSE (SELECT U.CD_NM FROM NIC92B U WHERE U.CD = 'A038' AND U.CNTNT = P.SN_CCD ) -- A038 결재상태코드 END AS SN_CCD_NM -- 결제상태 ,P.TARGET_ROLE_ID AS TARGET_ROLE_ID ,DECODE(P.TARGET_ROLE_ID, NULL, (SELECT (SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = G.GYLJ_ROLE_ID AND ROWNUM = 1) FROM C_GYLJ_D G WHERE G.GYLJ_LINE_G_C = 'LAP' AND G.SNO = 1 ) , 0, '', P.TARGET_ROLE_NM) AS TARGET_ROLE_NM ,Z.APP_NO AS APP_NO -- 결재번호 ,P.SNO ,P.NUM_SQ ,P.GYLJ_LINE_G_C ,P.WLR_SQ ,P.REG_DT AS APP_DT -- 결제일자 ,SUBSTR(Z.LGA_AST_EVL_DT,1,8) AS LGA_AST_EVL_DT ,Z.USE_YN AS USE_YN FROM NIC40_APPR W ,NIC40B Z ,(SELECT M.SNO ,M.APP_DT ,M.WLR_SQ ,M.REG_DT ,M.SN_CCD ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.APPR_ROLE_ID) AS APPR_ROLE_NM -- 결제한사람 ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.TARGET_ROLE_ID) AS TARGET_ROLE_NM -- 결제할사람 ,S.GYLJ_ROLE_ID -- 결재한 사람ID ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = S.GYLJ_ROLE_ID) AS GYLJ_ROLE_NM ,M.NUM_SQ ,M.GYLJ_LINE_G_C ,M.APP_NO ,M.TARGET_ROLE_ID FROM AML_APPR M ,C_GYLJ_D S WHERE S.GYLJ_LINE_G_C = 'LAP' AND S.GYLJ_LINE_G_C = M.GYLJ_LINE_G_C AND S.SNO = M.SNO AND (M.APP_NO, M.NUM_SQ) IN (SELECT /*+ INDEX(M PK_AML_APPR)*/ T.APP_NO, MAX(T.NUM_SQ) FROM AML_APPR T WHERE T.APP_NO = M.APP_NO AND T.GYLJ_LINE_G_C = 'LAP' GROUP BY T.APP_NO) ) P WHERE Z.APP_NO = P.APP_NO(+) AND Z.EVL_BAS_YYMM = W.EVL_BAS_YYMM AND Z.AML_CUST_ID = W.AML_CUST_ID
AND P.SN_CCD = #{SN_CCD}
AND P.SN_CCD = #{SN_CCD}
AND P.SN_CCD = #{SN_CCD}
AND Z.APP_NO IS NULL

