INSERT INTO NIC45B (
            GDS_DIT_CD
           ,GDS_CD
           ,GDS_NM
           ,LEV1
           ,LEV2
           ,GDS_MRK
           ,RSK_GRD_CD
           ,HNDL_DY_TM
           ,HNDL_P_ENO
           ,AML_CRT_DT
           ,FIU_GDS_NO
         ) VALUES (
           #{GDS_DIT_CD}
          ,#{GDS_CD}
          ,#{GDS_NM}
          ,#{LEV1}
          ,#{LEV2}
          ,#{GDS_MRK}
          ,#{RSK_GRD_CD}
          ,SYSDATE
          ,#{HNDL_P_ENO}
          ,TO_CHAR(SYSDATE, 'YYYYMMDD')
          ,#{FIU_GDS_NO}
         )

mapper.select:
SELECT '' as SELECTED ,ROWNUM AS SEQ, A.* FROM ( SELECT /*AML_10_03_01_01.getSearch*/ A.MNG_SNO ,A.WC_LIST_CCD ,(SELECT CD_NM FROM NIC92B WHERE CD = 'A003' AND CNTNT=A.WC_LIST_CCD) WC_LIST_CCD_NM ,A.NTV_FGNR_CCD ,A.RNM_CNFR_CCD ,A.RNMCNO ,A.CS_NM ,TRIM(A.NTN_CD) NTN_CD ,A.NTN_NM ,A.ADDR ,A.PSPT_NO ,A.HNGL_NM ,TO_CHAR(A.HNDL_DY_TM, 'YYYY-MM-DD HH24:MI:SS') HNDL_DY_TM ,A.HNDL_P_ENO ,'' AS COUNT ,(SELECT CD_NM FROM NIC92B WHERE CD='M006' AND CNTNT=A.INDV_CORP_CCD) INDV_CORP_CCD_NM ,A.INDV_CORP_CCD ,A.WL_BIRTHDAY, A.ORG_NM ,CASE WHEN A.WL_REG_DT IS NOT NULL THEN SUBSTR(A.WL_REG_DT,0,4) || '-' || SUBSTR(A.WL_REG_DT,5,2) || '-' || SUBSTR(A.WL_REG_DT,7,2) ELSE A.WL_REG_DT END AS WL_REG_DT ,CASE WHEN A.WL_DEL_DT IS NOT NULL THEN SUBSTR(A.WL_DEL_DT,0,4) || '-' || SUBSTR(A.WL_DEL_DT,5,2) || '-' || SUBSTR(A.WL_DEL_DT,7,2) ELSE A.WL_DEL_DT END AS WL_DEL_DT ,A.NORM_YN ,A.APPL_YN ,CASE WHEN A.NORM_YN ='Y' AND A.APPL_YN = 'N' THEN '등록' WHEN A.NORM_YN ='Y' AND A.APPL_YN = 'C' THEN '책임자승인완료' WHEN A.NORM_YN ='Y' AND A.APPL_YN = 'Y' THEN '승인완료' WHEN A.NORM_YN ='N' AND A.APPL_YN = 'N' THEN '삭제등록' WHEN A.NORM_YN ='Y' AND A.APPL_YN = 'C' THEN '삭제책임자승인완료' WHEN A.NORM_YN ='N' AND A.APPL_YN = 'Y' THEN '삭제승인완료' END AS APPL_NM ,A.LST_APPL_ID ,CASE WHEN A.APPL_DT IS NOT NULL THEN SUBSTR(A.APPL_DT,0,4) || '-' || SUBSTR(A.APPL_DT,5,2) || '-' || SUBSTR(A.APPL_DT,7,2) ELSE A.APPL_DT END AS APPL_DT FROM NIC19B A WHERE A.WC_LIST_CCD LIKE #{WC_LIST_CCD}||'%' AND A.NTV_FGNR_CCD = #{NTV_FGNR_CCD} AND UPPER(A.CS_NM) LIKE '%'||UPPER(#{CS_NM})||'%' AND A.WL_REG_DT BETWEEN #{WL_REG_DT_SD} AND #{WL_REG_DT_ED}
AND A.NORM_YN = #{NORM_YN}
AND A.APPL_YN IN ('N', 'C', 'Y')
AND A.APPL_YN IN ('N', 'Y')
AND A.APPL_YN IN ('C', 'Y')
AND A.APPL_YN = 'Y'
AND A.APPL_YN = #{APPL_YN}
ORDER BY A.WC_LIST_CCD, A.NTV_FGNR_CCD, A.NTN_CD ) A

