INSERT INTO NIC19B ( MNG_SNO, WC_LIST_CCD, NTV_FGNR_CCD, RNM_CNFR_CCD, INDV_CORP_CCD
                    ,RNMCNO, CS_NM, NTN_CD, NTN_NM, ADDR
                    ,HNGL_NM, PSPT_NO, WL_BIRTHDAY
                    ,ORG_NM, WL_REG_DT, WL_DEL_DT, NORM_YN
                    ,APPL_YN
                    ,HNDL_DY_TM, HNDL_P_ENO
                    ,AML_REF_DT
                    ,APP_NO
                   )
            VALUES ( #{MNG_SNO}, #{WC_LIST_CCD}, #{NTV_FGNR_CCD}, #{RNM_CNFR_CCD}, #{INDV_CORP_CCD}
                    ,#{RNMCNO}, #{CS_NM}, #{NTN_CD}, #{NTN_NM}, #{ADDR}
                    ,#{HNGL_NM}, #{PSPT_NO}, #{WL_BIRTHDAY}
                    ,#{ORG_NM}, #{WL_REG_DT}, #{WL_DEL_DT}, #{NORM_YN}
                    ,'N'
                    ,TO_DATE(#{HNDL_DY_TM}, 'YYYY-MM-DD HH24:MI:SS'), #{HNDL_P_ENO}
                    ,'99991231'
                    ,#{APP_NO, jdbcType=VARCHAR}
