mapper.select:
SELECT /*+USE_NL(A,P,C)*/ A.SQ ,A.SRCH_RQS_CCD ,A.SRCH_RSLT_DT -- 검색결과일자 ,B.CS_NM -- 고객명 ,A.CS_NM AS CS_NM_V -- WLF대상명 한글 ,B.ENG_CS_NM AS ENG_WLF_CS_NM -- WLF대상명 영문 ,(SELECT I.CD_NM FROM NIC92B I WHERE I.CD='M002' AND I.CNTNT=A.RNM_CCD) RNM_CCD -- 실명구분코드 ,A.AML_CUST_ID -- 실명번호 ,A.RNMCNO AS RNMCNO_ORG -- 실명번호 ,A.RNMCNO AS RNMCNO -- 실명번호 ,(SELECT J.CD_NM FROM NIC92B J WHERE J.CD='M004' AND J.CNTNT = A.NTN_CD) NTN_CD -- 국가 ,A.WC_LIST_CCD -- W/L 구분 ,(SELECT K.CD_NM FROM NIC92B K WHERE K.CD='A006' AND K.CNTNT = C.WL_TRD_CON_F) WL_TRD_CON_F_NM-- 거래거절 ,NVL(A.PSBL_F,'N') AS PSBL_F -- 가능여부 ,C.WL_TRD_CON_F -- 거래거절 ,P.SN_CCD ,A.RSN_CNTNT ,A.WLF_DCD AS WLF_DCD -- WLF결과코드_A505 ,(SELECT L.CD_NM FROM NIC92B L WHERE L.CD='M012' AND L.CNTNT = B.CS_TYP_CD) AS CUST_G_C -- 고객구분(01.개인,02.개인사업자 ,03.법인,04.비영리법인 ) ,A.RLT_CD ,(SELECT M.CD_NM FROM NIC92B M WHERE M.CD='A915' AND M.CNTNT = A.RLT_CD ) AS RLT_NM -- WLF고객구분코드(01.본인,02.대리인,03.대표자,04.실제소유자) ,SUBSTR(P.REG_DT,1,4) ||'-'|| SUBSTR(P.REG_DT,5,2)||'-'||SUBSTR(P.REG_DT,7,2) AS APP_DT -- 결재일자 ,CASE WHEN P.SN_CCD IS NULL THEN '미결재' ELSE (SELECT N.CD_NM FROM NIC92B N WHERE N.CD = 'A038' AND N.CNTNT = P.SN_CCD ) -- A038 결재상태코드 END AS APP_ST -- 결제상태 ,P.GYLJ_ROLE_NM AS APP_NM -- 결재자 ,P.APPR_ROLE_NM -- 결재한사람 ,P.TARGET_ROLE_NM -- 결재할사람 ,A.APP_NO AS APP_NO -- 결재번호 ,P.SNO ,P.NUM_SQ ,P.GYLJ_LINE_G_C ,P.WLR_SQ FROM NIC21B A ,NIC01B B ,NIC35B C , ( SELECT M.SNO ,M.APP_DT ,M.WLR_SQ ,M.REG_DT ,M.SN_CCD ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.APPR_ROLE_ID) AS APPR_ROLE_NM -- 결제한사람 ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.TARGET_ROLE_ID) AS TARGET_ROLE_NM -- 결제할사람 ,S.GYLJ_ROLE_ID -- 결재한 사람ID ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = S.GYLJ_ROLE_ID) AS GYLJ_ROLE_NM ,M.NUM_SQ ,M.GYLJ_LINE_G_C ,M.APP_NO FROM AML_APPR M , C_GYLJ_D S WHERE S.GYLJ_LINE_G_C = 'WLR' AND S.GYLJ_LINE_G_C = M.GYLJ_LINE_G_C AND S.SNO = M.SNO AND (M.APP_NO, M.NUM_SQ) IN (SELECT /*+ INDEX(T PK_AML_APPR)*/ T.APP_NO, MAX(T.NUM_SQ) FROM AML_APPR T WHERE T.APP_NO = M.APP_NO AND T.GYLJ_LINE_G_C = 'WLR' GROUP BY T.APP_NO) ) P WHERE A.AML_CUST_ID = B.AML_CUST_ID AND B.AML_CUST_ID = C.AML_CUST_ID AND A.APP_NO = P.APP_NO(+) AND A.SQ = P.WLR_SQ(+) AND (A.SRCH_RSLT_DT, A.SQ) IN (SELECT /*+ INDEX(D PK_NIC22B)*/ D.SRCH_RSLT_DT, D.SQ FROM NIC22B D WHERE D.SRCH_RSLT_DT = A.SRCH_RSLT_DT AND D.SQ = A.SQ GROUP BY D.SRCH_RSLT_DT, D.SQ )
AND A.SRCH_RSLT_DT BETWEEN #{RSK_GRD_RGST_DT_SD} AND #{RSK_GRD_RGST_DT_ED}
AND A.SRCH_RQS_CCD = #{SRCH_RQS_CCD}
AND A.AML_CUST_ID LIKE CONCAT(#{AML_CUST_ID},'%')
AND P.SN_CCD = #{SN_CCD}
AND P.SN_CCD = #{SN_CCD}
AND P.SN_CCD = #{SN_CCD}
AND A.APP_NO IS NULL
ORDER BY A.SRCH_RSLT_DT DESC, A.SQ

WITH SRCH_RSLT_TRGT AS ( SELECT NIC21.SRCH_RSLT_DT, NIC21.SQ , IAU.DTBR_NAME , IAU.MANG_NAME FROM NIC21B NIC21 , NIC01B NIC01 , (SELECT PRFT_CNTR_ENTY_ENTY_ID , ACNT_OWNR_ID , DTBR_CODE , DTBR_NAME , MANG_NAME FROM (SELECT IAU.PRFT_CNTR_ENTY_ENTY_ID , IAU.ACNT_OWNR_ID , ROW_NUMBER() OVER(PARTITION BY IAU.ACNT_OWNR_ID ORDER BY IAUSD.DTBR_CODE, IAUAER.EMPY_NO) AS ORD_RANK , NVL(IAUSD.DTBR_CODE, ' ') AS DTBR_CODE , NVL(IAUSD.DTBR_NAME, ' ') AS DTBR_NAME , NVL( (SELECT USER_NAME FROM SID.IDO_A_UWA_USER WHERE USER_ID = IAUAER.EMPY_NO) , IAUAER.EMPY_NO) AS MANG_NAME FROM SID.IDO_A_UUA_ACNT IAU INNER JOIN SID.IDO_A_UUE_SAMSUNG_DPRT IAUSD ON (IAUSD.ENTY_ID = IAU.PRFT_CNTR_ENTY_ENTY_ID) LEFT OUTER JOIN SID.IDO_A_UUA_ACNT_ENTY_RLTP IAUAER ON ( IAUAER.ACNT_ID = IAU.ACNT_ID AND IAUAER.ACNT_ENTY_ROLE_TYPE_CODE = 'MANG') WHERE IAU.ACNT_STAS_TYPE_CODE != 'CL' /* 폐쇄계좌가 아님 */) WHERE ORD_RANK = 1) IAU WHERE 1 = 1 AND ((SRCH_RSLT_DT < '20220427' AND ETC1 = 'Y') OR (SRCH_RSLT_DT >= '20220427' AND ETC1 IS NULL)) AND NIC01.RNMCNO = NIC21.RNMCNO AND IAU.ACNT_OWNR_ID(+) = TO_NUMBER(NIC01.RNMCNO) /* 상세가 존재하는 자료만 */ AND EXISTS(SELECT NIC22.SRCH_RSLT_DT FROM NIC22B NIC22 WHERE NIC22.SRCH_RSLT_DT = NIC21.SRCH_RSLT_DT AND NIC22.SQ = NIC21.SQ AND ROWNUM <= 1) /* 기간 입력 시 */ AND NIC21.SRCH_RSLT_DT >= #{RSK_GRD_RGST_DT_SD } AND NIC21.SRCH_RSLT_DT <= #{RSK_GRD_RGST_DT_ED } /* 고객명 입력 시 */
AND ( NIC01.CS_NM LIKE '%' || #{CS_NM } || '%' OR NIC01.ENG_CS_NM LIKE '%' || #{CS_NM } || '%')
/* 지점(대표지점) 입력 시 */
AND IAU.PRFT_CNTR_ENTY_ENTY_ID = (SELECT TO_NUMBER(DEP_ID) FROM C_DEP_INFO WHERE DEP_DESC = #{DEP_ID })
/* 구분(내/외국인) 입력 시 */
AND NIC21.NTV_FGNR_CCD = #{NTV_FGNR_CCD }
/* 검색요청 입력 시 */
AND NIC21.SRCH_RQS_CCD = #{SRCH_RQS_CCD }
) SELECT NIC21.SRCH_RSLT_DT /* 검색일자 */ , NIC21.SQ , NIC21.CS_NM /* 고객명 */ , NVL(NIC01.CS_NM, NIC01.ENG_CS_NM) AS F_CS_NM /* 원고객명 */ , (SELECT NIC92.CD_NM FROM NIC92B NIC92 WHERE NIC92.CD = 'A003' AND NIC92.CNTNT = NIC21.WC_LIST_CCD) AS WC_LIST_NM /* 적출기준 */ /* 적출내역 */ , NIC01.ENG_CS_NM /* 영문명 */ , NIC01.CS_NO /* 실명번호 */ , NIC02.PSPT_NO /* 여권번호 */ , CASE WHEN NIC02.SEX_CD = '1' THEN '남' WHEN NIC02.SEX_CD = '2' THEN '여' ELSE NULL END AS SEX_NM /* 성별 */ , CASE WHEN NIC21.WL_RELATED_PER_CODE = '1' THEN (SELECT NIC92.CD_NM FROM NIC92B NIC92 WHERE NIC92.CD = 'S004' AND NIC92.CNTNT = NIC01.NTN_CD) WHEN NIC21.WL_RELATED_PER_CODE = '2' THEN (SELECT CASE WHEN TRIM(RPRST_P_NM1) = TRIM(NIC21.CS_NM) THEN (SELECT NIC92.CD_NM FROM NIC92B NIC92 WHERE NIC92.CD = 'S004' AND NIC92.CNTNT = RPRST_P_NTNLT1) WHEN TRIM(RPRST_P_NM2) = TRIM(NIC21.CS_NM) THEN (SELECT NIC92.CD_NM FROM NIC92B NIC92 WHERE NIC92.CD = 'S004' AND NIC92.CNTNT = RPRST_P_NTNLT2) WHEN TRIM(RPRST_P_NM3) = TRIM(NIC21.CS_NM) THEN (SELECT NIC92.CD_NM FROM NIC92B NIC92 WHERE NIC92.CD = 'S004' AND NIC92.CNTNT = RPRST_P_NTNLT3) END AS NTN_NM FROM NIC03B WHERE RNMCNO = NIC21.RNMCNO ) WHEN NIC21.WL_RELATED_PER_CODE = '3' THEN (SELECT MAX(NIC92.CD_NM) FROM SID.IDO_A_MAH_CDD_REL_OWNR_IFMN OWNR , SID.IDO_A_UUE_COUNTRY COUNTRY , NIC92B NIC92 WHERE OWNR.CDD_TAGT_ENTY_ID = NIC21.RNMCNO AND TRIM(OWNR.REL_OWNR_NAME) = TRIM(NIC21.CS_NM) AND OWNR.REL_OWNR_NTNY_ID = COUNTRY.CNTY_ID AND NIC92.CD = 'S004' AND NIC92.CNTNT = COUNTRY.CNTY_CODE) END AS NTN_NM /* 소속국가 */ , T_SRT.DTBR_NAME AS DEP_TITLE /* 관리지점 */ , T_SRT.MANG_NAME AS USER_NM /* 관리자 */ , (SELECT IAUCC.CLNT_CLSS_CODE FROM SID.IDO_A_UUE_CLIENT_CLSN IAUCC WHERE IAUCC.ENTY_ID = TO_NUMBER(NIC01.RNMCNO) AND IAUCC.CLNT_CLSS_TYPE_CODE = 'CLRT') AS CLNT_CLSS_LVL /* 고객등급 */ , NVL( (SELECT SUM(ISSBM.ASST_VLTN_BLNC_AMNT) FROM SID.IDA_SETL_STD_BAL_M ISSBM WHERE ISSBM.STNR_YYMM = SUBSTR(NIC21.SRCH_RSLT_DT, 1,6) AND ISSBM.CLNT_ENTY_ID = TO_NUMBER(NIC21.RNMCNO)) , 0) AS ASST_VLTN_BLNC_AMNT /* 잔고 */ , GET_CODE_NAME('A310',NIC21.WL_RELATED_PER_CODE) AS WL_RELATED_PER_CODE /* WL유관인물구분코드*/ , CASE WHEN NIC21.WL_RELATED_PER_CODE = '1' THEN NIC02.BRTDY WHEN NIC21.WL_RELATED_PER_CODE = '2' THEN (SELECT CASE WHEN TRIM(RPRST_P_NM1) = TRIM(NIC21.CS_NM) THEN RPRST_P_BRDY1 WHEN TRIM(RPRST_P_NM2) = TRIM(NIC21.CS_NM) THEN RPRST_P_BRDY2 WHEN TRIM(RPRST_P_NM3) = TRIM(NIC21.CS_NM) THEN RPRST_P_BRDY3 END AS BRTDY FROM NIC03B WHERE RNMCNO = NIC21.RNMCNO ) WHEN NIC21.WL_RELATED_PER_CODE = '3' THEN (SELECT MAX(REL_OWNR_BRDT) FROM SID.IDO_A_MAH_CDD_REL_OWNR_IFMN WHERE CDD_TAGT_ENTY_ID = NIC21.RNMCNO AND TRIM(REL_OWNR_NAME) = TRIM(NIC21.CS_NM) ) END AS BRTDY /* 생년월일 */ FROM SRCH_RSLT_TRGT T_SRT , NIC21B NIC21 , NIC01B NIC01 , NIC02B NIC02 WHERE 1 = 1 AND NIC21.SRCH_RSLT_DT = T_SRT.SRCH_RSLT_DT AND NIC21.SQ = T_SRT.SQ AND NIC01.RNMCNO = NIC21.RNMCNO AND NIC02.RNMCNO(+) = NIC01.RNMCNO ORDER BY NIC21.SRCH_RSLT_DT DESC, NIC01.CS_NO, NIC21.WL_RELATED_PER_CODE, NVL(NIC01.CS_NM, NIC01.ENG_CS_NM)

SELECT NIC21.SRCH_RSLT_DT , NIC21.SQ , NIC21.CS_NM , NIC21.SRCH_RQS_CCD , NIC21.NTV_FGNR_CCD , CASE WHEN NIC21.NTV_FGNR_CCD = 'A' THEN '내국인' WHEN NIC21.NTV_FGNR_CCD = 'B' THEN '외국인' ELSE NULL END AS NTV_FGNR_NM , CASE WHEN NIC01.NTN_CD = 'KR' THEN NIC01.CS_NM WHEN NIC01.NTN_CD != 'KR' THEN NIC01.ENG_CS_NM ELSE NULL END AS F_CS_NM , (SELECT NIC92.CD_NM FROM NIC92B NIC92 WHERE NIC92.CD = 'A003' AND NIC92.CNTNT = NIC21.WC_LIST_CCD) AS WC_LIST_NM , NIC01.ENG_CS_NM , NIC01.CS_NO , NIC02.PSPT_NO , CASE WHEN NIC02.SEX_CD = '1' THEN '남' WHEN NIC02.SEX_CD = '2' THEN '여' ELSE NULL END AS SEX_NM , (SELECT NIC92.CD_NM FROM NIC92B NIC92 WHERE NIC92.CD = 'S004' AND NIC92.CNTNT = NIC21.NTN_CD) AS NTN_NM , NIC21.NTN_CD , NIC01.CS_MANAG_BRN_CD , CASE WHEN NIC21.WL_RELATED_PER_CODE = '1' THEN NIC02.BRTDY WHEN NIC21.WL_RELATED_PER_CODE = '2' THEN (SELECT CASE WHEN TRIM(RPRST_P_NM1) = TRIM(NIC21.CS_NM) THEN RPRST_P_BRDY1 WHEN TRIM(RPRST_P_NM2) = TRIM(NIC21.CS_NM) THEN RPRST_P_BRDY2 WHEN TRIM(RPRST_P_NM3) = TRIM(NIC21.CS_NM) THEN RPRST_P_BRDY3 END AS BRTDY FROM NIC03B WHERE RNMCNO = NIC21.RNMCNO) WHEN NIC21.WL_RELATED_PER_CODE = '3' THEN (SELECT MAX(REL_OWNR_BRDT) FROM SID.IDO_A_MAH_CDD_REL_OWNR_IFMN WHERE CDD_TAGT_ENTY_ID = NIC21.RNMCNO AND TRIM(REL_OWNR_NAME) = TRIM(NIC21.CS_NM)) END AS BRTDY , NIC21.WL_RELATED_PER_CODE AS WL_RELATED_PER_CODE_CD , GET_CODE_NAME('A310',NIC21.WL_RELATED_PER_CODE) AS WL_RELATED_PER_CODE , NIC21.RNMCNO FROM NIC21B NIC21 , NIC01B NIC01 , NIC02B NIC02 WHERE NIC21.RNMCNO = NIC01.RNMCNO AND NIC01.RNMCNO = NIC02.RNMCNO(+) AND NIC21.WC_LIST_CCD NOT IN ('W130') AND NIC21.SRCH_RSLT_DT >= #{RSK_GRD_RGST_DT_SD } AND NIC21.SRCH_RSLT_DT <= #{RSK_GRD_RGST_DT_ED }
AND (NIC21.CS_NM LIKE '%' || #{CS_NM} || '%')
AND NIC01.CS_MANAG_BRN_CD = #{DEP_ID}
AND NIC21.NTV_FGNR_CCD = #{NTV_FGNR_CCD}
AND NIC21.SRCH_RQS_CCD = #{SRCH_RQS_CCD}
ORDER BY NIC21.SRCH_RSLT_DT DESC, NIC21.SQ DESC

