   SET A.APP_NO =  #{APP_NO}
 WHERE A.AML_REF_DT = '99991231'

UPDATE NIC40B A
   SET A.APP_NO = #{APP_NO }
      ,A.USE_YN = #{USE_YN }
 WHERE 1 = 1
   AND A.AML_CUST_ID = #{AML_CUST_ID2 }
   AND A.EVL_BAS_YYMM = #{EVL_BAS_YYMM }

   MERGE INTO AML_APPR T
   USING DUAL
      ON ( T.APP_NO = #{APP_NO} )
    WHEN MATCHED THEN
           UPDATE SET T.NUM_SQ    = #{NUM_SQ}
                     ,T.APP_DT    = #{APP_DT}
                     ,T.WLR_SQ    = #{WLR_SQ}
                     ,T.REG_DT    = #{REG_DT}
                     ,T.SNO        = #{SNO}
                     ,T.SN_CCD     = #{SN_CCD}
                     ,T.BRN_CD     = #{BRN_CD}
                     ,T.APPR_ROLE_ID     = #{APPR_ROLE_ID}
                     ,T.TARGET_ROLE_ID   = #{TARGET_ROLE_ID}
                     ,T.RSN_CNTNT      = #{RSN_CNTNT}
                     ,T.PRV_APP_NO     = #{PRV_APP_NO}
                     ,T.HNDL_DY_TM = SYSDATE
                     ,T.HNDL_P_ENO = #{HNDL_P_ENO}
WHEN NOT MATCHED THEN
               INSERT ( T.APP_NO, T.GYLJ_LINE_G_C, T.NUM_SQ, T.APP_DT, T.WLR_SQ, T.REG_DT
                       ,T.SNO, T.SN_CCD, T.BRN_CD, T.APPR_ROLE_ID, T.TARGET_ROLE_ID
                       ,T.RSN_CNTNT, T.PRV_APP_NO, T.HNDL_DY_TM, T.HNDL_P_ENO )
               VALUES ( #{APP_NO}
                       ,#{GYLJ_LINE_G_C}
                       ,#{NUM_SQ}
                       ,#{APP_DT}
                       ,#{WLR_SQ}
                       ,#{REG_DT}
                       ,#{SNO}
                       ,#{SN_CCD}
                       ,#{BRN_CD}
                       ,#{APPR_ROLE_ID}
                       ,#{TARGET_ROLE_ID}
                       ,#{RSN_CNTNT}
                       ,#{PRV_APP_NO}
                       ,SYSDATE
                       ,#{HNDL_P_ENO}
                      )

