INSERT INTO AML_APPR_HIST ( APP_NO, GYLJ_LINE_G_C, NUM_SQ
                           ,APP_DT, WLR_SQ, REG_DT
                           ,SNO, SN_CCD, BRN_CD
                           ,APPR_ROLE_ID, TARGET_ROLE_ID
                           ,RSN_CNTNT
                           ,HNDL_DY_TM, HNDL_P_ENO
                          )
     VALUES ( #{APP_NO}
             ,#{GYLJ_LINE_G_C}
             ,#{NUM_SQ}
             ,#{APP_DT}
             ,#{WLR_SQ}
             ,#{REG_DT}
             ,#{SNO}
             ,#{SN_CCD}
             ,#{BRN_CD}
             ,#{APPR_ROLE_ID}
             ,#{TARGET_ROLE_ID}
             ,#{RSN_CNTNT}
             ,SYSDATE
             ,#{HNDL_P_ENO}
            )

