SELECT '' AS SELECTED ,ROWNUM AS SEQ ,X.NUM_SQ ,X.GUBUN_NM ,X.APP_DT --, X.SN_DT ,X.SNO_DEPTH ,X.APPR_ROLE_ID ,X.ROLE_NM ,X.CURRENT_ROLE_NM ,X.SN_CCD ,X.SN_CCD_NM ,X.HNDL_P_ENO ,X.BRN_CD ,X.CNT ,X.REG_DT ,TO_CHAR(X.REG_DATE,'YYYY-MM-DD HH:MM') AS REG_DATE ,X.HNDL_DY_TM FROM ( SELECT /*AML_10_40_01_04.getSearch*/ A.NUM_SQ -- 결제순번 ,DECODE(A.GYLJ_LINE_G_C, 'WLL', 'WatchList 등록', '') AS GUBUN_NM ,A.APP_DT AS APP_DT -- 19B적용일자 --, A.SN_DT -- 결재일자 ,A.REG_DT -- 결재일자 ,TO_DATE(A.REG_DT,'YYYYMMDDHH24MISS') AS REG_DATE -- 결재일자 ,TO_CHAR(A.HNDL_DY_TM, 'YYYY-MM-DD HH24:MI') AS HNDL_DY_TM ,CONCAT(A.SNO, '단계') AS SNO_DEPTH -- 결제단계순 --, A.SNO ,A.APPR_ROLE_ID -- 현재결제대상자 ,( SELECT DECODE(T.ROLE_NM, NULL, 'SS', T.ROLE_NM) FROM C_GYLJ_D S, C_ROLE T WHERE S.GYLJ_ROLE_ID = A.APPR_ROLE_ID AND S.GYLJ_ROLE_ID = T.ROLE_ID(+) AND S.GYLJ_LINE_G_C = #{GYLJ_LINE_G_C} --AND S.SNO = A.SNO ) AS ROLE_NM -- 현재결재대상자 ,( SELECT N.ROLE_NM FROM C_GYLJ_D M, C_ROLE N WHERE A.TARGET_ROLE_ID = M.GYLJ_ROLE_ID AND M.GYLJ_ROLE_ID = N.ROLE_ID(+) AND M.GYLJ_LINE_G_C = #{GYLJ_LINE_G_C} AND M.SNO = A.SNO ) AS CURRENT_ROLE_NM -- 현재결재대상자 ,A.SN_CCD -- 현재결제여부 S.결재, R.반려 ,(SELECT C.CD_NM FROM NIC92B C WHERE C.CD = 'A038' AND C.CNTNT = A.SN_CCD ) AS SN_CCD_NM -- A038 결재상태코드 ,A.HNDL_P_ENO ,A.BRN_CD ,TO_CHAR( (SELECT COUNT(*) FROM NIC19B E WHERE E.APPL_DT = A.APP_DT), '999,999,999,999,999') AS CNT -- 결제건수 FROM AML_APPR_HIST A WHERE A.GYLJ_LINE_G_C = #{GYLJ_LINE_G_C} AND A.APP_DT = #{APP_DT}
AND A.APP_NO = #{APP_NO}
ORDER BY A.NUM_SQ ) X

