INSERT INTO NIC51B (RQRM_DT
                   ,RQRM_GRP_NO
                   ,SEQ
                   ,RQRM_DEP_CD
                   ,CS_NM
                   ,ENG_NM
                   ,NTNLT_CD
                   ,BIRTHDAY
                   ,RQRM_ID
                   ,WL_CRT_DT
                   ,HNDL_DY_TM
                   ,HNDL_P_ENO
                   ,EMP_NO )
     VALUES ( #{RQRM_DT}
             ,#{RQRM_GRP_NO}
             ,#{SEQ}
             ,REPLACE(#{RQRM_DEP_CD}, ' ', '')
             ,#{CS_NM}
             ,#{ENG_NM}
             ,REPLACE(#{NTNLT_CD}, ' ', '')
             ,#{BIRTHDAY}
             ,#{RQRM_ID}
             ,#{WL_CRT_DT}
             ,SYSDATE
             ,#{HNDL_P_ENO}
             ,#{EMP_NO} )

mapper.select:
SELECT ROWNUM AS SEQ ,A.AML_CUST_ID ,A.RNMCNO ,A.CS_NM ,A.ENG_CS_NM ,NVL(C.BRTDY, D.FNDTN_DT) AS DOB ,P.SN_CCD ,P.APP_NO ,SUBSTR(P.REG_DT, 1, 4) ||'-'|| SUBSTR(P.REG_DT, 5, 2) || '-' || SUBSTR(P.REG_DT, 7, 2) AS APP_DT ,CASE WHEN P.SN_CCD IS NULL THEN '미결재' ELSE (SELECT I.CD_NM FROM NIC92B I WHERE I.CD = 'A038' AND I.CNTNT = P.SN_CCD ) -- A038 결재상태코드 END AS APP_ST ,P.GYLJ_ROLE_NM AS APP_NM ,P.APPR_ROLE_NM ,P.TARGET_ROLE_NM ,P.SNO ,P.NUM_SQ ,'WHL' AS GYLJ_LINE_G_C ,P.WLR_SQ ,TO_CHAR(NVL(C.HNDL_DY_TM, D.HNDL_DY_TM), 'YYYY-MM-DD') AS HNDL_DY_TM FROM NIC01B A INNER JOIN (SELECT DISTINCT N.AML_CUST_ID, N.APP_NO FROM NIC27B N) B ON A.AML_CUST_ID = B.AML_CUST_ID LEFT OUTER JOIN ( SELECT M.SNO ,M.APP_DT ,M.WLR_SQ ,M.REG_DT ,M.SN_CCD ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.APPR_ROLE_ID) AS APPR_ROLE_NM -- 결제한사람 ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.TARGET_ROLE_ID) AS TARGET_ROLE_NM -- 결제할사람 ,S.GYLJ_ROLE_ID -- 결재한 사람ID ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = GYLJ_ROLE_ID) AS GYLJ_ROLE_NM ,M.NUM_SQ ,M.GYLJ_LINE_G_C ,M.APP_NO FROM AML_APPR M, C_GYLJ_D S WHERE S.GYLJ_LINE_G_C = 'WHL' AND S.GYLJ_LINE_G_C = M.GYLJ_LINE_G_C AND S.SNO = M.SNO AND (M.APP_NO, M.NUM_SQ) IN (SELECT /*+ INDEX(T PK_AML_APPR)*/ T.APP_NO, MAX(T.NUM_SQ) FROM AML_APPR T WHERE T.APP_NO = M.APP_NO AND T.GYLJ_LINE_G_C = 'WHL' GROUP BY T.APP_NO ) ) P ON (B.APP_NO = P.APP_NO) LEFT JOIN NIC02B C ON A.AML_CUST_ID = C.AML_CUST_ID LEFT JOIN NIC03B D ON A.AML_CUST_ID = D.AML_CUST_ID WHERE 1=1
AND UPPER(A.CS_NM) LIKE '%' || UPPER(#{CS_NM}) || '%'
AND NVL(C.HNDL_DY_TM, D.HNDL_DY_TM) BETWEEN TO_DATE(#{HNDL_DY_TM_START}||'000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{HNDL_DY_TM_END}||'235959', 'YYYYMMDDHH24MISS')
AND P.SN_CCD = #{SN_CCD}
AND P.SN_CCD = #{SN_CCD}
AND P.SN_CCD = #{SN_CCD}
AND B.APP_NO IS NULL
ORDER BY C.HNDL_DY_TM

