INSERT INTO NIC27B_LOG ( AML_CUST_ID, RLT_CD, RLT_SQ, WC_LIST_CCD, MNG_SNO
                        ,CS_NM, SEQ, APPL_YN, HNDL_DY_TM, HNDL_P_ENO, DEL_YN )
            ( SELECT A.AML_CUST_ID
                    ,A.RLT_CD
                    ,A.RLT_SQ
                    ,A.WC_LIST_CCD
                    ,A.MNG_SNO
                    ,A.CS_NM
                    ,(SELECT NVL(MAX(B.SEQ) + 1, 1)
                        FROM NIC27B_LOG B
                       WHERE B.AML_CUST_ID = #{AML_CUST_ID}
                         AND B.WC_LIST_CCD  = #{WC_LIST_CCD}
                         AND B.MNG_SNO      = #{MNG_SNO}
                         AND B.CS_NM        = #{CS_NM} )
                    ,A.APPL_YN
                    ,SYSDATE
                    ,A.HNDL_P_ENO
                    ,'Y'
                FROM NIC27B_RSLT A
               WHERE A.AML_CUST_ID   = #{AML_CUST_ID}
                 AND A.RLT_CD        = #{RLT_CD}
                 AND A.RLT_SQ        = #{RLT_SQ}
                 AND A.WC_LIST_CCD   = #{WC_LIST_CCD}
                 AND A.MNG_SNO      = #{MNG_SNO}
                 AND A.CS_NM        = #{CS_NM} )

