      ,A.APVL_DT     = TO_CHAR(SYSDATE, 'YYYYMMDD')
 WHERE A.RQRM_DT     = #{RQRM_DT}
   AND A.RQRM_GRP_NO = #{RQRM_GRP_NO}
   AND A.SEQ         = #{SEQ}
   AND A.MNG_SNO     = #{MNG_SNO}

mapper.select:
WITH SRCH_RSLT_TRGT AS ( SELECT A.SRCH_RSLT_DT, A.SQ FROM NIC21B A ,NIC01B B WHERE 1 = 1 AND B.AML_CUST_ID = A.AML_CUST_ID /* 상세가 존재하는 자료만 */ AND EXISTS ( SELECT E.SRCH_RSLT_DT FROM NIC22B E WHERE E.SRCH_RSLT_DT = A.SRCH_RSLT_DT AND E.SQ = A.SQ AND ROWNUM <= 1 ) /* 기간 입력 시 */ AND A.SRCH_RSLT_DT >= #{RSK_GRD_RGST_DT_SD } AND A.SRCH_RSLT_DT <= #{RSK_GRD_RGST_DT_ED } /* 검색요청 입력 시 */
AND A.SRCH_RQS_CCD = #{SRCH_RQS_CCD }
) SELECT W.SRCH_RSLT_DT /* 검색일자 */ ,W.SQ ,NVL(Y.CS_NM, Y.ENG_CS_NM) AS CS_NM /* 고객명 */ ,(SELECT F.CD_NM FROM NIC92B F WHERE F.CD = 'A003' AND F.CNTNT = W.WC_LIST_CCD) AS WC_LIST_NM /* 적출기준 */ /* 적출내역 */ ,W.CS_NM AS WLF_CS_NM /* WLF대상명 */ ,Y.ENG_CS_NM AS WLF_ENG_CS_NM /* WLF대상명(영문) */ ,W.AML_CUST_ID /* 고객번호 */ ,W.RNMCNO AS RNMCNO /* 실명번호 */ ,Z.PSPT_NO /* 여권번호 */ ,Z.BRTDY /* 생년월일 */ ,CASE WHEN Z.SEX_CD = '1' THEN '남' WHEN Z.SEX_CD = '2' THEN '여' ELSE NULL END AS SEX_NM /* 성별 */ ,(SELECT G.CD_NM FROM NIC92B G WHERE G.CD = 'M004' AND G.CNTNT = W.NTN_CD) AS NTN_NM /* 소속국가 */ ,X.WC_LIST_CCD AS WC_LIST_CCD /* WLF구분코드 */ ,(SELECT H.CD_NM FROM NIC92B H WHERE H.CD = 'A003' AND H.CNTNT = X.WC_LIST_CCD) AS WLF_WC_LIST_NM /* WLF_적출기준 */ ,X.CS_NM AS WLF_CS_NM /* WLF_영문명 */ ,NULL AS WLF_PSPT_NO /* WLF_여권번호 */ ,X.WL_BIRTHDAY AS WLF_WL_BIRTHDAY /* WLF_생년월일 */ ,NULL AS WLF_SEX_NM /* WLF_성별 */ ,(SELECT I.CD_NM FROM NIC92B I WHERE I.CD = 'M004' AND I.CNTNT = X.NTNLT_CD) AS WLF_NTN_NM /* WLF_소속국가 */ ,X.HIT_R AS WLF_HIT_R /* WLF_정확도 */ ,X.MNG_SNO /* 관리번호 */ ,(SELECT J.CD_NM FROM NIC92B J WHERE J.CD='A915' AND J.CNTNT = W.RLT_CD ) AS RLT_NM /* WLF고객구분코드(01.본인,02.대리인,03.대표자,04.실제소유자) */ ,(SELECT K.CD_NM FROM NIC92B K WHERE K.CD='M012' AND K.CNTNT = Y.CS_TYP_CD ) AS CUST_G_C /* 고객구분 */ ,(SELECT L.CD_NM FROM NIC92B L WHERE L.CD = 'A005' AND L.CNTNT = W.SRCH_RQS_CCD) AS SRCH_RQS_CCD /* ONLINE/BATCH */ FROM SRCH_RSLT_TRGT T , NIC21B W , NIC22B X , NIC01B Y , NIC02B Z WHERE 1 = 1 AND W.SRCH_RSLT_DT = T.SRCH_RSLT_DT AND W.SQ = T.SQ AND X.SRCH_RSLT_DT = W.SRCH_RSLT_DT AND X.SQ = W.SQ AND Y.AML_CUST_ID = W.AML_CUST_ID AND Z.AML_CUST_ID(+) = Y.AML_CUST_ID ORDER BY W.SRCH_RSLT_DT DESC, NVL(Y.CS_NM, Y.ENG_CS_NM)

WITH SRCH_RSLT_TRGT AS ( SELECT NIC21.SRCH_RSLT_DT, NIC21.SQ , IAU.DTBR_NAME , IAU.MANG_NAME FROM NIC21B NIC21 , NIC01B NIC01 , (SELECT PRFT_CNTR_ENTY_ENTY_ID , ACNT_OWNR_ID , DTBR_CODE , DTBR_NAME , MANG_NAME FROM (SELECT IAU.PRFT_CNTR_ENTY_ENTY_ID , IAU.ACNT_OWNR_ID , RANK() OVER(PARTITION BY IAU.ACNT_OWNR_ID ORDER BY IAUSD.DTBR_CODE, IAUAER.EMPY_NO) AS ORD_RANK , NVL(IAUSD.DTBR_CODE, ' ') AS DTBR_CODE , NVL(IAUSD.DTBR_NAME, ' ') AS DTBR_NAME , NVL( (SELECT USER_NAME FROM SID.IDO_A_UWA_USER WHERE USER_ID = IAUAER.EMPY_NO) , IAUAER.EMPY_NO) AS MANG_NAME FROM SID.IDO_A_UUA_ACNT IAU INNER JOIN SID.IDO_A_UUE_SAMSUNG_DPRT IAUSD ON (IAUSD.ENTY_ID = IAU.PRFT_CNTR_ENTY_ENTY_ID) LEFT OUTER JOIN SID.IDO_A_UUA_ACNT_ENTY_RLTP IAUAER ON ( IAUAER.ACNT_ID = IAU.ACNT_ID AND IAUAER.ACNT_ENTY_ROLE_TYPE_CODE = 'MANG') WHERE IAU.ACNT_STAS_TYPE_CODE != 'CL' /* 폐쇄계좌가 아님 */) WHERE ORD_RANK = 1) IAU WHERE 1 = 1 AND NIC21.ETC1 = 'Y' AND NIC01.RNMCNO = NIC21.RNMCNO AND IAU.ACNT_OWNR_ID(+) = TO_NUMBER(NIC01.RNMCNO) /* 상세가 존재하는 자료만 */ AND EXISTS(SELECT NIC22.SRCH_RSLT_DT FROM NIC22B NIC22 WHERE NIC22.SRCH_RSLT_DT = NIC21.SRCH_RSLT_DT AND NIC22.SQ = NIC21.SQ AND ROWNUM <= 1) /* 기간 입력 시 */ AND NIC21.SRCH_RSLT_DT >= #{RSK_GRD_RGST_DT_SD } AND NIC21.SRCH_RSLT_DT <= #{RSK_GRD_RGST_DT_ED } /* 고객명 입력 시 */
AND ( NIC01.CS_NM LIKE '%' || #{CS_NM } || '%' OR NIC01.ENG_CS_NM LIKE '%' || #{CS_NM } || '%')
/* 지점(대표지점) 입력 시 */
AND IAU.PRFT_CNTR_ENTY_ENTY_ID = (SELECT TO_NUMBER(DEP_ID) FROM C_DEP_INFO WHERE DEP_DESC = #{DEP_ID })
/* 구분(내/외국인) 입력 시 */
AND NIC21.NTV_FGNR_CCD = #{NTV_FGNR_CCD }
/* 검색요청 입력 시 */
AND NIC21.SRCH_RQS_CCD = #{SRCH_RQS_CCD }
) SELECT NIC21.SRCH_RSLT_DT /* 검색일자 */ , NIC21.SQ , NVL(NIC01.CS_NM, NIC01.ENG_CS_NM) AS CS_NM /* 고객명 */ , (SELECT NIC92.CD_NM FROM NIC92B NIC92 WHERE NIC92.CD = 'A003' AND NIC92.CNTNT = NIC21.WC_LIST_CCD) AS WC_LIST_NM /* 적출기준 */ /* 적출내역 */ , NIC01.ENG_CS_NM /* 영문명 */ , NIC01.CS_NO /* 실명번호 */ , NIC02.PSPT_NO /* 여권번호 */ , NIC02.BRTDY /* 생년월일 */ , CASE WHEN NIC02.SEX_CD = '1' THEN '남' WHEN NIC02.SEX_CD = '2' THEN '여' ELSE NULL END AS SEX_NM /* 성별 */ , (SELECT NIC92.CD_NM FROM NIC92B NIC92 WHERE NIC92.CD = 'S004' AND NIC92.CNTNT = NIC01.NTN_CD) AS NTN_NM /* 소속국가 */ , (SELECT NIC92.CD_NM FROM NIC92B NIC92 WHERE NIC92.CD = 'A003' AND NIC92.CNTNT = NIC22.WC_LIST_CCD) AS WLF_WC_LIST_NM /* WLF_적출기준 */ , NIC22.CS_NM AS WLF_CS_NM /* WLF_영문명 */ , NULL AS WLF_PSPT_NO /* WLF_여권번호 */ , NIC22.WL_BIRTHDAY AS WLF_WL_BIRTHDAY /* WLF_생년월일 */ , NULL AS WLF_SEX_NM /* WLF_성별 */ , (SELECT NIC92.CD_NM FROM NIC92B NIC92 WHERE NIC92.CD = 'S004' AND NIC92.CNTNT = NIC22.NTNLT_CD) AS WLF_NTN_NM /* WLF_소속국가 */ , NIC22.HIT_R AS WLF_HIT_R /* WLF_정확도 */ , T_SRT.DTBR_NAME AS DEP_TITLE /* 관리지점 */ , T_SRT.MANG_NAME AS USER_NM /* 관리자 */ , (SELECT IAUCC.CLNT_CLSS_CODE FROM SID.IDO_A_UUE_CLIENT_CLSN IAUCC WHERE IAUCC.ENTY_ID = TO_NUMBER(NIC01.RNMCNO) AND IAUCC.CLNT_CLSS_TYPE_CODE = 'CLRT') AS CLNT_CLSS_LVL /* 고객등급 */ , NVL( (SELECT SUM(ISSBM.ASST_VLTN_BLNC_AMNT) FROM SID.IDA_SETL_STD_BAL_M ISSBM WHERE ISSBM.STNR_YYMM = SUBSTR(NIC21.SRCH_RSLT_DT, 1,6) AND ISSBM.CLNT_ENTY_ID = TO_NUMBER(NIC21.RNMCNO)) , 0) AS ASST_VLTN_BLNC_AMNT /* 잔고 */ FROM SRCH_RSLT_TRGT T_SRT , NIC21B NIC21 , NIC22B NIC22 , NIC01B NIC01 , NIC02B NIC02 WHERE 1 = 1 AND NIC21.SRCH_RSLT_DT = T_SRT.SRCH_RSLT_DT AND NIC21.SQ = T_SRT.SQ AND NIC22.SRCH_RSLT_DT = NIC21.SRCH_RSLT_DT AND NIC22.SQ = NIC21.SQ AND NIC01.RNMCNO = NIC21.RNMCNO AND NIC02.RNMCNO(+) = NIC01.RNMCNO ORDER BY NIC21.SRCH_RSLT_DT DESC, NVL(NIC01.CS_NM, NIC01.ENG_CS_NM)

