MERGE INTO NIC27B T
USING DUAL
   ON (T.AML_CUST_ID = #{AML_CUST_ID, jdbcType=VARCHAR}
       AND T.RLT_CD = #{RLT_CD, jdbcType=VARCHAR}
       AND T.RLT_SQ = #{RLT_SQ, jdbcType=VARCHAR}
      )
 WHEN MATCHED THEN
            UPDATE SET T.CS_NM           = #{CS_NM}
                      ,T.ENG_CS_NM       = #{ENG_CS_NM}
                      ,T.NTN_CD          = #{NTN_CD}
                      ,T.NTN_NM          = #{NTN_NM}
                      ,T.INDV_CORP_CCD   = #{INDV_CORP_CCD}
                      ,T.SEX             = #{SEX}
                      ,T.DOB             = #{DOB}
                      ,T.APPL_YN         = 'Y'
                      ,T.HNDL_DY_TM      = SYSDATE
                      ,T.HNDL_P_ENO      = #{USER_ID}
 WHEN NOT MATCHED THEN
                INSERT ( T.AML_CUST_ID
                        ,T.RLT_CD
                        ,T.RLT_SQ
                        ,T.CS_NM
                        ,T.ENG_CS_NM
                        ,T.NTN_CD
                        ,T.NTN_NM
                        ,T.INDV_CORP_CCD
                        ,T.SEX
                        ,T.DOB
                        ,T.APPL_YN
                        ,T.HNDL_DY_TM
                        ,T.HNDL_P_ENO
                       )
                VALUES ( #{AML_CUST_ID}
                        ,#{RLT_CD}
                        ,#{RLT_SQ}
                        ,#{CS_NM}
                        ,#{ENG_CS_NM}
                        ,#{NTN_CD}
                        ,#{NTN_NM}
                        ,#{INDV_CORP_CCD}
                        ,#{SEX}
                        ,#{DOB}
                        ,'Y'
                        ,SYSDATE
                        ,#{USER_ID}
                       )

UPDATE NIC27B A
   SET A.HNDL_DY_TM = SYSDATE
      ,A.HNDL_P_ENO = #{USER_ID}
 WHERE A.AML_CUST_ID = #{AML_CUST_ID}

