SELECT ROWNUM, W.* FROM ( SELECT A.REG_DT ,FN_DATE_FORMAT(A.REG_DT) AS REG_DT_F ,A.REG_NO ,A.SEQ ,A.REG_ID ,GET_USER_NAME(A.REG_ID) AS REG_ID_DISPLAY ,A.CS_NM ,A.INDV_CORP_CCD ,A.NTNLT_CD ,A.DOB ,A.SEX ,A.WL_CRT_DT ,FN_DATE_FORMAT(A.WL_CRT_DT) AS WL_CRT_DT_F ,A.WL_CRT_SDWL ,A.WL_CRT_ID ,GET_USER_NAME(A.WL_CRT_ID) AS WL_CRT_ID_DISPLAY ,'U' AS IDU ,DECODE(A.WL_CRT_DT, NULL, '', (DECODE(B.MAT_CNT, '', 'N', 'Y') ) ) AS MAT_YN FROM NIC20B_AE A LEFT OUTER JOIN ( SELECT Y.RQRM_DT, Y.REG_NO, Y.SEQ, Y.REG_DT, COUNT(*) AS MAT_CNT FROM NIC20B_AE X INNER JOIN NIC22B_AE Y ON Y.RQRM_DT = X.WL_CRT_DT AND Y.REG_NO = X.REG_NO AND Y.REG_NO = X.REG_NO AND Y.SEQ = X.SEQ AND Y.REG_DT = X.REG_DT GROUP BY Y.RQRM_DT, Y.REG_NO, Y.SEQ, Y.REG_DT ) B ON A.WL_CRT_DT = B.RQRM_DT AND A.REG_NO = B.REG_NO AND A.SEQ = B.SEQ AND A.REG_DT = B.REG_DT WHERE 1=1
AND A.REG_DT >= #{stDate}
AND A.REG_DT <= #{edDate}
AND A.CS_NM = #{CS_NM}
AND A.INDV_CORP_CCD = #{INDV_CORP_CCD}
AND A.NTNLT_CD = #{NTNLT_CD}
AND A.SEX = #{SEX}
AND A.WL_CRT_DT IS NOT NULL
AND A.WL_CRT_DT IS NULL
ORDER BY A.REG_DT DESC, A.REG_NO ASC, A.SEQ ASC ) W WHERE 1=1
AND W.MAT_YN = #{MAT_YN}
ORDER BY ROWNUM

SELECT A.RQRM_DT ,FN_DATE_FORMAT(A.RQRM_DT) AS RQRM_DT_F ,A.REG_NO ,A.SEQ ,A.MNG_SNO ,A.RLT_SRCH_SQ ,A.RQRM_ID ,A.WC_LIST_CCD ,GET_CODE_NAME('A003', A.WC_LIST_CCD) AS WC_LIST_CCD_NM ,A.CS_NM ,A.INDV_CORP_CCD ,A.NTNLT_CD ,A.ADDR ,A.DOB ,FN_DATE_FORMAT(A.DOB) AS DOB_F ,A.HIT_R ,A.SEX ,A.WC_UID ,A.WL_NM_FIRST ,A.WL_NM_MIDDLE ,A.WL_NM_LAST FROM NIC22B_AE A WHERE A.RQRM_DT = #{WL_CRT_DT} AND A.REG_NO = #{REG_NO} AND A.SEQ = #{SEQ} AND A.REG_DT = #{REG_DT}
AND A.HIT_R >= #{stACC}
AND A.HIT_R <= #{edACC}
AND A.WC_LIST_CCD = #{WLF_TYPE}

SELECT NVL(MAX(A.SEQ), 0) + 1 AS SEQ
  FROM NIC20B_AE A
 WHERE A.REG_DT = #{REG_DT}
   AND A.REG_NO = #{REG_NO}

