SELECT X.REQ_DT ,X.CATEGORY ,(SELECT I.CD_NM FROM NIC92B I WHERE I.CD = 'A003' AND X.CATEGORY = I.CNTNT) AS CATEGORY_NM ,X.ADD_CNT ,X.CHG_CNT ,X.DEL_CNT ,X.ACTIVE_CNT ,X.INACTIVE_CNT ,X.TOTAL_CNT ,X.SEQ FROM ( WITH BASETABLE AS ( SELECT SUBSTR(A.REG_DT, 1, 8) AS REQ_DT ,A.TYPE ,A.CATEGORY ,A.ACTIVE_CNT ,A.INACTIVE_CNT ,A.T_CNT ,A.SEQ ,A.ADD_CNT ,A.UPD_CNT ,A.DEL_CNT FROM NIC19B_REPORT A WHERE 1 = 1 AND A.REG_DT BETWEEN #{REG_DT_SD} || '000000' AND #{REG_DT_ED} || '235959' AND A.SEQ BETWEEN 1 AND 30 AND A.TYPE = 'Dataset1'
AND A.CATEGORY = #{WLF_TYPE}
), REPORT AS ( SELECT B.REQ_DT ,B.CATEGORY ,B.ACTIVE_CNT ,B.INACTIVE_CNT ,B.T_CNT ,B.SEQ ,B.ADD_CNT ,B.UPD_CNT ,B.DEL_CNT FROM BASETABLE B WHERE B.SEQ BETWEEN 1 AND 10 ), REPORT2 AS ( SELECT C.REQ_DT ,C.CATEGORY ,C.ACTIVE_CNT ,C.INACTIVE_CNT ,C.T_CNT ,C.SEQ ,C.ADD_CNT ,C.UPD_CNT ,C.DEL_CNT FROM BASETABLE C WHERE C.CATEGORY IN ( 'Politically Exposed Person (PEP)','Relative or Close Associate (RCA)' ,'Special Interest Entity (SIE)','Special Interest Person (SIP)') ), TOTREPORT AS ( SELECT 'Total' AS CATEGORY ,SUM(D.ACTIVE_CNT) AS ACTIVE_CNT ,SUM(D.INACTIVE_CNT) AS INACTIVE_CNT ,SUM(D.T_CNT) AS T_CNT ,SUM(D.ADD_CNT) AS ADD_CNT ,SUM(D.UPD_CNT) AS CHG_CNT ,SUM(D.DEL_CNT) AS DEL_CNT ,31 AS SEQ FROM BASETABLE D WHERE D.SEQ BETWEEN 1 AND 30 ) SELECT M.REQ_DT ,M.CATEGORY ,M.ADD_CNT ,M.CHG_CNT ,M.DEL_CNT ,M.ACTIVE_CNT ,M.INACTIVE_CNT ,M.TOTAL_CNT ,M.SEQ FROM ( SELECT G.REQ_DT ,G.CATEGORY ,NVL(G.ACTIVE_CNT, 0) AS ACTIVE_CNT ,NVL(G.INACTIVE_CNT, 0) AS INACTIVE_CNT ,NVL(G.T_CNT, 0) AS TOTAL_CNT ,G.SEQ ,NVL(G.ADD_CNT, 0) AS ADD_CNT ,NVL(G.UPD_CNT, 0) AS CHG_CNT ,NVL(G.DEL_CNT, 0) AS DEL_CNT FROM ( SELECT E.REQ_DT ,E.CATEGORY ,E.ACTIVE_CNT ,E.INACTIVE_CNT ,E.T_CNT ,E.SEQ ,E.ADD_CNT ,E.UPD_CNT ,E.DEL_CNT FROM REPORT E UNION SELECT F.REQ_DT ,F.CATEGORY ,F.ACTIVE_CNT ,F.INACTIVE_CNT ,F.T_CNT ,F.SEQ ,F.ADD_CNT ,F.UPD_CNT ,F.DEL_CNT FROM REPORT2 F ) G WHERE 1 = 1 ORDER BY G.SEQ ) M UNION ALL SELECT '' AS REQ_DT ,'Total' AS CATEGORY ,NVL(SUM(H.ADD_CNT), 0) AS ADD_CNT ,NVL(SUM(H.CHG_CNT), 0) AS CHG_CNT ,NVL(SUM(H.DEL_CNT), 0) AS DEL_CNT ,NVL(SUM(H.ACTIVE_CNT), 0) AS ACTIVE_CNT ,NVL(SUM(H.INACTIVE_CNT), 0) AS INACTIVE_CNT ,NVL(SUM(H.T_CNT), 0) AS T_CNT ,31 AS SEQ FROM TOTREPORT H ) X

SELECT A.SRCH_RQS_REG_NO ,A.SRCH_RSLT_DT ,A.SRCH_RQS_CCD ,A.APP_NO ,A.RNM_CCD ,A.AML_CUST_ID ,A.RNMCNO AS RNMCNO_ORG ,A.RNMCNO ,A.INDV_CORP_CCD ,(SELECT C.CD_NM FROM NIC92B C WHERE C.CD = 'M006' AND C.CNTNT = A.INDV_CORP_CCD) AS INDV_CORP_CCD_NM ,A.NTV_FGNR_CCD ,B.CS_NM ,B.ENG_CS_NM ,A.NTN_CD ,A.NTN_NM ,A.DOB ,A.WC_LIST_GRP_CD ,A.DCSN_F ,A.PSBL_F ,A.RSLT_BRN_CD ,A.WLF_DCD ,A.RSN_CNTNT ,A.HNDL_DY_TM ,A.HNDL_P_ENO ,A.WL_OPEN_DATA_YN ,CASE WHEN (TRIM(A.PSBL_F) IS NULL OR TRIM(A.PSBL_F) = '') OR (TRIM(A.WLF_DCD) IS NULL OR TRIM(A.WLF_DCD) = '') OR (TRIM(A.RSN_CNTNT) IS NULL OR TRIM(A.RSN_CNTNT) = '') THEN 'N' ELSE 'Y' END AS SAVE_STATUS ,P.SN_CCD ,SUBSTR(P.REG_DT,1,4) ||'-'|| SUBSTR(P.REG_DT,5,2)||'-'||SUBSTR(P.REG_DT,7,2) AS APP_DT -- 결재일자 ,CASE WHEN P.SN_CCD IS NULL THEN '미결재' ELSE (SELECT D.CD_NM FROM NIC92B D WHERE D.CD = 'A038' AND D.CNTNT = P.SN_CCD ) -- A038 결재상태코드 END AS APP_ST -- 결재상태 ,P.GYLJ_ROLE_NM AS APP_NM -- 결재자 ,P.APPR_ROLE_NM -- 결재한사람 ,P.TARGET_ROLE_NM -- 결재할사람 ,A.APP_NO AS APP_NO -- 결재번호 ,P.SNO ,P.NUM_SQ ,P.GYLJ_LINE_G_C ,P.WLR_SQ FROM NIC21B_APPR A LEFT OUTER JOIN ( SELECT M.SNO ,M.APP_DT ,M.WLR_SQ ,M.REG_DT ,M.SN_CCD ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.APPR_ROLE_ID) AS APPR_ROLE_NM -- 결제한사람 ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.TARGET_ROLE_ID) AS TARGET_ROLE_NM -- 결제할사람 ,S.GYLJ_ROLE_ID -- 결재한 사람ID ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = S.GYLJ_ROLE_ID) AS GYLJ_ROLE_NM ,M.NUM_SQ ,M.GYLJ_LINE_G_C ,M.APP_NO FROM AML_APPR M, C_GYLJ_D S WHERE S.GYLJ_LINE_G_C = 'WLR' AND S.GYLJ_LINE_G_C = M.GYLJ_LINE_G_C AND S.SNO = M.SNO AND (M.APP_NO, M.NUM_SQ) IN (SELECT T.APP_NO, MAX(T.NUM_SQ) FROM AML_APPR T WHERE T.APP_NO = M.APP_NO AND T.GYLJ_LINE_G_C = 'WLR' GROUP BY T.APP_NO ) ) P ON (A.APP_NO = P.APP_NO) ,NIC01B B WHERE 1=1 AND A.AML_CUST_ID = B.AML_CUST_ID
AND A.SRCH_RSLT_DT BETWEEN #{RSK_GRD_RGST_DT_SD} AND #{RSK_GRD_RGST_DT_ED}
AND A.SRCH_RQS_CCD = #{SRCH_RQS_CCD}
AND A.AML_CUST_ID LIKE CONCAT(#{AML_CUST_ID},'%')
AND P.SN_CCD = #{SN_CCD}
AND P.SN_CCD = #{SN_CCD}
AND P.SN_CCD = #{SN_CCD}
AND A.APP_NO IS NULL
AND A.WL_OPEN_DATA_YN = #{WL_OPEN_DATA_YN}
AND A.INDV_CORP_CCD = #{INDV_CORP_CCD}
ORDER BY A.SRCH_RSLT_DT DESC, TO_NUMBER(A.SRCH_RQS_REG_NO) DESC

SELECT /*AML_10_30_07_01.getSearch*/ ROW_NUMBER() OVER (ORDER BY A.WC_UID DESC, A.SQ ASC) AS SEQ ,A.WC_LIST_CCD -- WATCH 목록 구분코드 ,GET_CODE_NAME('A003', A.WC_LIST_CCD) AS WC_LIST_CCD_NM -- W050: 회사가정한 요주의 인물 ,A.SQ -- 19B_LOCAL 등록 순번 ,A.WC_UID -- 'W050' + SQ ,A.WC_LIST_GRP_CD -- Watch List 그룹코드 ,GET_CODE_NAME('W010', A.WC_LIST_GRP_CD) AS WC_LIST_GRP_CD_NM -- C: 고객 ,A.CS_NM ,A.CS_NM_ORG ,A.INDV_CORP_CCD ,GET_CODE_NAME('M006', A.INDV_CORP_CCD) AS INDV_CORP_CCD_NM ,A.NTN_CD -- 국적코드 - WL국가코드 ,A.NTN_NM -- 국적명 ,A.SEX -- 성별 1: 남자, 2: 여자 ,A.DOB -- WL생년월일 ,A.ADDR_DESC -- WL주소상세 ,A.ADDR_CITY -- WL주소City ,A.ADDR_STATE -- WL주소State ,A.ADDR_NTN_CD -- WL주소Country ,A.REG_REASON -- 등록사유 ,A.START_DT -- 적용시작일 ,A.END_DT -- 적용종료일 ,A.USE_YN -- 사용여부 ,TO_CHAR(A.HNDL_DY_TM, 'YYYY-MM-DD HH24:MI:SS') AS HNDL_DY_TM -- 등록일시 ,A.HNDL_P_ENO -- 처리자사번 ,A.GYLJ_S_C AS SN_CCD -- 결재상태 ,GET_CODE_NAME('A038', A.GYLJ_S_C) AS APP_ST -- 결재상태명 ,A.APPL_YN -- 적용여부 ,A.APPL_DT -- 적용일자 ,A.APP_NO -- 결재번호 ,B.REG_DT AS APP_DT -- 결재일자 ,A.PRV_APP_NO -- 이전 결재번호 ,B.APPR_ROLE_ID -- 결재자ID ,C.ROLE_NM AS APPR_ROLE_NM -- 결재자명 ,B.TARGET_ROLE_ID -- 다음 결재자ID ,D.ROLE_NM AS TARGET_ROLE_NM -- 다음 결재자명 ,B.SNO ,B.WLR_SQ ,B.GYLJ_LINE_G_C FROM NIC19B_LOCAL A LEFT OUTER JOIN AML_APPR B ON A.APP_NO = B.APP_NO AND B.GYLJ_LINE_G_C = #{GYLJ_LINE_G_C, jdbcType=VARCHAR} LEFT OUTER JOIN C_ROLE C ON B.APPR_ROLE_ID = C.ROLE_ID LEFT OUTER JOIN C_ROLE D ON B.TARGET_ROLE_ID = C.ROLE_ID WHERE NOT EXISTS ( SELECT 1 FROM NIC19B_LOCAL_HIST X WHERE A.WC_UID= X.WC_UID AND A.WC_LIST_CCD = X.WC_LIST_CCD AND X.USE_YN = 'N' AND X.APPL_YN= 'N' AND X.GYLJ_S_C = 'N' )
AND A.APP_NO IS NULL
AND B.SN_CCD = #{SN_CCD}
AND A.HNDL_DY_TM BETWEEN TO_DATE(#{RSK_RGST_DT_SD}||'000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{RSK_RGST_DT_ED}||'235959', 'YYYYMMDDHH24MISS')
AND UPPER(A.CS_NM) LIKE '%' || UPPER(#{SRCH_CS_NM}) || '%'
AND A.APPL_YN = #{APPL_YN}
AND A.USE_YN = #{USE_YN}

SELECT /*AML_10_30_07_01.getSearch*/ ROW_NUMBER() OVER (ORDER BY A.WC_UID DESC, A.SQ ASC) AS SEQ ,A.WC_LIST_CCD -- WATCH 목록 구분코드 ,GET_CODE_NAME('A003', A.WC_LIST_CCD) AS WC_LIST_CCD_NM -- W050: 회사가정한 요주의 인물 ,A.SQ -- 19B_LOCAL 등록 순번 ,A.WC_UID -- 'W050' + SQ ,A.WC_LIST_GRP_CD -- Watch List 그룹코드 ,GET_CODE_NAME('W010', A.WC_LIST_GRP_CD) AS WC_LIST_GRP_CD_NM -- C: 고객 ,A.CS_NM ,A.CS_NM_ORG ,A.INDV_CORP_CCD ,GET_CODE_NAME('M006', A.INDV_CORP_CCD) AS INDV_CORP_CCD_NM ,A.NTN_CD -- 국적코드 - WL국가코드 ,A.NTN_NM -- 국적명 ,A.SEX -- 성별 1: 남자, 2: 여자 ,A.DOB -- WL생년월일 ,A.ADDR_DESC -- WL주소상세 ,A.ADDR_CITY -- WL주소City ,A.ADDR_STATE -- WL주소State ,A.ADDR_NTN_CD -- WL주소Country ,A.REG_REASON -- 등록사유 ,A.START_DT -- 적용시작일 ,A.END_DT -- 적용종료일 ,A.USE_YN -- 사용여부 ,TO_CHAR(A.HNDL_DY_TM, 'YYYY-MM-DD HH24:MI:SS') AS HNDL_DY_TM -- 등록일시 ,A.HNDL_P_ENO -- 처리자사번 ,A.GYLJ_S_C AS SN_CCD -- 결재상태 ,GET_CODE_NAME('A038', A.GYLJ_S_C) AS APP_ST -- 결재상태명 ,A.APPL_YN -- 적용여부 ,A.APPL_DT -- 적용일자 ,A.APP_NO -- 결재번호 ,B.REG_DT AS APP_DT -- 결재일자 ,A.PRV_APP_NO -- 이전 결재번호 ,B.APPR_ROLE_ID -- 결재자ID ,C.ROLE_NM AS APPR_ROLE_NM -- 결재자명 ,B.TARGET_ROLE_ID -- 다음 결재자ID ,D.ROLE_NM AS TARGET_ROLE_NM -- 다음 결재자명 ,B.SNO ,B.WLR_SQ ,B.GYLJ_LINE_G_C FROM NIC19B_LOCAL A LEFT OUTER JOIN AML_APPR B ON A.APP_NO = B.APP_NO AND B.GYLJ_LINE_G_C = #{GYLJ_LINE_G_C, jdbcType=VARCHAR} LEFT OUTER JOIN C_ROLE C ON B.APPR_ROLE_ID = C.ROLE_ID LEFT OUTER JOIN C_ROLE D ON B.TARGET_ROLE_ID = C.ROLE_ID WHERE 1 = 1
AND A.APP_NO IS NULL
AND B.SN_CCD = #{SN_CCD}
AND A.HNDL_DY_TM BETWEEN TO_DATE(#{RSK_RGST_DT_SD, jdbcType=VARCHAR}||'000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{RSK_RGST_DT_ED, jdbcType=VARCHAR}||'235959', 'YYYYMMDDHH24MISS')
AND UPPER(A.CS_NM) LIKE '%' || UPPER(#{SRCH_CS_NM}) || '%'
AND A.APPL_YN = #{APPL_YN}
AND A.USE_YN = #{USE_YN}

