            )

mapper.select:
WITH SRCH_RSLT_TRGT AS ( SELECT A.SRCH_RSLT_DT, A.SQ FROM NIC21B A ,NIC01B B WHERE 1 = 1 AND B.AML_CUST_ID = A.AML_CUST_ID /* 상세가 존재하는 자료만 */ AND EXISTS ( SELECT C.SRCH_RSLT_DT FROM NIC22B C WHERE C.SRCH_RSLT_DT = A.SRCH_RSLT_DT AND C.SQ = A.SQ AND ROWNUM <= 1) /* 기간 입력 시 */ AND A.SRCH_RSLT_DT >= #{RSK_GRD_RGST_DT_SD } AND A.SRCH_RSLT_DT <= #{RSK_GRD_RGST_DT_ED } /* 검색요청 입력 시 */
AND A.SRCH_RQS_CCD = #{SRCH_RQS_CCD }
) SELECT W.SRCH_RSLT_DT /* 검색일자 */ ,W.SQ ,NVL(Y.CS_NM, Y.ENG_CS_NM) AS CS_NM /* 고객명 */ ,(SELECT D.CD_NM FROM NIC92B D WHERE D.CD = 'A003' AND D.CNTNT = W.WC_LIST_CCD) AS WC_LIST_NM /* 적출기준 */ /* 적출내역 */ ,W.CS_NM AS WLF_CS_NM /* WLF대상명 */ ,Y.ENG_CS_NM AS WLF_ENG_CS_NM /* WLF대상명(영문) */ ,W.AML_CUST_ID /* 고객번호 */ ,W.RNMCNO AS RNMCNO /* 실명번호 */ ,Z.PSPT_NO /* 여권번호 */ ,Z.BRTDY /* 생년월일 */ ,CASE WHEN Z.SEX_CD = '1' THEN '남' WHEN Z.SEX_CD = '2' THEN '여' ELSE NULL END AS SEX_NM /* 성별 */ ,(SELECT E.CD_NM FROM NIC92B E WHERE E.CD = 'M004' AND E.CNTNT = W.NTN_CD) AS NTN_NM /* 소속국가 */ ,X.WC_LIST_CCD AS WC_LIST_CCD /* WLF구분코드 */ ,(SELECT F.CD_NM FROM NIC92B F WHERE F.CD = 'A003' AND F.CNTNT = X.WC_LIST_CCD) AS WLF_WC_LIST_NM /* WLF_적출기준 */ ,X.CS_NM AS WLF_CS_NM /* WLF_영문명 */ ,NULL AS WLF_PSPT_NO /* WLF_여권번호 */ ,X.WL_BIRTHDAY AS WLF_WL_BIRTHDAY /* WLF_생년월일 */ ,NULL AS WLF_SEX_NM /* WLF_성별 */ ,(SELECT G.CD_NM FROM NIC92B G WHERE G.CD = 'M004' AND G.CNTNT = X.NTNLT_CD) AS WLF_NTN_NM /* WLF_소속국가 */ ,X.HIT_R AS WLF_HIT_R /* WLF_정확도 */ ,X.MNG_SNO /* 관리번호 */ ,(SELECT H.CD_NM FROM NIC92B H WHERE H.CD='A915' AND H.CNTNT = W.RLT_CD ) AS RLT_NM /* WLF고객구분코드(01.본인,02.대리인,03.대표자,04.실제소유자) */ ,(SELECT I.CD_NM FROM NIC92B I WHERE I.CD='M012' AND I.CNTNT = Y.CS_TYP_CD ) AS CUST_G_C /* 고객구분 */ ,(SELECT J.CD_NM FROM NIC92B J WHERE J.CD = 'A005' AND J.CNTNT = W.SRCH_RQS_CCD) AS SRCH_RQS_CCD /* ONLINE/BATCH */ FROM SRCH_RSLT_TRGT T ,NIC21B W ,NIC22B X ,NIC01B Y ,NIC02B Z WHERE 1 = 1 AND W.SRCH_RSLT_DT = T.SRCH_RSLT_DT AND W.SQ = T.SQ AND X.SRCH_RSLT_DT = W.SRCH_RSLT_DT AND X.SQ = W.SQ AND Y.AML_CUST_ID = W.AML_CUST_ID AND Z.AML_CUST_ID(+) = Y.AML_CUST_ID ORDER BY W.SRCH_RSLT_DT DESC, NVL(Y.CS_NM, Y.ENG_CS_NM)

mapper.update:
UPDATE NIC21B A
   SET A.WL_UPDATE_DT = TO_CHAR(SYSDATE,'YYYYMMDD')
      ,A.WLF_DCD      = #{WLF_DCD}
      ,A.PSBL_F = #{PSBL_F}
      ,A.RSN_CNTNT = #{RSN_CNTNT}
 WHERE A.SRCH_RSLT_DT = #{SRCH_RSLT_DT}
   AND A.SQ = #{SQ}

UPDATE NIC35B A
   SET A.WL_CON_DT = TO_CHAR(SYSDATE,'YYYYMMDD')
      ,A.WL_TRD_CAN_F = #{WL_TRD_CON_F}
      ,A.WL_CON_P_ENO = #{USER_ID}
 WHERE A.AML_CUST_ID = #{AML_CUST_ID}

UPDATE NIC21B A
   SET 
       A.APP_NO = ( SELECT R.APP_NO
                      FROM AML_APPR R
                     WHERE 1 = 1
                       AND R.GYLJ_LINE_G_C = #{GYLJ_LINE_G_C}
                       AND R.APP_DT        = #{APP_DT}
                       AND R.WLR_SQ        = #{WLR_SQ}
                       AND ROWNUM = 1
                  )
 WHERE A.SRCH_RSLT_DT = #{APP_DT}
   AND A.SQ           = #{WLR_SQ}

mapper.select:
SELECT X.SQ ,X.SRCH_RQS_CCD ,GET_CODE_NAME( 'A005', X.SRCH_RQS_CCD) AS SRCH_RQS_CCD_NM ,X.SRCH_RSLT_DT -- 검색결과일자 ,X.CS_NM1 AS CS_NM -- 고객명 --,X.CS_NM AS ENG_CS_NM -- 영문고객명 ,CASE WHEN LENGTH(X.CS_NM) > 50 THEN SUBSTR(X.CS_NM,1,50) || '...' ELSE X.CS_NM END AS ENG_CS_NM ,(SELECT E.CD_NM FROM NIC92B E WHERE E.CD='M002' AND E.CNTNT = X.RNM_CCD) AS RNM_CCD -- 실명구분코드 ,X.RNMCNO -- 실명번호 ,(SELECT F.CD_NM FROM NIC92B F WHERE F.CD='M004' AND F.CNTNT = X.NTN_CD) NTN_CD -- 국가 ,X.WC_LIST_CCD -- W/L 구분 ,X.RSN_CNTNT ,X.ETC1 AS TRANS_TYPE ,GET_CODE_NAME( 'A901', X.ETC1) AS TRANS_TYPE_NM ,X.RSLT_BRN_CD AS DPRT_CD ,(SELECT G.DPRT_NM FROM NIC41B G WHERE G.DPRT_CD = X.RSLT_BRN_CD) AS DPRT_NM ,X.ETC3 AS FILE_YN ,X.ETC2 AS SEQ --,X.ETC4 AS FIELD_NAME ,CASE WHEN ( (SUBSTR(X.ETC4, LENGTH(X.ETC4) - 1, LENGTH(X.ETC4) ) = ',W') OR (SUBSTR(X.ETC4, LENGTH(X.ETC4) - 1, LENGTH(X.ETC4) ) = ',E') ) THEN SUBSTR(X.ETC4, 1, LENGTH(X.ETC4) - 1) || '(' || GET_CODE_NAME( 'A912', SUBSTR(X.ETC4, LENGTH(X.ETC4), LENGTH(X.ETC4))) || ')' ELSE X.ETC4 END AS FIELD_NAME ,CASE WHEN ( (SUBSTR(X.ETC4, LENGTH(X.ETC4) - 1, LENGTH(X.ETC4) ) = ',W') OR (SUBSTR(X.ETC4, LENGTH(X.ETC4) - 1, LENGTH(X.ETC4) ) = ',E') ) THEN SUBSTR(X.ETC4, LENGTH(X.ETC4), LENGTH(X.ETC4) ) ELSE '' END AS SWIFT_TYPE ,X.S_FILENAME ,X.TRANS_YN || DECODE(X.TRANS_YN,'Y',DECODE(X.TRANS_L_CD,NULL,'','('|| GET_CODE_NAME( 'A908',X.TRANS_L_CD) ||')'),'') AS TRANS_YN ,GET_CODE_NAME( 'A910', X.TRANS_YN) || DECODE(X.TRANS_YN,'Y',DECODE(X.TRANS_L_CD,NULL,'','('|| GET_CODE_NAME( 'A908', X.TRANS_L_CD) ||')'),'') AS TRANS_YN_NM ,X.MSG_TYPE ,GET_CODE_NAME( (SELECT H.GRP_CD FROM NIC92B H WHERE H.CD = 'A901' AND H.CNTNT = X.ETC1), X.MSG_TYPE) AS MSG_TYPE_NM ,X.ADDR FROM ( SELECT A.*, B.CS_NM AS CS_NM1, B.ENG_CS_NM, E.S_FILENAME, E.TRANS_YN, E.MSG_TYPE, E.TRANS_L_CD FROM NIC21B A LEFT OUTER JOIN NIC21B_FILE E ON ( A.ETC2 = E.SEQ ) LEFT OUTER JOIN NIC01B B ON (A.RNMCNO = B.RNMCNO) WHERE A.SRCH_RSLT_DT BETWEEN #{RSK_GRD_RGST_DT_SD} AND #{RSK_GRD_RGST_DT_ED} AND ( SELECT COUNT(*) FROM NIC22B F WHERE F.SRCH_RSLT_DT = A.SRCH_RSLT_DT AND F.SQ = A.SQ ) > 0 ) X LEFT OUTER JOIN ( SELECT C.AML_CUST_ID ,(SELECT I.CD_NM FROM NIC92B I WHERE I.CD='A006' AND I.CNTNT = C.WL_TRD_CON_F) WL_TRD_CON_F_NM-- 거래거절 ,C.WL_TRD_CON_F -- 거래거절 ,D.SN_CCD --거절취소요청여부 ,D.SN_STAT --거절취소요청여부 ,D.SN_CMNT ,D.INST_ID FROM NIC35B C LEFT OUTER JOIN NIC38B D ON ( C.KYC_INST_ID = D.INST_ID ) ) Y ON (X.AML_CUST_ID = Y.AML_CUST_ID) WHERE 1 = 1
AND X.NTV_FGNR_CCD = #{NTV_FGNR_CCD}
AND X.SRCH_RQS_CCD = #{SRCH_RQS_CCD}
AND X.RSLT_BRN_CD = #{BRN_CD}
AND X.TRANS_YN = #{TRANS_YN}
ORDER BY X.SRCH_RSLT_DT DESC, X.SQ DESC

SELECT A.AML_CUST_ID ,A.CS_NM ,A.ENG_CS_NM ,GET_CODE_NAME( 'M002', A.RNM_CNFR_CCD) AS RNM_CNFR_CCD_NM ,GET_CODE_NAME( 'M005', A.RSDNC_F) AS RSDNC_F_NM ,A.RNMCNO AS RNMCNO_VIEW ,GET_CODE_NAME( 'M001' ,A.CS_ST_CD) AS CS_ST_CD -- 고객상태 ,FN_DATE_FORMAT(A.CS_RGST_DT) AS CS_RGST_DT -- 고객등록일자 ,GET_CODE_NAME( 'M004' ,A.NTN_CD) AS NTN_NM -- 국가 ,FN_DATE_FORMAT(A.AML_CRT_DT) AS AML_CRT_DT -- AML 생성일자 ,GET_CODE_NAME( 'A004', A.RSK_GRD_CD) AS RSK_GRD_CD -- 위험등급 ,A.RSK_GRD_MRK ,FN_DATE_FORMAT(A.RSK_GRD_RGST_DT) AS RSK_GRD_RGST_DT -- 위험등급등록일 ,A.STR_RPR_TNO ,A.CTR_RPR_TNO ,CASE WHEN A.CS_EDD_MNG_F='1' THEN 'Y' ELSE 'N' END AS CS_EDD_MNG_F_NM -- EDD 대상 여부 ,(SELECT D.DPRT_NM FROM NIC41B D WHERE D.DPRT_CD = A.CS_EXCTN_BRN_CD) AS CS_EXCTN_BRN_CD_NM -- 개설지점 ,A.CS_NM AS CS_NM2 ,A.ENG_CS_NM AS ENG_CS_NM2 ,GET_CODE_NAME( 'M002', A.RNM_CNFR_CCD) AS RNM_CNFR_CCD_NM2 ,GET_CODE_NAME( 'M005', A.RSDNC_F) AS RSDNC_F_NM2 ,GET_CODE_NAME( 'M001' ,A.CS_ST_CD) AS CS_ST_CD2 -- 고객상태 ,FN_DATE_FORMAT(A.CS_RGST_DT) AS CS_RGST_DT2 -- 고객등록일자 ,GET_CODE_NAME( 'M004' ,A.NTN_CD) AS NTN_NM2 -- 국가 ,FN_DATE_FORMAT(A.AML_CRT_DT) AS AML_CRT_DT2 -- AML 생성일자 ,GET_CODE_NAME( 'A004' , A.RSK_GRD_CD) AS RSK_GRD_CD2 -- 위험등급 ,A.RSK_GRD_MRK AS RSK_GRD_MRK2 ,FN_DATE_FORMAT(A.RSK_GRD_RGST_DT) AS RSK_GRD_RGST_DT2 -- 위험등급등록일 ,A.STR_RPR_TNO AS STR_RPR_TNO2 ,A.CTR_RPR_TNO AS CTR_RPR_TNO2 ,CASE WHEN A.CS_EDD_MNG_F='1' THEN 'Y' ELSE 'N' END AS CS_EDD_MNG_F_NM2 -- EDD 대상 여부 ,(SELECT D.DPRT_NM FROM NIC41B D WHERE D.DPRT_CD = A.CS_EXCTN_BRN_CD) AS CS_EXCTN_BRN_CD_NM2 -- 개설지점 FROM VIC01B A WHERE 1=1
AND A.AML_CUST_ID = #{INPUT_AML_CUST_ID}
AND A.INDV_CORP_CCD = #{INDV_CORP_CCD}
AND A.CS_NM = #{CS_INPUT}

