MERGE INTO CDD_WLF_INFO T
USING DUAL
   ON ( T.RNNO= #{RNNO} AND T.SEQNO = #{SEQNO} )
 WHEN MATCHED THEN
            UPDATE SET T.WLF_EXC_DT =#{WLF_EXC_DT}
                      ,T.WLF_EXC_NTH =#{WLF_EXC_NTH}
                      ,T.WLF_REVW_RSLT_CD =#{WLF_REVW_RSLT_CD}
