mapper.delete:
DELETE NIC92B A
 WHERE A.CD = #{CD}
   AND A.CNTNT = #{CNTNT}

DELETE NIC95B A
 WHERE A.CD = #{CD}
   AND A.CD_VL9 = #{CD_VL9}
   AND A.TRNSFRM_CD = #{TRNSFRM_CD}

mapper.select:
SELECT '0' AS SELECTED ,A.CD -- 코드 ,A.CNTNT -- 내용 ,A.CNTNT AS OLD_CD -- 내용 ,A.CD_NM -- 코드명 ,A.USE_F -- 사용여부 ,A.CD_RNK_SQ -- 코드순위일련번호 ,A.GRP_CD -- 그룹코드 ,A.HNDL_DY_TM -- 처리일시 ,GET_USER_NAME(A.HNDL_P_ENO) AS HNDL_P_ENO -- 처리자사번 FROM NIC92B A WHERE A.CD = #{CD}
AND UPPER(A.CD_NM) LIKE '%'||UPPER(#{VA_VA})||'%'
ORDER BY A.CD_RNK_SQ, A.CNTNT

SELECT '0' AS SELECTED ,A.CD ,A.CD_NM ,A.CD_VL9 ,A.CD_VL_NM ,A.TRNSFRM_CD ,A.TRNSFRM_CD_EXPL ,A.HNDL_DY_TM -- 처리일시 ,GET_USER_NAME(A.HNDL_P_ENO) AS HNDL_P_ENO -- 처리자사번 ,A.CD_VL9 AS CD_VL9_REAL ,A.TRNSFRM_CD AS TRNSFRM_CD_REAL ,DECODE((SELECT COUNT(*) FROM NIC92B WHERE CD = A.CD AND CNTNT = A.TRNSFRM_CD),1,'Y','N') AS CD_YN FROM NIC95B A WHERE A.CD = #{CD}
AND UPPER(A.CD_VL_NM) LIKE '%'||UPPER(#{VA_VA})||'%'
ORDER BY A.CD_VL9, A.TRNSFRM_CD

mapper.insert:
INSERT INTO NIC92B ( CD             -- 코드
                    ,CNTNT          -- 내용
                    ,CD_NM          -- 코드명
                    ,USE_F          -- 사용여부
                    ,CD_RNK_SQ      -- 코드순위일련번호
                    ,GRP_CD         -- 그룹코드
                    ,HNDL_DY_TM     -- 처리일시
                    ,HNDL_P_ENO     -- 처리자사번
                    )
     VALUES ( #{CD}
             ,#{CNTNT}
             ,#{CD_NM}
             ,#{USE_F}
             ,#{CD_RNK_SQ}
             ,#{GRP_CD}
             ,SYSDATE
             ,#{HNDL_P_ENO}
            )

INSERT INTO NIC91B ( CD             -- 코드
                    ,CD_NM          -- 코드명
                    ,CD_LNGTH       -- 코드길이
                    ,CCD            -- 구분코드
                    ,STND_CD_NM     -- 표준코드명
                    ,TBL_NM         -- 테이블명
                    ,MDFY_F         -- 수정여부
                    ,CD_EXPL        -- 코드설명
                    ,HNDL_DY_TM     -- 처리일시
                    ,HNDL_P_ENO     -- 처리자사번  aml
                   )
     VALUES ( #{CD}
             ,#{CD_NM}
             ,#{CD_LNGTH}
             ,#{CCD}
             ,#{STND_CD_NM}
             ,#{TBL_NM}
             ,#{MDFY_F}
             ,#{CD_EXPL}
             ,SYSDATE
             ,#{HNDL_P_ENO}
            )

