                    ,CD_VL9
                    ,TRNSFRM_CD
                    ,CD_NM
                    ,CD_VL_NM
                    ,TRNSFRM_CD_EXPL
                    ,HNDL_DY_TM
                    ,HNDL_P_ENO )
