mapper.select:
SELECT B.RS15_1 AS CODE, B.RS15_2 AS NAME
  FROM BRS150TB B
 WHERE B.RS11_1 =#{CODE}

SELECT '' AS SELECTED ,ROWNUM AS SEQ ,X.* FROM ( SELECT /*+USE_NL(A, P)*/ A.MNG_SNO ,A.WC_LIST_CCD ,( SELECT D.CD_NM FROM NIC92B D WHERE D.CD = 'A003' AND D.CNTNT = A.WC_LIST_CCD) AS WC_LIST_CCD_NM ,A.NTV_FGNR_CCD ,A.RNM_CNFR_CCD ,A.RNMCNO ,A.CS_NM ,TRIM(A.NTN_CD) AS NTN_CD ,A.NTN_NM ,A.ADDR ,A.PSPT_NO ,A.HNGL_NM ,TO_CHAR(A.HNDL_DY_TM, 'YYYY-MM-DD HH24:MI:SS') AS HNDL_DY_TM ,A.HNDL_P_ENO ,'' AS COUNT ,( SELECT E.CD_NM FROM NIC92B E WHERE E.CD='M006' AND E.CNTNT = A.INDV_CORP_CCD) AS INDV_CORP_CCD_NM ,A.INDV_CORP_CCD ,A.WL_BIRTHDAY ,A.ORG_NM ,CASE WHEN A.WL_REG_DT IS NOT NULL THEN SUBSTR(A.WL_REG_DT,0,4) || '-' || SUBSTR(A.WL_REG_DT,5,2) || '-' || SUBSTR(A.WL_REG_DT,7,2) ELSE A.WL_REG_DT END AS WL_REG_DT ,CASE WHEN A.WL_DEL_DT IS NOT NULL THEN SUBSTR(A.WL_DEL_DT,0,4) || '-' || SUBSTR(A.WL_DEL_DT,5,2) || '-' || SUBSTR(A.WL_DEL_DT,7,2) ELSE A.WL_DEL_DT END AS WL_DEL_DT ,A.NORM_YN ,A.APPL_YN ,A.LST_APPL_ID ,CASE WHEN A.APPL_DT IS NOT NULL THEN SUBSTR(A.APPL_DT,0,4) || '-' || SUBSTR(A.APPL_DT,5,2) || '-' || SUBSTR(A.APPL_DT,7,2) ELSE A.APPL_DT END AS APPL_DT ,P.REG_DT AS APP_DT -- 결제일자 ,CASE WHEN P.SN_CCD IS NULL THEN '미결재' ELSE (SELECT F.CD_NM FROM NIC92B F WHERE F.CD = 'A038' AND F.CNTNT = P.SN_CCD ) -- A038 결재상태코드 END AS APP_ST -- 결제상태 ,P.GYLJ_ROLE_NM AS APP_NM -- 결재자 ,P.APPR_ROLE_NM -- 결제한사람 ,P.TARGET_ROLE_NM -- 결제할사람 ,P.SN_CCD ,A.APP_NO AS APP_NO -- 결재번호 ,P.SNO ,P.NUM_SQ ,'WLL' AS GYLJ_LINE_G_C ,P.WLR_SQ FROM NIC19B A ,( SELECT M.SNO ,M.APP_DT ,M.WLR_SQ ,M.REG_DT ,M.SN_CCD ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.APPR_ROLE_ID) AS APPR_ROLE_NM -- 결제한사람 ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.TARGET_ROLE_ID) AS TARGET_ROLE_NM -- 결제할사람 ,S.GYLJ_ROLE_ID -- 결재한 사람ID ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = S.GYLJ_ROLE_ID) AS GYLJ_ROLE_NM ,M.NUM_SQ ,M.GYLJ_LINE_G_C ,M.APP_NO FROM AML_APPR M ,C_GYLJ_D S WHERE S.GYLJ_LINE_G_C = 'WLL' AND S.GYLJ_LINE_G_C = M.GYLJ_LINE_G_C AND S.SNO = M.SNO AND (M.APP_NO, M.NUM_SQ) IN (SELECT /*+ INDEX(T PK_AML_APPR)*/ T.APP_NO, MAX(T.NUM_SQ) FROM AML_APPR T WHERE T.APP_NO = M.APP_NO AND T.GYLJ_LINE_G_C = M.GYLJ_LINE_G_C GROUP BY T.APP_NO ) ) P WHERE A.APP_NO = P.APP_NO(+) AND A.APP_NO = P.APP_NO(+) AND A.WC_LIST_CCD LIKE #{WC_LIST_CCD}||'%' AND UPPER(A.CS_NM) LIKE '%'||UPPER(#{CS_NM})||'%'
AND (A.WL_REG_DT BETWEEN '00000000' AND '99999999' OR A.WL_DEL_DT BETWEEN '00000000' AND '99999999' )
AND A.WL_REG_DT BETWEEN #{WL_REG_DT_SD} AND #{WL_REG_DT_ED}
AND A.WL_DEL_DT BETWEEN #{WL_REG_DT_SD} AND #{WL_REG_DT_ED}
AND A.WL_REG_DT BETWEEN '00000000' AND '99999999'
AND A.WL_DEL_DT BETWEEN '00000000' AND '99999999'
AND ( A.WL_REG_DT BETWEEN #{WL_REG_DT_SD} AND #{WL_REG_DT_ED} OR A.WL_DEL_DT BETWEEN #{WL_REG_DT_SD} AND #{WL_REG_DT_ED} )
AND A.NORM_YN = #{NORM_YN}
AND A.APPL_YN = #{APPL_YN}
AND P.SN_CCD = #{SN_CCD}
AND P.SN_CCD = #{SN_CCD}
AND P.SN_CCD = #{SN_CCD}
AND A.APP_NO IS NULL
ORDER BY A.WL_REG_DT DESC, A.WC_LIST_CCD, A.NTV_FGNR_CCD, A.NTN_CD ) X

SELECT COUNT(A.AML_CUST_ID) AS TOTALCOUNT FROM NIC01B A, NIC03B C WHERE A.AML_CUST_ID = C.AML_CUST_ID(+) AND A.CS_ST_CD ='Y' --고객상태 AND A.INDV_CORP_CCD = #{INDV_CORP_CCD}
AND A.CS_NM LIKE '%'|| #{CS_NM} || '%'
AND A.ENG_CS_NM LIKE '%'|| #{CS_NM} ||'%'

SELECT A.RA_ID -- 시뮬레이션ID ,A.SMUL_NM -- 시뮬레이션명 ,A.SMUL_CNTNT -- 시뮬레이션내용 ,A.RA_MDL_VER_CD -- 위험평가모델버전코드_A043 ,NVL((SELECT D.CD_NM FROM NIC92B D WHERE D.CD = 'A043' AND D.CNTNT = A.RA_MDL_VER_CD), '') AS RA_MDL_VER_NM -- 위험평가모델버전명 ,A.SMUL_OBJ_CD -- 시뮬레이션목적코드_A044 ,NVL((SELECT E.CD_NM FROM NIC92B E WHERE E.CD = 'A044' AND E.CNTNT = A.SMUL_OBJ_CD), '') AS SMUL_OBJ_NM -- 시뮬레이션목적명 ,A.CS_TYP_CD -- 고객유형코드 ,NVL((SELECT F.CD_NM FROM NIC92B F WHERE F.CD = 'M012' AND F.CNTNT = A.CS_TYP_CD), '전체') AS CS_TYP_NM -- 고객유형명 ,A.RA_GBN_CD -- 위험평가구분코드_A041 ,(SELECT G.CD_NM FROM NIC92B G WHERE G.CD = 'A041' AND G.CNTNT = A.RA_GBN_CD ) AS RA_GBN_NM -- 위험평가구분명 ,A.WORK_GBN_CD -- 작업구분코드_A042 ,(SELECT H.CD_NM FROM NIC92B H WHERE H.CD = 'A042' AND H.CNTNT = A.WORK_GBN_CD) AS WORK_GBN_NM -- 작업구분명 ,CASE WHEN A.WORK_TRGT_START_DT IS NOT NULL THEN TO_CHAR(TO_DATE(A.WORK_TRGT_START_DT, 'YYYY-MM-DD'), 'YYYY-MM-DD')||' ~ '||TO_CHAR(TO_DATE(A.WORK_TRGT_END_DT, 'YYYY-MM-DD'), 'YYYY-MM-DD') ELSE '전체' END AS WORK_TRGT_DT -- 고객등록일자 ,TO_CHAR(TO_DATE(A.WORK_TRGT_START_DT, 'YYYY-MM-DD'), 'YYYY-MM-DD') AS WORK_TRGT_START_DT -- 작업대상시작일자 ,TO_CHAR(TO_DATE(A.WORK_TRGT_END_DT, 'YYYY-MM-DD'), 'YYYY-MM-DD') AS WORK_TRGT_END_DT -- 작업대상종료일자 ,TO_CHAR(TO_DATE(A.WORK_START_DTTM , 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS WORK_START_DTTM -- 배치시작일시 ,TO_CHAR(TO_DATE(A.WORK_END_DTTM , 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS WORK_END_DTTM -- 배치종료일시 ,CASE WHEN A.WORK_START_DTTM IS NOT NULL AND A.WORK_END_DTTM IS NOT NULL THEN EXTRACT(HOUR FROM (TO_TIMESTAMP(A.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(A.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '시간 ' || EXTRACT(MINUTE FROM (TO_TIMESTAMP(A.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(A.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '분 ' || EXTRACT(SECOND FROM (TO_TIMESTAMP(A.WORK_END_DTTM, 'YYYYMMDDHH24MISS') - TO_TIMESTAMP(A.WORK_START_DTTM, 'YYYYMMDDHH24MISS'))) || '초' ELSE '' END AS TIME_DIFF ,A.WORK_ST_CD -- 작업상태코드_A039 ,(SELECT I.CD_NM FROM NIC92B I WHERE I.CD = 'A039' AND I.CNTNT = A.WORK_ST_CD) AS WORK_ST_NM -- 작업상태 ,A.WRKR_ID -- 배치실행자ID ,(SELECT J.USER_NM FROM C_USER J WHERE J.USER_ID = A.WRKR_ID) AS WRKR_NM ,A.APP_NO -- 결재번호 ,TO_CHAR(TO_DATE(A.APPL_DT, 'YYYY-MM-DD'), 'YYYY-MM-DD') AS APPL_DT -- 대상시작일자 ,A.REG_ID -- 등록자ID ,(SELECT K.USER_NM FROM C_USER K WHERE K.USER_ID = A.REG_ID) AS REG_NM ,TO_CHAR(TO_DATE(A.REG_DT, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS REG_DT ,A.UPD_ID -- 수정자ID ,(SELECT L.USER_NM FROM C_USER L WHERE L.USER_ID = A.UPD_ID) AS UPD_NM ,TO_CHAR(TO_DATE(A.UPD_DT, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS UPD_DT ,P.SN_CCD ,P.APP_NO ,SUBSTR(P.REG_DT,1,4) ||'-'|| SUBSTR(P.REG_DT,5,2)||'-'||SUBSTR(P.REG_DT,7,2) AS APP_DT ,CASE WHEN P.SN_CCD IS NULL THEN '미결재' ELSE (SELECT N.CD_NM FROM NIC92B N WHERE N.CD = 'A038' AND N.CNTNT = P.SN_CCD ) -- A038 결재상태코드 END AS APP_ST ,P.GYLJ_ROLE_NM AS APP_NM ,P.APPR_ROLE_NM ,P.TARGET_ROLE_NM ,P.SNO ,P.NUM_SQ ,'RA4' AS GYLJ_LINE_G_C ,P.WLR_SQ FROM RA_WORK_INFO A LEFT OUTER JOIN ( SELECT M.SNO ,M.APP_DT ,M.WLR_SQ ,M.REG_DT ,M.SN_CCD ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.APPR_ROLE_ID) AS APPR_ROLE_NM -- 결제한사람 ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.TARGET_ROLE_ID) AS TARGET_ROLE_NM -- 결제할사람 ,S.GYLJ_ROLE_ID -- 결재한 사람ID ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = S.GYLJ_ROLE_ID) AS GYLJ_ROLE_NM ,M.NUM_SQ ,M.GYLJ_LINE_G_C ,M.APP_NO FROM AML_APPR M, C_GYLJ_D S WHERE S.GYLJ_LINE_G_C = 'RA4' AND S.GYLJ_LINE_G_C = M.GYLJ_LINE_G_C AND S.SNO = M.SNO AND (M.APP_NO, M.NUM_SQ) IN ( SELECT /*+ INDEX(T PK_AML_APPR)*/ T.APP_NO, MAX(T.NUM_SQ) FROM AML_APPR T WHERE T.APP_NO = M.APP_NO AND T.GYLJ_LINE_G_C = 'RA4' GROUP BY T.APP_NO ) ) P ON (A.APP_NO = P.APP_NO) WHERE A.RA_GBN_CD = 'S' -- 시뮬레이션
AND A.RA_MDL_VER_CD = #{RA_MDL_VER_CD}
AND A.SMUL_OBJ_CD = #{SMUL_OBJ_CD}
AND A.CS_TYP_CD = #{CS_TYP_CD}
AND A.WORK_ST_CD = #{WORK_ST_CD}
AND A.REG_DT BETWEEN #{REG_DT_SD}||'000000' AND #{REG_DT_ED}||'235959'
AND P.SN_CCD = #{SN_CCD}
AND P.SN_CCD = #{SN_CCD}
AND P.SN_CCD = #{SN_CCD}
AND A.APP_NO IS NULL
ORDER BY A.RA_ID DESC

mapper.update:
UPDATE RA_WORK_INFO A
   SET A.APP_NO = #{APP_NO}
 WHERE A.RA_ID = #{RA_ID}

UPDATE RA_WORK_INFO A
   SET A.APPL_DT   = TO_CHAR(SYSDATE,'YYYYMMDD')
      ,A.UPD_ID    = #{HNDL_P_ENO}
      ,A.UPD_DT    = TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
 WHERE A.RA_ID = #{RA_ID}

mapper.insert:
INSERT INTO RA_WORK_INFO ( RA_ID
                          ,SMUL_NM
                          ,RA_MDL_VER_CD
                          ,SMUL_OBJ_CD
                          ,CS_TYP_CD
                          ,RA_GBN_CD
                          ,WORK_TRGT_START_DT
                          ,WORK_TRGT_END_DT
                          ,REG_ID
                          ,REG_DT )
                  VALUES ( RA_WORK_INFO_SEQ.NEXTVAL
                          ,#{SMUL_NM}
                          ,#{RA_MDL_VER_CD}
                          ,#{SMUL_OBJ_CD}
                          ,#{CS_TYP_CD, jdbcType=VARCHAR}
                          ,#{RA_GBN_CD}
                          ,#{WORK_TRGT_START_DT, jdbcType=VARCHAR}
                          ,#{WORK_TRGT_END_DT, jdbcType=VARCHAR}
                          ,#{REG_ID, jdbcType=VARCHAR}
                          ,TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
                         )

mapper.select:
SELECT X.CS_TYP_CD ,(SELECT E.CD_NM FROM NIC92B E WHERE E.CD = 'M012' AND E.CNTNT = X.CS_TYP_CD) AS CS_TYP_NM ,D.RA_ITEM_CD ,D.RA_ITEM_NM ,D.RA_MDL_GBN_CD ,(SELECT F.CD_NM FROM NIC92B F WHERE F.CD = 'A040' AND F.CNTNT = D.RA_MDL_GBN_CD) AS RA_MDL_GBN_NM ,X.NEW_OLD_GBN_CD ,TO_CHAR(X.RA_ITEM_WGHT, '0.00') AS RA_ITEM_WGHT ,X.B_NEW_OLD_GBN_CD ,TO_CHAR(X.B_RA_ITEM_WGHT, '0.00') AS B_RA_ITEM_WGHT FROM ( SELECT A.CS_TYP_CD ,A.RA_ITEM_CD ,B.NEW_OLD_GBN_CD ,B.RA_ITEM_WGHT ,C.NEW_OLD_GBN_CD AS B_NEW_OLD_GBN_CD ,C.RA_ITEM_WGHT AS B_RA_ITEM_WGHT FROM ( SELECT DISTINCT G.CS_TYP_CD, G.RA_ITEM_CD FROM RA_ITEM_WGHT G ) A LEFT JOIN ( SELECT H.CS_TYP_CD ,H.NEW_OLD_GBN_CD ,H.RA_ITEM_CD ,H.RA_ITEM_WGHT ,H.REG_ID ,H.REG_DT ,H.UPD_ID ,H.UPD_DT FROM RA_ITEM_WGHT H WHERE H.NEW_OLD_GBN_CD = 'A' ) B ON A.RA_ITEM_CD = B.RA_ITEM_CD AND A.CS_TYP_CD = B.CS_TYP_CD LEFT JOIN ( SELECT I.CS_TYP_CD, I.NEW_OLD_GBN_CD, I.RA_ITEM_CD, I.RA_ITEM_WGHT, I.REG_ID, I.REG_DT, I.UPD_ID, I.UPD_DT FROM RA_ITEM_WGHT I WHERE I.NEW_OLD_GBN_CD = 'B' ) C ON A.RA_ITEM_CD = C.RA_ITEM_CD AND A.CS_TYP_CD = C.CS_TYP_CD ) X INNER JOIN RA_ITEM D ON X.RA_ITEM_CD = D.RA_ITEM_CD AND D.USE_YN = 'Y' WHERE 1=1
AND X.CS_TYP_CD = #{CS_TYP_CD}
ORDER BY X.CS_TYP_CD, X.NEW_OLD_GBN_CD, X.RA_ITEM_CD

mapper.update:
MERGE INTO RA_SMUL_WGHT T
USING DUAL
   ON ( T.RA_ID = #{RA_ID}
        AND T.CS_TYP_CD = #{CS_TYP_CD}
        AND T.NEW_OLD_GBN_CD = #{NEW_OLD_GBN_CD}
        AND T.RA_ITEM_CD = #{RA_ITEM_CD} )
 WHEN MATCHED THEN
            UPDATE SET T.RA_ITEM_WGHT = #{RA_ITEM_WGHT}
                      ,T.UPD_ID = #{USER_ID}
                      ,T.UPD_DT = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
 WHEN NOT MATCHED THEN
                INSERT ( T.RA_ID
                        ,T.CS_TYP_CD
                        ,T.NEW_OLD_GBN_CD
                        ,T.RA_ITEM_CD
                        ,T.RA_ITEM_WGHT
                        ,T.REG_ID
                        ,T.REG_DT
                       )
                VALUES ( #{RA_ID}
                        ,#{CS_TYP_CD}
                        ,#{NEW_OLD_GBN_CD}
                        ,#{RA_ITEM_CD}
                        ,#{RA_ITEM_WGHT}
                        ,#{USER_ID, jdbcType=VARCHAR}
                        ,TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
                       )

mapper.select:
SELECT B.* ,A.SMUL_NM ,A.SMUL_CNTNT ,A.CS_TYP_CD ,A.RA_GBN_CD ,A.WORK_GBN_CD ,A.WORK_TRGT_START_DT ,A.WORK_TRGT_END_DT ,A.WORK_START_DTTM ,A.WORK_END_DTTM ,A.WORK_ST_CD ,A.WRKR_ID ,A.APP_NO ,A.APPL_DT ,A.REG_ID ,A.REG_DT ,A.UPD_ID ,A.UPD_DT ,P.SN_CCD ,SUBSTR(P.REG_DT,1,4) ||'-'|| SUBSTR(P.REG_DT,5,2)||'-'||SUBSTR(P.REG_DT,7,2) AS APP_DT ,CASE WHEN P.SN_CCD IS NULL THEN '미결재' ELSE (SELECT D.CD_NM FROM NIC92B D WHERE D.CD = 'A038' AND D.CNTNT = P.SN_CCD ) -- A038 결재상태코드 END AS APP_ST ,P.GYLJ_ROLE_NM AS APP_NM ,P.APPR_ROLE_NM ,P.TARGET_ROLE_NM ,P.SNO ,P.NUM_SQ ,'RA4' AS GYLJ_LINE_G_C ,P.WLR_SQ FROM RA_WORK_INFO A INNER JOIN ( SELECT X.RA_ID -- ,NVL((SELECT E.CD_NM FROM NIC92B E WHERE E.CD = 'M012' AND E.CNTNT = X.CS_TYP_CD), '전체') AS GUBN ,SUM(X.CS_CNT) AS TOT_CNT ,ROUND((SUM(X.CS_CNT) / (SELECT SUM(F.CS_CNT) FROM RA_SMUL_RSLT F WHERE F.RA_ID = X.RA_ID ) ) * 100, 1) AS TOT_RAT ,SUM(CASE WHEN X.LST_RA_GRD_CD = 'H' THEN X.CS_CNT ELSE 0 END) AS H_CNT ,ROUND((SUM(CASE WHEN X.LST_RA_GRD_CD = 'H' THEN X.CS_CNT ELSE 0 END) / (SELECT SUM(I.CS_CNT) FROM RA_SMUL_RSLT I WHERE I.RA_ID = X.RA_ID ) ) * 100, 1) AS H_RAT ,SUM(CASE WHEN X.LST_RA_GRD_CD = 'M' THEN X.CS_CNT ELSE 0 END) AS M_CNT ,ROUND((SUM(CASE WHEN X.LST_RA_GRD_CD = 'M' THEN X.CS_CNT ELSE 0 END) / (SELECT SUM(J.CS_CNT) FROM RA_SMUL_RSLT J WHERE J.RA_ID = X.RA_ID ) ) * 100, 1) AS M_RAT ,SUM(CASE WHEN X.LST_RA_GRD_CD = 'L' THEN X.CS_CNT ELSE 0 END) AS L_CNT ,ROUND((SUM(CASE WHEN X.LST_RA_GRD_CD = 'L' THEN X.CS_CNT ELSE 0 END) / (SELECT SUM(K.CS_CNT) FROM RA_SMUL_RSLT K WHERE K.RA_ID = X.RA_ID ) ) * 100, 1) AS L_RAT FROM RA_SMUL_RSLT X WHERE X.RA_ID IN
#{RA_LIST, jdbcType=VARCHAR}
GROUP BY X.RA_ID ) B ON A.RA_ID = B.RA_ID LEFT OUTER JOIN ( SELECT M.SNO ,M.APP_DT ,M.WLR_SQ ,M.REG_DT ,M.SN_CCD ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.APPR_ROLE_ID) AS APPR_ROLE_NM -- 결제한사람 ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.TARGET_ROLE_ID) AS TARGET_ROLE_NM -- 결제할사람 ,S.GYLJ_ROLE_ID -- 결재한 사람ID ,(SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = S.GYLJ_ROLE_ID) AS GYLJ_ROLE_NM ,M.NUM_SQ ,M.GYLJ_LINE_G_C ,M.APP_NO FROM AML_APPR M, C_GYLJ_D S WHERE S.GYLJ_LINE_G_C = 'RA4' AND S.GYLJ_LINE_G_C = M.GYLJ_LINE_G_C AND S.SNO = M.SNO AND (M.APP_NO, M.NUM_SQ) IN ( SELECT /*+ INDEX(T PK_AML_APPR)*/ T.APP_NO, MAX(T.NUM_SQ) FROM AML_APPR T WHERE T.APP_NO = M.APP_NO AND T.GYLJ_LINE_G_C = 'RA4' GROUP BY T.APP_NO ) ) P ON (A.APP_NO = P.APP_NO) WHERE A.RA_GBN_CD = 'S' -- 시뮬레이션 ORDER BY A.RA_ID DESC

SELECT A.RA_ID ,A.AML_CUST_ID ,A.CS_TYP_CD ,A.NEW_OLD_GBN_CD ,A.RA_GRD_SCR -- 등급점수 ,A.RA_GRD_CD -- 위험등급 ,A.LST_RA_GRD_CD -- 최종등급 ,B.CS_NM FROM RA_CS_RA_RSLT A LEFT JOIN NIC01B B ON A.AML_CUST_ID = B.AML_CUST_ID WHERE 1=1 AND A.RA_ID = #{RA_ID}
AND A.AML_CUST_ID = #{AML_CUST_ID}
AND A.CS_TYP_CD = #{CS_TYP_CD} AND A.NEW_OLD_GBN_CD = #{NEW_OLD_GBN_CD}

SELECT * FROM ( SELECT COUNT(*) OVER() AS TOTALCOUNT, ROWNUM AS RN, V.* FROM ( SELECT A.RA_ID ,A.AML_CUST_ID ,A.CS_TYP_CD ,A.NEW_OLD_GBN_CD ,A.RA_GRD_SCR -- 등급점수 ,A.RA_GRD_CD -- 위험등급 ,A.LST_RA_GRD_CD -- 최종등급 ,B.CS_NM FROM RA_CS_RA_RSLT A LEFT JOIN NIC01B B ON A.AML_CUST_ID = B.AML_CUST_ID WHERE 1=1 AND A.RA_ID = #{RA_ID}
AND A.AML_CUST_ID = #{AML_CUST_ID}
AND A.CS_TYP_CD = #{CS_TYP_CD} AND A.NEW_OLD_GBN_CD = #{NEW_OLD_GBN_CD}
ORDER BY
A.AML_CUST_ID B.CS_NM DECODE(A.LST_RA_GRD_CD, 'H', 1, 'M', 2, 'L', 3) TRX_DTTM
ASCDESC
) V ) X WHERE 1=1
AND X.RN >= ( ( #{thisPage} - 1 ) * #{pageCount} + 1 ) AND X.RN <= ( #{thisPage} * #{pageCount} )

SELECT COUNT(A.AML_CUST_ID) AS TOTALCOUNT
  FROM RA_CS_RA_RSLT A
  LEFT JOIN NIC01B B
    ON A.AML_CUST_ID = B.AML_CUST_ID
 WHERE 1=1
   AND A.RA_ID = #{RA_ID}

   AND A.AML_CUST_ID = #{AML_CUST_ID}

   AND A.CS_TYP_CD = #{CS_TYP_CD}
   AND A.NEW_OLD_GBN_CD = #{NEW_OLD_GBN_CD}

SELECT COUNT(A.AML_CUST_ID) AS TOTALCOUNT FROM NIC01B_1 A LEFT JOIN NIC01B B ON A.AML_CUST_ID = B.AML_CUST_ID INNER JOIN RA_CS_RA_RSLT E ON A.AML_CUST_ID = E.AML_CUST_ID AND E.RA_ID = #{RA_ID} WHERE 1=1
AND A.CS_TYP_CD = #{CS_TYP_CD}
AND A.NEW_OLD_GBN_CD = #{NEW_OLD_GBN_CD}
AND B.CS_NM LIKE '%'|| #{CS_NM} || '%'
AND B.ENG_CS_NM LIKE '%'|| #{CS_NM} ||'%'
AND ( B.CS_NM LIKE '%'|| #{CS_NM} || '%' OR B.ENG_CS_NM LIKE '%'|| #{CS_NM} ||'%')

