SELECT CDD_FLFL_DATE , CDD_TAGT_ENTY_ID , CDD_FLFL_SQNO , MNTN_STNR_CODE , MNTN_STNR_NAME , MNTN_DTLS_CTNT , PRCE_DATE_TIME , TAGT_CLNT_NAME , CDD_CLNT_SECT_NAME , CS_NO , RGBR_CODE , RGBR_NAME , RGSN_EMPY_NO , RGSN_EMPY_NAME , PRCE_CHNL_SECT_CODE , ACTN_RSLT_SECT_CODE , ACTN_CTNT , ACTN_EMPY_NO , ACTN_EMPY_NM , ACTN_DATE_TIME , CDD_DUTY_FLFL_TAGT_YN , SA_CDD_DUTY_FLFL_TAGT_YN , CDD_RESN_CODE , MNTN_DATE FROM ( SELECT TO_CHAR(TO_DATE(C.CDD_FLFL_DATE, 'YYYYMMDD'), 'YYYY/MM/DD') AS CDD_FLFL_DATE , A.CDD_TAGT_ENTY_ID AS CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO AS CDD_FLFL_SQNO , A.MNTN_STNR_CODE AS MNTN_STNR_CODE , TRIM(B.MNTN_STNR_NAME) AS MNTN_STNR_NAME , TRIM(A.MNTN_DTLS_CTNT) AS MNTN_DTLS_CTNT , TO_CHAR(A.PRCE_DATE_TIME, 'YYYY/MM/DD HH24:MI:SS') AS PRCE_DATE_TIME , TRIM(C.TAGT_CLNT_NAME) AS TAGT_CLNT_NAME , CASE C.CDD_CLNT_SECT_CODE WHEN '1' THEN '개인' WHEN '2' THEN '영리법인' WHEN '3' THEN '비영리법인' ELSE ' ' END AS CDD_CLNT_SECT_NAME , TRIM(C.CDD_TAGT_CLNT_NO_CRYP) AS CS_NO , TRIM(C.RGBR_CODE) AS RGBR_CODE , NVL((SELECT TRIM(DTBR_NAME) FROM SID.IDO_A_UUE_SAMSUNG_DPRT WHERE DTBR_CODE = C.RGBR_CODE), C.RGBR_CODE) AS RGBR_NAME , TRIM(C.RGSN_EMPY_NO) AS RGSN_EMPY_NO , NVL((SELECT TRIM(USER_NAME) FROM SID.IDO_A_UWA_USER WHERE USER_ID = C.RGSN_EMPY_NO), C.RGSN_EMPY_NO) AS RGSN_EMPY_NAME ,'[' || C.PRCE_CHNL_SECT_CODE || '] ' || NVL((SELECT TRIM(CHNL_SECT_NAME) FROM SID.IDO_A_UWB_CHANNEL_CD WHERE CHNL_SECT_CODE = C.PRCE_CHNL_SECT_CODE), C.PRCE_CHNL_SECT_CODE) AS PRCE_CHNL_SECT_CODE ,A.ACTN_RSLT_SECT_CODE ,A.ACTN_CTNT ,TRIM(A.ACTN_EMPY_NO) AS ACTN_EMPY_NO ,NVL((SELECT TRIM(USER_NAME) FROM SID.IDO_A_UWA_USER WHERE USER_ID = A.ACTN_EMPY_NO), A.ACTN_EMPY_NO) AS ACTN_EMPY_NM ,A.ACTN_DATE_TIME ,A.CDD_DUTY_FLFL_TAGT_YN ,CASE WHEN A.CDD_DUTY_FLFL_TAGT_YN = 'Y' THEN 'Y' WHEN A.CDD_DUTY_FLFL_TAGT_YN = 'N' THEN 'N' ELSE 'T' END AS SA_CDD_DUTY_FLFL_TAGT_YN ,A.CDD_RESN_CODE ,A.MNTN_DATE FROM SSQ.L_CDD_MNTN_DTLD A -- CDD모니터링상세 , SSQ.L_CDD_MNTN_MSTR B -- CDD모니터링마스터 , SID.IDO_A_MAH_CDD_FLFL_CHAN C -- CDD수행이력 WHERE 1 = 1 AND A.CDD_TAGT_ENTY_ID = C.CDD_TAGT_ENTY_ID AND A.CDD_FLFL_SQNO = C.CDD_FLFL_SQNO AND A.MNTN_STNR_CODE = B.MNTN_STNR_CODE ) WHERE 1 = 1 AND MNTN_DATE BETWEEN #{stDate} AND #{edDate}
AND MNTN_STNR_CODE LIKE 'CDD_1%'
AND MNTN_STNR_CODE LIKE 'CDD_2%'
AND MNTN_STNR_CODE = #{MNTN_STNR_CODE, jdbcType=VARCHAR}
AND ACTN_RSLT_SECT_CODE = #{ACTN_RSLT_SECT_CODE}
AND SA_CDD_DUTY_FLFL_TAGT_YN = #{CDD_PER_DUTY_YN}
AND MNTN_STNR_CODE NOT LIKE 'CDD_3%' AND MNTN_STNR_CODE NOT IN ('CDD_214') ORDER BY MNTN_DATE, MNTN_STNR_CODE, CDD_TAGT_ENTY_ID, CDD_FLFL_SQNO

SELECT CDD_FLFL_DATE , CDD_TAGT_ENTY_ID , CDD_FLFL_SQNO , MNTN_STNR_CODE , MNTN_STNR_NAME , MNTN_DTLS_CTNT , PRCE_DATE_TIME , TAGT_CLNT_NAME , CDD_CLNT_SECT_NAME , CS_NO , RGBR_CODE , RGBR_NAME , RGSN_EMPY_NO , RGSN_EMPY_NAME , PRCE_CHNL_SECT_CODE , ACTN_RSLT_SECT_CODE , ACTN_CTNT , ACTN_EMPY_NO , ACTN_EMPY_NM , ACTN_DATE_TIME , CDD_DUTY_FLFL_TAGT_YN , SA_CDD_DUTY_FLFL_TAGT_YN , CDD_RESN_CODE , MNTN_DATE FROM ( SELECT TO_CHAR(TO_DATE(C.CDD_FLFL_DATE, 'YYYYMMDD'), 'YYYY/MM/DD') AS CDD_FLFL_DATE , A.CDD_TAGT_ENTY_ID AS CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO AS CDD_FLFL_SQNO , A.MNTN_STNR_CODE AS MNTN_STNR_CODE , TRIM(B.MNTN_STNR_NAME) AS MNTN_STNR_NAME , TRIM(A.MNTN_DTLS_CTNT) AS MNTN_DTLS_CTNT , TO_CHAR(A.PRCE_DATE_TIME, 'YYYY/MM/DD HH24:MI:SS') AS PRCE_DATE_TIME , TRIM(C.TAGT_CLNT_NAME) AS TAGT_CLNT_NAME , CASE C.CDD_CLNT_SECT_CODE WHEN '1' THEN '개인' WHEN '2' THEN '영리법인' WHEN '3' THEN '비영리법인' ELSE ' ' END AS CDD_CLNT_SECT_NAME , TRIM(C.CDD_TAGT_CLNT_NO_CRYP) AS CS_NO , TRIM(C.RGBR_CODE) AS RGBR_CODE , NVL((SELECT TRIM(DTBR_NAME) FROM SID.IDO_A_UUE_SAMSUNG_DPRT WHERE DTBR_CODE = C.RGBR_CODE), C.RGBR_CODE) AS RGBR_NAME , TRIM(C.RGSN_EMPY_NO) AS RGSN_EMPY_NO , NVL((SELECT TRIM(USER_NAME) FROM SID.IDO_A_UWA_USER WHERE USER_ID = C.RGSN_EMPY_NO), C.RGSN_EMPY_NO) AS RGSN_EMPY_NAME ,'[' || C.PRCE_CHNL_SECT_CODE || '] ' || NVL((SELECT TRIM(CHNL_SECT_NAME) FROM SID.IDO_A_UWB_CHANNEL_CD WHERE CHNL_SECT_CODE = C.PRCE_CHNL_SECT_CODE), C.PRCE_CHNL_SECT_CODE) AS PRCE_CHNL_SECT_CODE ,A.ACTN_RSLT_SECT_CODE ,A.ACTN_CTNT ,TRIM(A.ACTN_EMPY_NO) AS ACTN_EMPY_NO ,NVL((SELECT TRIM(USER_NAME) FROM SID.IDO_A_UWA_USER WHERE USER_ID = A.ACTN_EMPY_NO), A.ACTN_EMPY_NO) AS ACTN_EMPY_NM ,A.ACTN_DATE_TIME ,A.CDD_DUTY_FLFL_TAGT_YN ,CASE WHEN A.CDD_DUTY_FLFL_TAGT_YN = 'Y' THEN 'Y' WHEN A.CDD_DUTY_FLFL_TAGT_YN = 'N' THEN 'N' ELSE 'T' END AS SA_CDD_DUTY_FLFL_TAGT_YN ,A.CDD_RESN_CODE ,A.MNTN_DATE FROM SSQ.L_CDD_MNTN_DTLD A -- CDD모니터링상세 , SSQ.L_CDD_MNTN_MSTR B -- CDD모니터링마스터 , SID.IDO_A_MAH_CDD_FLFL_CHAN C -- CDD수행이력 WHERE 1 = 1 AND A.CDD_TAGT_ENTY_ID = C.CDD_TAGT_ENTY_ID AND A.CDD_FLFL_SQNO = C.CDD_FLFL_SQNO AND A.MNTN_STNR_CODE = B.MNTN_STNR_CODE AND A.MNTN_STNR_CODE LIKE 'CDD_3%' ) WHERE 1 = 1 AND MNTN_DATE BETWEEN #{stDate} AND #{edDate}
AND MNTN_STNR_CODE = #{MNTN_STNR_CODE, jdbcType=VARCHAR}
AND ACTN_RSLT_SECT_CODE = #{ACTN_RSLT_SECT_CODE}
AND SA_CDD_DUTY_FLFL_TAGT_YN = #{CDD_PER_DUTY_YN}
ORDER BY MNTN_DATE, MNTN_STNR_CODE, CDD_TAGT_ENTY_ID, CDD_FLFL_SQNO

SELECT NVL(PROFILE, ' ') PROFILE
FROM WAL_BAS
WHERE DJ_UID = #{DJ_UID}

SELECT DISTINCT(INDV_CORP_CCD) INDV_CORP_CCD
FROM WAL_NM
WHERE DJ_UID = #{DJ_UID}

SELECT A.RISK_CATG1_C -- 위험요소대분류 , (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = A.RISK_CATG1_C AND GRP_C = 'S001') AS RISK_CATG1_C_NM , A.RISK_CATG2_C -- 위험요소중분류 , (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = A.RISK_CATG2_C AND GRP_C = 'S002') AS RISK_CATG2_C_NM , A.RISK_ELMT_C -- 위험요소소분류 , A.RISK_ELMT_NM -- 위험요소명 , A.RISK_VAL_ITEM -- 평가항목 , (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = A.RISK_VAL_ITEM AND GRP_C = 'R342' ) AS RISK_VAL_ITEM_NM , A.RISK_INDI -- 개인여부 , CASE WHEN A.RISK_INDI = 'Y' THEN '●' ELSE '' END AS RISK_INDI_NM , A.RISK_CORP -- 법인여부 , CASE WHEN A.RISK_CORP = 'Y' THEN '●' ELSE '' END AS RISK_CORP_NM , A.RISK_SCR -- 위험점수 , A.RISK_HRSK_YN -- 당연EDD여부 , A.RISK_APPL_MODEL_I -- I모델적용여부 , CASE WHEN A.RISK_APPL_MODEL_I = 'Y' THEN '●' ELSE '' END AS RISK_APPL_MODEL_I_NM , A.RISK_APPL_MODEL_B -- B모델적용여부 , CASE WHEN A.RISK_APPL_MODEL_B = 'Y' THEN '●' ELSE '' END AS RISK_APPL_MODEL_B_NM , A.RISK_RSN_DESC -- 위험사유 , A.RISK_RMRK -- 비고 , A.RISK_SN_CCD AS RA_SN_CCD -- 결재상태 , GET_CODE_NAME('A038', A.RISK_SN_CCD) AS RA_SN_CCD_NM , A.APP_NO AS RA_APP_NO -- 결재번호 , A.APP_DT AS RA_APP_DT -- 결재일자 , A.LST_APP_NO AS RA_LST_APP_NO -- 최종결재번호 , A.LST_APP_DT AS RA_LST_APP_DT -- 최종결재일자 , A.RISK_APPL_YN -- 적용여부 , A.RA_REF_SN_CCD -- 반려여부 , A.FACT_SEQ AS RA_SEQ , B.APP_NO -- 결재번호 , B.SN_CCD -- 결재상태코드 , GET_CODE_NAME('A038', B.SN_CCD) AS SN_CCD_NM -- 결재상태코드명 , B.GYLJ_LINE_G_C , B.APP_DT , B.SNO , B.PRV_APP_NO , B.RSN_CNTNT , B.APPR_ROLE_ID , B.TARGET_ROLE_ID , (SELECT DISPLAY_NM FROM C_CD_NM WHERE LANG_CD = 'ko-KR' AND CD_ID = #{RANKID}) AS POSITION_NAME FROM RA_RISK_FACTOR_REQ A , AML_APPR B WHERE A.APP_NO = B.APP_NO(+)
AND RISK_CATG1_C = #{RA_ITEM_CD}
AND RISK_VAL_ITEM = #{MNTN_STNR_CODE}
AND RISK_HRSK_YN = #{RISK_HRSK_YN}
AND RISK_HRSK_YN = #{RISK_HRSK_YN}
AND RISK_HRSK_YN = #{RISK_HRSK_YN}
AND RISK_HRSK_YN IN ('Y','H')
AND RISK_INDI IN ('Y')
AND RISK_CORP IN ('Y')
AND RISK_APPL_MODEL_I IN ('Y')
AND RISK_APPL_MODEL_B IN ('Y')
ORDER BY RISK_CATG1_C, RISK_CATG2_C

