SELECT ROWNUM AS SEQ , RA_ITEM_CD -- 위험평가항목코드 , RA_ITEM_CODE -- 위험평가항목코드(상세코드) , RA_ITEM_NTN_CD -- 위험평가항목값(상세코드) , RA_ITEM_NM -- 위험평가항목명(내용) , ABS_HRSK_YN -- 당연고위험여부 , RA_ITEM_SCR -- 표준점수 , RECAL_ABS_HRSK_YN , RECAL_RA_ITEM_SCR , RECAL_RA_SCR , RECAL_RA_SCR_CODE , CASE WHEN ABS_HRSK_YN != RECAL_ABS_HRSK_YN THEN 'CHR' ELSE 'CHN' END AS CHANGE_ABS_HRSK_YN , CASE WHEN RA_ITEM_SCR != RECAL_RA_ITEM_SCR THEN 'CHR' ELSE 'CHN' END AS CHANGE_RA_ITEM_SCR , FATF_BLACK_LIST_YN -- FATF Black list 여부 , FATF_GREY_LIST_YN -- FATF Grey list 여부 , FINCEN_LIST_YN -- FinCEN조치국가 여부 , UN_SANTIONS_YN -- UN제재국가 여부 , OFAC_SANTIONS_YN -- OFAC제재국가 여부 , OECD_YN -- OECD국가 여부 , TICPI_CPI_IDX -- TI부패인식지수 평균 , TICPI_CPI_IDX_SCR -- TI부패인식지수 표준점수 , INCRS_PROD_YN -- INCRS 마약생산유통국가 여부 , INCRS_CHEM_YN -- INCRS 마약밀매수익금거래국가 여부 , EU_SANTIONS_YN -- EU제재국가 여부 , EU_HRT_YN -- EU고위험 제3국 여부 , BASEL_RIK_IDX -- Basel 자금세탁위험 평균 , BASEL_RIK_IDX_SCR -- Basel 자금세탁위험 표준점수 , RA_APP_NO , RA_APP_DT , RA_LST_APP_NO , RA_LST_APP_DT , RA_SN_CCD , RA_SN_CCD_NM , RA_REF_SN_CCD , RA_SEQ , UPLOAD_GUBUN , SN_CCD , SN_CCD_NM , GYLJ_LINE_G_C , APP_DT , SNO , PRV_APP_NO , RSN_CNTNT , POSITION_NAME FROM ( SELECT A.RA_ITEM_CD -- 위험평가항목코드 , A.RA_ITEM_CODE -- 위험평가항목코드(상세코드) , A.RA_ITEM_NTN_CD -- 위험평가항목값(상세코드) , A.RA_ITEM_NM -- 위험평가항목명(내용) , CASE WHEN TRIM(A.ABS_HRSK_YN) IS NULL THEN 'N' ELSE TRIM(A.ABS_HRSK_YN) END AS ABS_HRSK_YN -- 당연고위험여부 , A.RA_ITEM_SCR -- 표준점수 , CASE WHEN A.NTN_SN_CCD IN ('N','S','R') THEN CASE WHEN TRIM(C.ABS_HRSK_YN) IS NULL THEN 'N' ELSE TRIM(C.ABS_HRSK_YN) END ELSE '' END AS RECAL_ABS_HRSK_YN , CASE WHEN A.NTN_SN_CCD IN ('N','S','R') THEN C.RA_ITEM_SCR ELSE NULL END AS RECAL_RA_ITEM_SCR , CASE WHEN A.NTN_SN_CCD IN ('N','S','R') THEN C.RA_ITEM_SCR - A.RA_ITEM_SCR ELSE NULL END AS RECAL_RA_SCR , CASE WHEN A.NTN_SN_CCD IN ('N','S','R') AND (C.RA_ITEM_SCR - A.RA_ITEM_SCR) > 0 THEN 'U' WHEN A.NTN_SN_CCD IN ('N','S','R') AND (C.RA_ITEM_SCR - A.RA_ITEM_SCR) < 0 THEN 'D' WHEN A.NTN_SN_CCD IN ('N','S','R') AND (C.RA_ITEM_SCR - A.RA_ITEM_SCR) = 0 THEN 'M' ELSE '' END RECAL_RA_SCR_CODE , CASE WHEN TRIM(A.FATF_BLACK_LIST_YN) IS NULL THEN 'N' ELSE TRIM(A.FATF_BLACK_LIST_YN) END AS FATF_BLACK_LIST_YN -- FATF Black list 여부 , CASE WHEN TRIM(A.FATF_GREY_LIST_YN) IS NULL THEN 'N' ELSE TRIM(A.FATF_GREY_LIST_YN) END AS FATF_GREY_LIST_YN -- FATF Grey list 여부 , CASE WHEN TRIM(A.FINCEN_LIST_YN) IS NULL THEN 'N' ELSE TRIM(A.FINCEN_LIST_YN) END AS FINCEN_LIST_YN -- FinCEN조치국가 여부 , CASE WHEN TRIM(A.UN_SANTIONS_YN) IS NULL THEN 'N' ELSE TRIM(A.UN_SANTIONS_YN) END AS UN_SANTIONS_YN -- UN제재국가 여부 , CASE WHEN TRIM(A.OFAC_SANTIONS_YN) IS NULL THEN 'N' ELSE TRIM(A.OFAC_SANTIONS_YN) END AS OFAC_SANTIONS_YN -- OFAC제재국가 여부 , CASE WHEN TRIM(A.OECD_YN) IS NULL THEN 'N' ELSE TRIM(A.OECD_YN) END AS OECD_YN -- OECD국가 여부 , A.TICPI_CPI_IDX -- TI부패인식지수 평균 , A.TICPI_CPI_IDX_SCR -- TI부패인식지수 표준점수 , CASE WHEN TRIM(A.INCRS_PROD_YN) IS NULL THEN 'N' ELSE TRIM(A.INCRS_PROD_YN) END AS INCRS_PROD_YN -- INCRS 마약생산유통국가 여부 , CASE WHEN TRIM(A.INCRS_CHEM_YN) IS NULL THEN 'N' ELSE TRIM(A.INCRS_CHEM_YN) END AS INCRS_CHEM_YN -- INCRS 마약밀매수익금거래국가 여부 , CASE WHEN TRIM(A.EU_SANTIONS_YN) IS NULL THEN 'N' ELSE TRIM(A.EU_SANTIONS_YN) END AS EU_SANTIONS_YN -- EU제재국가 여부 , CASE WHEN TRIM(A.EU_HRT_YN) IS NULL THEN 'N' ELSE TRIM(A.EU_HRT_YN) END AS EU_HRT_YN -- EU고위험 제3국 여부 , A.BASEL_RIK_IDX -- Basel 자금세탁위험 평균 , A.BASEL_RIK_IDX_SCR -- Basel 자금세탁위험 표준점수 , A.APP_NO AS RA_APP_NO , A.APP_DT AS RA_APP_DT , A.LST_APP_NO AS RA_LST_APP_NO , A.LST_APP_DT AS RA_LST_APP_DT , A.NTN_SN_CCD AS RA_SN_CCD , GET_CODE_NAME('A038', A.NTN_SN_CCD) AS RA_SN_CCD_NM , A.RA_REF_SN_CCD , A.NTN_SEQ AS RA_SEQ , A.GYLJ_LINE_G_C AS UPLOAD_GUBUN , B.SN_CCD -- 결재상태코드 , GET_CODE_NAME('A038', B.SN_CCD) AS SN_CCD_NM -- 결재상태코드명 , B.GYLJ_LINE_G_C , B.APP_DT , B.SNO , B.PRV_APP_NO , B.RSN_CNTNT , (SELECT DISPLAY_NM FROM C_CD_NM WHERE LANG_CD = 'ko-KR' AND CD_ID = #{RANKID}) AS POSITION_NAME FROM RA_ITEM_NTN_SCR_REQ A , AML_APPR B , RA_ITEM_NTN_SCR_RE_CAL C WHERE A.APP_NO = B.APP_NO(+) AND A.RA_ITEM_CD = C.RA_ITEM_CD AND A.RA_ITEM_CODE = C.RA_ITEM_CODE ORDER BY RA_ITEM_CODE ) WHERE 1=1
AND UPPER(RA_ITEM_NM) LIKE '%'||UPPER(#{RA_ITEM_NM})||'%'
AND RA_ITEM_CODE = #{RA_ITEM_CODE}
AND ABS_HRSK_YN = #{ABS_HRSK_YN}
AND ABS_HRSK_YN = #{ABS_HRSK_YN}
AND ABS_HRSK_YN = #{ABS_HRSK_YN}
AND ABS_HRSK_YN IN ('Y','H')
AND FATF_BLACK_LIST_YN = #{RISK_ELMT_CD2}
AND FATF_GREY_LIST_YN = #{RISK_ELMT_CD2}
AND FINCEN_LIST_YN = #{RISK_ELMT_CD2}
AND UN_SANTIONS_YN = #{RISK_ELMT_CD2}
AND OFAC_SANTIONS_YN = #{RISK_ELMT_CD2}
AND OECD_YN = #{RISK_ELMT_CD2}
AND TICPI_CPI_IDX_SCR = #{RISK_ELMT_CD2}
AND INCRS_PROD_YN = #{RISK_ELMT_CD2}
AND INCRS_CHEM_YN = #{RISK_ELMT_CD2}
AND EU_SANTIONS_YN = #{RISK_ELMT_CD2}
AND EU_HRT_YN = #{RISK_ELMT_CD2}
AND BASEL_RIK_IDX_SCR = #{RISK_ELMT_CD2}
AND RECAL_RA_SCR_CODE = #{RECAL_RA_SCR_NM}

