AND ABS_HRSK_YN IN ('Y','H')
--법률, 회계, 세무 관련 산업/직종 AND RA_CORJOB_YN1 = #{RISK_ELMT_CD2}
--투자자문 관련 산업/직종 AND RA_CORJOB_YN2 = #{RISK_ELMT_CD2}
--부동산 관련 산업/직종 AND RA_CORJOB_YN3 = #{RISK_ELMT_CD2}
--오락, 도박, 스포츠 관련 산업/직종 AND RA_CORJOB_YN4 = #{RISK_ELMT_CD2}
--카지노 AND RA_CORJOB_YN5 = #{RISK_ELMT_CD2}
--대부업자, 환전상, 소액해외송급업자 AND RA_CORJOB_YN6 = #{RISK_ELMT_CD2}
--귀금속, 예술품, 골동품 판매상 AND RA_CORJOB_YN7 = #{RISK_ELMT_CD2}
--주류 도소매업, 유흥주점업 AND RA_CORJOB_STA_YN1 = #{RISK_ELMT_CD2}
--의료,제약관련 AND RA_CORJOB_STA_YN2 = #{RISK_ELMT_CD2}
--건설산업 AND RA_IDJOB_STA_YN3 = #{RISK_ELMT_CD2}
--무기,방위산업 AND RA_CORJOB_STA_YN4 = #{RISK_ELMT_CD2}
--채광,금속,고물상 AND RA_CORJOB_STA_YN5 = #{RISK_ELMT_CD2}
--가상자산사업 의심 AND RA_CORJOB_YN8 = #{RISK_ELMT_CD2}
AND RECAL_RA_SCR_CODE = #{RECAL_RA_SCR_NM}

WITH CUST_TOTAL_CNT AS ( SELECT RA_GRD_CD, COUNT(RA_GRD_CD) AS CNT FROM ( SELECT /*+ FULL(RSLT) FULL(NIC35) USE_HASH(RSLT NIC35) PARALLEL(8)*/ RSLT.RNMCNO , NIC35.B_RSK_GRD_CD AS RA_GRD_CD , ROW_NUMBER()OVER (PARTITION BY RSLT.RNMCNO ORDER BY RA_ID DESC) RN FROM RA_CS_RA_RSLT RSLT , NIC35B NIC35 WHERE RSLT.RNMCNO = NIC35.RNMCNO
AND RSLT.CS_TYP_CD = #{CS_TYP_CD}
AND RSLT.NEW_OLD_GBN_CD = 'B' AND NIC35.B_CHECK_DAT BETWEEN TO_CHAR(ADD_MONTHS(SYSDATE,-12),'YYYYMMDD') AND TO_CHAR(SYSDATE,'YYYYMMDD') ) WHERE RN =1 GROUP BY RA_GRD_CD ), CUST_STR_CTR_CNT AS ( SELECT RA_GRD_CD , SUM(STR_CNT) AS STR_CNT , SUM(CTR_CNT) AS CTR_CNT FROM ( SELECT /*+ FULL(RSLT) FULL(NIC35) USE_HASH(RSLT NIC35)365 PARALLEL(8)*/ 'L' AS RA_GRD_CD , NIC35.STR_RPR_TNO AS STR_CNT , NIC35.CTR_RPR_TNO AS CTR_CNT , ROW_NUMBER()OVER (PARTITION BY RSLT.RNMCNO ORDER BY RA_ID DESC) RN FROM RA_CS_RA_RSLT RSLT , NIC35B NIC35 WHERE RSLT.RNMCNO = NIC35.RNMCNO
AND RSLT.CS_TYP_CD = #{CS_TYP_CD}
AND RSLT.NEW_OLD_GBN_CD = 'B' AND NIC35.B_RSK_GRD_CD = 'L' AND NIC35.B_CHECK_DAT BETWEEN TO_CHAR(ADD_MONTHS(SYSDATE,-12),'YYYYMMDD') AND TO_CHAR(SYSDATE,'YYYYMMDD') ) WHERE RN =1 GROUP BY RA_GRD_CD UNION ALL SELECT RA_GRD_CD , SUM(STR_CNT) AS STR_CNT , SUM(CTR_CNT) AS CTR_CNT FROM ( SELECT /*+ FULL(RSLT) FULL(NIC35) USE_HASH(RSLT NIC35) PARALLEL(8)*/ 'M' AS RA_GRD_CD , NIC35.STR_RPR_TNO AS STR_CNT , NIC35.CTR_RPR_TNO AS CTR_CNT , ROW_NUMBER()OVER (PARTITION BY RSLT.RNMCNO ORDER BY RA_ID DESC) RN FROM RA_CS_RA_RSLT RSLT , NIC35B NIC35 WHERE RSLT.RNMCNO = NIC35.RNMCNO
AND RSLT.CS_TYP_CD = #{CS_TYP_CD}
AND RSLT.NEW_OLD_GBN_CD = 'B' AND NIC35.B_RSK_GRD_CD = 'M' AND NIC35.B_CHECK_DAT BETWEEN TO_CHAR(ADD_MONTHS(SYSDATE,-12),'YYYYMMDD') AND TO_CHAR(SYSDATE,'YYYYMMDD') ) WHERE RN =1 GROUP BY RA_GRD_CD UNION ALL SELECT RA_GRD_CD , SUM(STR_CNT) AS STR_CNT , SUM(CTR_CNT) AS CTR_CNT FROM ( SELECT /*+ FULL(RSLT) FULL(NIC35) USE_HASH_AGGPE(RSLT NIC35) PARALLEL(8)*/ 'H' AS RA_GRD_CD , NIC35.STR_RPR_TNO AS STR_CNT , NIC35.CTR_RPR_TNO AS CTR_CNT , ROW_NUMBER()OVER (PARTITION BY RSLT.RNMCNO ORDER BY RA_ID DESC) RN FROM RA_CS_RA_RSLT RSLT , NIC35B NIC35 WHERE RSLT.RNMCNO = NIC35.RNMCNO
AND RSLT.CS_TYP_CD = #{CS_TYP_CD}
AND RSLT.NEW_OLD_GBN_CD = 'B' AND NIC35.B_RSK_GRD_CD = 'H' AND NIC35.B_CHECK_DAT BETWEEN TO_CHAR(ADD_MONTHS(SYSDATE,-12),'YYYYMMDD') AND TO_CHAR(SYSDATE,'YYYYMMDD') ) WHERE RN =1 GROUP BY RA_GRD_CD ) SELECT RA_GRD_SEQ , RA_GRD_CD , RA_GRD_NM , TOTAL_CNT , STR_CNT , STR_PER , CTR_CNT , CTR_PER FROM ( SELECT CASE WHEN RA_GRD_CD = 'H' THEN '1' WHEN RA_GRD_CD = 'M' THEN '2' ELSE '3' END AS RA_GRD_SEQ , RA_GRD_CD , RA_GRD_NM , TOTAL_CNT , STR_CNT , CASE WHEN STR_CNT = 0 OR TOTAL_CNT = 0 THEN '0 %' ELSE TO_CHAR(ROUND((STR_CNT/TOTAL_CNT)*100,2),'FM99999990.00') || ' %' END AS STR_PER , CTR_CNT , CASE WHEN CTR_CNT = 0 OR TOTAL_CNT = 0 THEN '0 %' ELSE TO_CHAR(ROUND((CTR_CNT/TOTAL_CNT)*100,2),'FM99999990.00') || ' %' END AS CTR_PER FROM ( SELECT /*+ MATERIALIZE FULL(A) FULL(B) USE_HASH(A B) PARALLEL(8)*/ CASE WHEN A.RA_GRD_CD = 'H' THEN '고위험' WHEN A.RA_GRD_CD = 'M' THEN '중위험' WHEN A.RA_GRD_CD = 'L' THEN '저위험' ELSE '' END AS RA_GRD_NM , A.RA_GRD_CD , NVL(A.CNT,0) AS TOTAL_CNT , NVL(B.STR_CNT,0) AS STR_CNT , NVL(B.CTR_CNT,0) AS CTR_CNT FROM CUST_TOTAL_CNT A , CUST_STR_CTR_CNT B WHERE A.RA_GRD_CD = B.RA_GRD_CD ) ) ORDER BY RA_GRD_SEQ

WITH RA_WGHT_REQ AS ( SELECT CS_TYP_CD , RA_ITEM_CD , RA_ITEM_WGHT FROM RA_ITEM_WGHT_REQ WHERE CS_TYP_CD = #{CS_TYP_CD} AND NEW_OLD_GBN_CD = 'B' UNION SELECT #{CS_TYP_CD} AS CS_TYP_CD , RA_ITEM_CD , 1 FROM RA_ITEM WHERE RA_ITEM_CD IN ('I009','I011','I012','I013','I014','I018') ) , RA_RNMCNO AS ( SELECT /*+ FULL(A) PARALLEL(8) */RNMCNO, CS_TYP_CD, NEW_OLD_GBN_CD, RA_GRD_SCR2, RA_GRD_SCR, EDD_YN1, EDD_YN2, EDD_YN3, EDD_YN4, EDD_YN5, EDD_YN6, EDD_YN7, EDD_YN16, EDD_YN17 FROM ( SELECT RNMCNO , MAX(CS_TYP_CD) AS CS_TYP_CD , MAX(NEW_OLD_GBN_CD) AS NEW_OLD_GBN_CD , TRUNC(SUM(RA_ITEM_WGHT)) AS RA_GRD_SCR2 , (TRUNC(SUM(RA_ITEM_WGHT))/10) AS RA_GRD_SCR , DECODE(SUM(EDD_YN1),1,'Y','N') AS EDD_YN1 , DECODE(SUM(EDD_YN2),1,'Y','N') AS EDD_YN2 , DECODE(SUM(EDD_YN3),1,'Y','N') AS EDD_YN3 , DECODE(SUM(EDD_YN4),1,'Y','N') AS EDD_YN4 , DECODE(SUM(EDD_YN5),1,'Y','N') AS EDD_YN5 , DECODE(SUM(EDD_YN6),1,'Y','N') AS EDD_YN6 , DECODE(SUM(EDD_YN7),1,'Y','N') AS EDD_YN7 , DECODE(SUM(EDD_YN16),1,'Y','N') AS EDD_YN16 , DECODE(SUM(EDD_YN17),1,'Y','N') AS EDD_YN17 FROM ( SELECT A.RNMCNO , A.RA_ITEM_CD , A.CS_TYP_CD , A.NEW_OLD_GBN_CD , CASE WHEN A.RA_ITEM_CD = 'I001' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'I009' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'I011' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'I012' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'I013' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'I014' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'I018' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B001' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B002' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B003' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B004' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B005' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B006' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B007' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B008' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B009' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B010' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B011' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B012' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B013' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B014' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B015' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B016' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B017' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B018' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B019' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT WHEN A.RA_ITEM_CD = 'B020' THEN A.RA_ITEM_SCR * B.RA_ITEM_WGHT END AS RA_ITEM_WGHT , CASE WHEN (CASE WHEN A.RA_ITEM_CD = 'I001' AND A.RA_ITEM_VAL = (SELECT RA_ITEM_VAL FROM RA_ITEM_SCR B WHERE A.RA_ITEM_VAL = B.RA_ITEM_VAL AND RA_ITEM_CD = 'I001') THEN (SELECT ABS_HRSK_YN FROM RA_ITEM_SCR B WHERE A.RA_ITEM_VAL = B.RA_ITEM_VAL AND RA_ITEM_CD = 'I001') END) IN ('Y','H') THEN 1 ELSE 0 END AS EDD_YN1 , CASE WHEN A.RA_ITEM_CD = 'I009' AND A.RA_ITEM_VAL = '02' THEN 1 ELSE 0 END AS EDD_YN2 , CASE WHEN A.RA_ITEM_CD = 'I011' AND A.RA_ITEM_VAL = '02' THEN 1 ELSE 0 END AS EDD_YN3 , CASE WHEN A.RA_ITEM_CD = 'I012' AND A.RA_ITEM_VAL = '02' THEN 1 ELSE 0 END AS EDD_YN4 , CASE WHEN A.RA_ITEM_CD = 'I013' AND A.RA_ITEM_VAL = '02' THEN 1 ELSE 0 END AS EDD_YN5 , CASE WHEN A.RA_ITEM_CD = 'I014' AND A.RA_ITEM_VAL = '02' THEN 1 ELSE 0 END AS EDD_YN6 , CASE WHEN A.RA_ITEM_CD = 'I018' AND A.RA_ITEM_VAL = '02' THEN 1 ELSE 0 END AS EDD_YN7 , CASE WHEN A.RA_ITEM_CD = 'B019' AND A.RA_ITEM_VAL = '01' THEN 1 ELSE 0 END AS EDD_YN16 , CASE WHEN (CASE WHEN A.RA_ITEM_CD = 'B020' AND A.RA_ITEM_VAL = (SELECT RA_ITEM_VAL FROM RA_ITEM_SCR B WHERE A.RA_ITEM_VAL = B.RA_ITEM_VAL AND RA_ITEM_CD = 'B020') THEN (SELECT ABS_HRSK_YN FROM RA_ITEM_SCR B WHERE A.RA_ITEM_VAL = B.RA_ITEM_VAL AND RA_ITEM_CD = 'B020') END) = 'Y' THEN 1 ELSE 0 END AS EDD_YN17 FROM RA_WGHT_REQ B , ( SELECT A.RNMCNO, A.RA_ITEM_CD, A.RA_ITEM_SCR, A.CS_TYP_CD, A.RA_ITEM_VAL, A.NEW_OLD_GBN_CD FROM RA_CS_RA_RSLT_DTL A , ( SELECT RNMCNO, RA_ID FROM ( SELECT /*+ FULL(T) FULL(NIC35) USE_HASH(T NIC35) PARALLEL(8)*/T.RNMCNO, T.RA_ID , ROW_NUMBER()OVER (PARTITION BY T.RNMCNO ORDER BY RA_ID DESC) RN FROM RA_CS_RA_RSLT T , NIC35B NIC35 WHERE T.RNMCNO = NIC35.RNMCNO AND T.CS_TYP_CD = #{CS_TYP_CD} AND T.NEW_OLD_GBN_CD = 'B' AND NIC35.B_CHECK_DAT BETWEEN TO_CHAR(ADD_MONTHS(SYSDATE,-12),'YYYYMMDD') AND TO_CHAR(SYSDATE,'YYYYMMDD') ) WHERE RN = 1 ) B WHERE A.RNMCNO = B.RNMCNO AND A.RA_ID = B.RA_ID ) A WHERE A.CS_TYP_CD = B.CS_TYP_CD AND A.RA_ITEM_CD = B.RA_ITEM_CD ) GROUP BY RNMCNO ) ) , CUST_TOTAL_CNT2 AS ( SELECT RA_GRD_CD , COUNT(RA_GRD_CD) AS CNT FROM ( SELECT /*+ FULL(A) PARALLEL(8) */A.RNMCNO , A.CS_TYP_CD , A.NEW_OLD_GBN_CD , CASE WHEN A.EDD_YN1 = 'Y' THEN 'H' WHEN A.EDD_YN2 = 'Y' THEN 'H' WHEN A.EDD_YN3 = 'Y' THEN 'H' WHEN A.EDD_YN4 = 'Y' THEN 'H' WHEN A.EDD_YN5 = 'Y' THEN 'H' WHEN A.EDD_YN6 = 'Y' THEN 'H' WHEN A.EDD_YN7 = 'Y' THEN 'H' WHEN A.EDD_YN16 = 'Y' THEN 'H' WHEN A.EDD_YN17 = 'Y' THEN 'H' ELSE NVL( (SELECT RA_GRD_CD FROM RA_GRD_STD WHERE CS_TYP_CD = A.CS_TYP_CD AND NEW_OLD_GBN_CD = A.NEW_OLD_GBN_CD AND RA_GRD_SCR_MAX = (SELECT MIN(RA_GRD_SCR_MAX) FROM RA_GRD_STD WHERE CS_TYP_CD = A.CS_TYP_CD AND NEW_OLD_GBN_CD = A.NEW_OLD_GBN_CD AND A.RA_GRD_SCR < RA_GRD_SCR_MAX )
) , (SELECT RA_GRD_CD FROM RA_GRD_STD WHERE CS_TYP_CD = A.CS_TYP_CD AND NEW_OLD_GBN_CD = A.NEW_OLD_GBN_CD AND RA_GRD_SCR_MAX = (SELECT MAX(RA_GRD_SCR_MAX) FROM RA_GRD_STD WHERE CS_TYP_CD = A.CS_TYP_CD AND NEW_OLD_GBN_CD = A.NEW_OLD_GBN_CD) ) ) END AS RA_GRD_CD FROM RA_RNMCNO A ) GROUP BY RA_GRD_CD ) , CUST_TOTAL_CNT AS ( SELECT RNMCNO , RA_GRD_CD FROM ( SELECT /*+ FULL(A) PARALLEL(8) */A.RNMCNO , A.CS_TYP_CD , A.NEW_OLD_GBN_CD , CASE WHEN A.EDD_YN1 = 'Y' THEN 'H' WHEN A.EDD_YN2 = 'Y' THEN 'H' WHEN A.EDD_YN3 = 'Y' THEN 'H' WHEN A.EDD_YN4 = 'Y' THEN 'H' WHEN A.EDD_YN5 = 'Y' THEN 'H' WHEN A.EDD_YN6 = 'Y' THEN 'H' WHEN A.EDD_YN7 = 'Y' THEN 'H' WHEN A.EDD_YN16 = 'Y' THEN 'H' WHEN A.EDD_YN17 = 'Y' THEN 'H' ELSE NVL( (SELECT RA_GRD_CD FROM RA_GRD_STD WHERE CS_TYP_CD = A.CS_TYP_CD AND NEW_OLD_GBN_CD = A.NEW_OLD_GBN_CD AND RA_GRD_SCR_MAX = (SELECT MIN(RA_GRD_SCR_MAX) FROM RA_GRD_STD WHERE CS_TYP_CD = A.CS_TYP_CD AND NEW_OLD_GBN_CD = A.NEW_OLD_GBN_CD AND A.RA_GRD_SCR < RA_GRD_SCR_MAX )
) , (SELECT RA_GRD_CD FROM RA_GRD_STD WHERE CS_TYP_CD = A.CS_TYP_CD AND NEW_OLD_GBN_CD = A.NEW_OLD_GBN_CD AND RA_GRD_SCR_MAX = (SELECT MAX(RA_GRD_SCR_MAX) FROM RA_GRD_STD WHERE CS_TYP_CD = A.CS_TYP_CD AND NEW_OLD_GBN_CD = A.NEW_OLD_GBN_CD) ) ) END AS RA_GRD_CD FROM RA_RNMCNO A ) ) , CUST_STR_CTR_CNT AS ( SELECT /*+ FULL(A) PARALLEL(8) */ 'L' AS RA_GRD_CD , SUM(A.STR_RPR_TNO) AS STR_CNT , SUM(A.CTR_RPR_TNO) AS CTR_CNT FROM NIC35B A , CUST_TOTAL_CNT B WHERE A.RNMCNO = B.RNMCNO AND B.RA_GRD_CD = 'L' UNION ALL SELECT /*+ FULL(A) PARALLEL(8) */ 'M' AS RA_GRD_CD , SUM(A.STR_RPR_TNO) AS STR_CNT , SUM(A.CTR_RPR_TNO) AS CTR_CNT FROM NIC35B A , CUST_TOTAL_CNT B WHERE A.RNMCNO = B.RNMCNO AND B.RA_GRD_CD = 'M' UNION ALL SELECT /*+ FULL(A) PARALLEL(8) */ 'H' AS RA_GRD_CD , SUM(A.STR_RPR_TNO) AS STR_CNT , SUM(A.CTR_RPR_TNO) AS CTR_CNT FROM NIC35B A , CUST_TOTAL_CNT B WHERE A.RNMCNO = B.RNMCNO AND B.RA_GRD_CD = 'H' )
SELECT RA_GRD_SEQ , RA_GRD_CD , RA_GRD_NM , VAL AS RVAL , ROW_NUMBER() OVER (PARTITION BY RA_GRD_CD ORDER BY CASE COL WHEN 'TOTAL_CNT' THEN 1 WHEN 'STR_CNT' THEN 2 WHEN 'STR_PER' THEN 3 WHEN 'CTR_CNT' THEN 4 WHEN 'CTR_PER' THEN 5 END
) AS RN FROM (
SELECT RA_GRD_SEQ , RA_GRD_CD , RA_GRD_NM , TOTAL_CNT , STR_CNT , STR_PER , CTR_CNT , CTR_PER FROM ( SELECT CASE WHEN RA_GRD_CD = 'H' THEN '1' WHEN RA_GRD_CD = 'M' THEN '2' ELSE '3' END AS RA_GRD_SEQ , RA_GRD_CD , RA_GRD_NM , TOTAL_CNT , STR_CNT , CASE WHEN STR_CNT = 0 OR TOTAL_CNT = 0 THEN 0 ELSE ROUND((STR_CNT/TOTAL_CNT)*100,2) END AS STR_PER , CTR_CNT , CASE WHEN CTR_CNT = 0 OR TOTAL_CNT = 0 THEN 0 ELSE ROUND((CTR_CNT/TOTAL_CNT)*100,2) END AS CTR_PER FROM ( SELECT /*+ FULL(A) PARALLEL(8) */ CASE WHEN A.RA_GRD_CD = 'H' THEN '고위험' WHEN A.RA_GRD_CD = 'M' THEN '중위험' WHEN A.RA_GRD_CD = 'L' THEN '저위험' ELSE '' END AS RA_GRD_NM , A.RA_GRD_CD , NVL(A.CNT,0) AS TOTAL_CNT , NVL(B.STR_CNT,0) AS STR_CNT , NVL(B.CTR_CNT,0) AS CTR_CNT FROM CUST_TOTAL_CNT2 A , CUST_STR_CTR_CNT B WHERE A.RA_GRD_CD = B.RA_GRD_CD ) ) ORDER BY RA_GRD_SEQ ) UNPIVOT(VAL FOR COL IN (TOTAL_CNT, STR_CNT, STR_PER, CTR_CNT, CTR_PER))

