UPDATE NIC65B
   SET CNT = #{RVAL}
     , BRN_CD = #{RVAL}
 WHERE BAS_YYMM = 'RAWGHT'
   AND DATA_CCD = #{CS_TYP_CD}
   AND BIZ_RULE_CCD = #{RA_GRD_CD}
   AND CUST_CCD = #{RN}

		UPDATE RA_ITEM_NTN_SCR_APPR
		   SET NUM_SQ       = #{NUM_SQ}
             , APP_NO       = #{APP_NO}
             , APP_DT       = #{APP_DT}
             , NTN_SN_CCD   = #{SN_CCD}
             , HNDL_REG_DT  = SYSDATE
             , HNDL_REG_ID  = #{HNDL_P_ENO}
             , HNDL_DY_TM   = SYSDATE
             , HNDL_P_ENO   = #{HNDL_P_ENO}
		 WHERE RA_ITEM_CD   = #{RA_ITEM_CD}
		   AND NTN_SEQ    = #{RA_SEQ}

		UPDATE RA_ITEM_NTN_SCR_APPR_ONE
		   SET NUM_SQ       = #{NUM_SQ}
             , APP_NO       = #{APP_NO}
             , APP_DT       = #{APP_DT}
             , NTN_SN_CCD   = #{SN_CCD}
             , HNDL_REG_DT  = SYSDATE
             , HNDL_REG_ID  = #{HNDL_P_ENO}
             , HNDL_DY_TM   = SYSDATE
             , HNDL_P_ENO   = #{HNDL_P_ENO}
		 WHERE RA_ITEM_CD   = #{RA_ITEM_CD}
		   AND NTN_SEQ    = #{RA_SEQ}

		UPDATE RA_ITEM_IDJOB_SCR_APPR
		   SET NUM_SQ       = #{NUM_SQ}
             , APP_NO       = #{APP_NO}
             , APP_DT       = #{APP_DT}
             , IDJOB_SN_CCD = #{SN_CCD}
             , HNDL_REG_DT  = SYSDATE
             , HNDL_REG_ID  = #{HNDL_P_ENO}
             , HNDL_DY_TM   = SYSDATE
             , HNDL_P_ENO   = #{HNDL_P_ENO}
		 WHERE RA_ITEM_CD   = #{RA_ITEM_CD}
		   AND INJOB_SEQ    = #{RA_SEQ}

		UPDATE RA_ITEM_IDJOB_SCR_APPR_ONE
		   SET NUM_SQ       = #{NUM_SQ}
             , APP_NO       = #{APP_NO}
             , APP_DT       = #{APP_DT}
             , IDJOB_SN_CCD = #{SN_CCD}
             , HNDL_REG_DT  = SYSDATE
             , HNDL_REG_ID  = #{HNDL_P_ENO}
             , HNDL_DY_TM   = SYSDATE
             , HNDL_P_ENO   = #{HNDL_P_ENO}
		 WHERE RA_ITEM_CD   = #{RA_ITEM_CD}
		   AND INJOB_SEQ    = #{RA_SEQ}

		UPDATE RA_ITEM_CORJOB_SCR_APPR
		   SET NUM_SQ        = #{NUM_SQ}
             , APP_NO        = #{APP_NO}
             , APP_DT        = #{APP_DT}
             , CORJOB_SN_CCD = #{SN_CCD}
             , HNDL_REG_DT   = SYSDATE
             , HNDL_REG_ID   = #{HNDL_P_ENO}
             , HNDL_DY_TM    = SYSDATE
             , HNDL_P_ENO    = #{HNDL_P_ENO}
		 WHERE RA_ITEM_CD    = #{RA_ITEM_CD}
		   AND CORJOB_SEQ    = #{RA_SEQ}

		UPDATE RA_ITEM_CORJOB_SCR_APPR_ONE
		   SET NUM_SQ        = #{NUM_SQ}
             , APP_NO        = #{APP_NO}
             , APP_DT        = #{APP_DT}
             , CORJOB_SN_CCD = #{SN_CCD}
             , HNDL_REG_DT   = SYSDATE
             , HNDL_REG_ID   = #{HNDL_P_ENO}
             , HNDL_DY_TM    = SYSDATE
             , HNDL_P_ENO    = #{HNDL_P_ENO}
		 WHERE RA_ITEM_CD    = #{RA_ITEM_CD}
		   AND CORJOB_SEQ    = #{RA_SEQ}

		UPDATE RA_ITEM_COMMON_APPR
		   SET NUM_SQ        = #{NUM_SQ}
             , APP_NO        = #{APP_NO}
             , APP_DT        = #{APP_DT}
             , COMMON_SN_CCD = #{SN_CCD}
             , HNDL_REG_DT   = SYSDATE
             , HNDL_REG_ID   = #{HNDL_P_ENO}
             , HNDL_DY_TM    = SYSDATE
             , HNDL_P_ENO    = #{HNDL_P_ENO}
		 WHERE RA_ITEM_CD    = #{RA_ITEM_CD}
		   AND COMMON_SEQ    = #{RA_SEQ}

UPDATE RA_ITEM_WGHT_APPR
   SET NUM_SQ      = #{NUM_SQ}
     , APP_NO      = #{APP_NO}
     , APP_DT      = #{APP_DT}
     , WGHT_SN_CCD = #{SN_CCD}
     , REG_DT      = SYSDATE
     , REG_ID      = #{HNDL_P_ENO}
     , UPD_DT      = SYSDATE
     , UPD_ID      = #{HNDL_P_ENO}
 WHERE CS_TYP_CD      = #{CS_TYP_CD}
   AND NEW_OLD_GBN_CD = #{NEW_OLD_GBN_CD}
   AND WGHT_SEQ       = #{RA_SEQ}

UPDATE RA_GRD_STD_APPR
