SELECT A.* FROM ( SELECT PRD_CK.PRD_CK_ID , PRD_CK.VERSION_ID , PRD_CK.TITLE , PRD_CK.APP_NO , PRD_CK.REG_DT , PRD_CK.REG_ID , ( SELECT GET_LOGINID_NAME( PRD_CK.REG_ID ) FROM DUAL ) AS REG_NM , PRD_CK.UPD_DT , PRD_CK.UPD_ID , ( SELECT GET_LOGINID_NAME( PRD_CK.UPD_ID ) FROM DUAL ) AS UPD_NM -- , 'PRD01' AS APP_GUBUN -- , P.APP_NO , P.GYLJ_LINE_G_C , P.NUM_SQ -- , P.REG_DT -- , P.SN_CCD , CASE WHEN P.SN_CCD IS NULL THEN 'N' ELSE ( SELECT CNTNT FROM NIC92B WHERE CD = 'P001' AND CNTNT = P.SN_CCD ) END AS SN_CCD , CASE WHEN P.SN_CCD IS NULL THEN '임시저장' ELSE ( SELECT CD_NM FROM NIC92B WHERE CD = 'P001' AND CNTNT = P.SN_CCD ) END AS SN_CCD_NM , CASE WHEN P.SN_CCD = 'E' THEN P.APP_DT ELSE '-' END AS APP_FNSH_DT , P.APP_DT , P.GYLJ_ROLE_ID , P.GYLJ_ROLE_NM , P.APPR_ROLE_ID , P.APPR_ROLE_NM , P.TARGET_ROLE_ID , P.TARGET_ROLE_NM , P.RSN_CNTNT FROM KYC_PRD_CK PRD_CK LEFT OUTER JOIN ( SELECT M.APP_NO , M.GYLJ_LINE_G_C , M.SNO , M.NUM_SQ , M.SN_CCD , M.APP_DT , M.REG_DT , S.GYLJ_ROLE_ID , ( SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = GYLJ_ROLE_ID ) AS GYLJ_ROLE_NM , M.APPR_ROLE_ID , ( SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.APPR_ROLE_ID ) AS APPR_ROLE_NM , M.TARGET_ROLE_ID , ( SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.TARGET_ROLE_ID ) AS TARGET_ROLE_NM , M.RSN_CNTNT FROM AML_APPR M , C_GYLJ_D S WHERE S.GYLJ_LINE_G_C = 'PRD01' AND S.GYLJ_LINE_G_C = M.GYLJ_LINE_G_C AND S.SNO = M.SNO AND ( M.APP_NO, M.NUM_SQ ) IN ( SELECT /*+ IDEX(M PK_AML_APPR) */ T.APP_NO , MAX(T.NUM_SQ) FROM AML_APPR T WHERE T.APP_NO = M.APP_NO AND T.GYLJ_LINE_G_C = 'PRD01' GROUP BY T.APP_NO ) ) P ON ( PRD_CK.APP_NO = P.APP_NO ) WHERE 1=1
AND PRD_CK.TITLE LIKE '%' || #{TITLE} || '%'
) A WHERE 1=1
AND A.SN_CCD = 'E' -- 최종결재상태 T:요청,S:승인,R:반려,E:결재완료 AND A.APP_DT >= TO_CHAR( #{APPR_SD_DT} || '00000000') AND A.APP_DT <= TO_CHAR( #{APPR_ED_DT} || '99999999')
