SELECT A.* FROM ( SELECT A.PRD_EVLTN_ID , A.PRD_CK_ID , A.PRD_CTGR_CD , ( SELECT C.CD_NM FROM NIC92B C WHERE C.CD = 'P201' AND C.CNTNT = A.PRD_CTGR_CD ) AS PRD_CTGR_CD_NM , A.PRD_TP_CD , CASE WHEN A.PRD_CTGR_CD = 'SVC' THEN ( SELECT C.CD_NM FROM NIC92B C WHERE C.CD = 'P203' AND C.CNTNT = A.PRD_TP_CD ) ELSE ( SELECT C.CD_NM FROM NIC92B C WHERE C.CD = 'P202' AND C.CNTNT = A.PRD_TP_CD ) END AS PRD_TP_CD_NM , A.PRD_NM , A.EVLTN_DEPT_ID , B.DEP_TITLE AS EVLTN_DEPT_NM , A.EVLTN_USER_ID , C.USER_NM AS EVLTN_USER_NM , A.RLS_EXPCT_DT , A.EVLTN_PRF_DT , A.PRD_RMRK , A.SMRY_OPNN , A.PRD_CD , CASE WHEN A.RSNB_EDD_YN = 'Y' THEN '30104' ELSE A.RSK_GRD END AS RSK_GRD , A.CNTRL_RVW_YN , A.RSNB_EDD_YN , A.EVLTN_STATE , ( SELECT C.CD_NM FROM NIC92B C WHERE C.CD = 'P002' AND C.CNTNT = A.EVLTN_STATE ) AS EVLTN_STATE_NM , A.APP_NO , A.REG_DT , P.GYLJ_LINE_G_C , P.NUM_SQ , CASE WHEN P.SN_CCD IS NULL THEN 'N' ELSE ( SELECT CNTNT FROM NIC92B WHERE CD = 'P002' AND CNTNT = P.SN_CCD ) END AS SN_CCD , CASE WHEN P.SN_CCD IS NULL THEN '임시저장' ELSE ( SELECT CD_NM FROM NIC92B WHERE CD = 'P002' AND CNTNT = P.SN_CCD ) END AS SN_CCD_NM , CASE WHEN P.SN_CCD = 'E' THEN P.APP_DT ELSE '-' END AS APP_FNSH_DT , P.APP_DT , P.GYLJ_ROLE_ID , P.GYLJ_ROLE_NM , P.APPR_ROLE_ID , P.APPR_ROLE_NM , P.TARGET_ROLE_ID , P.TARGET_ROLE_NM FROM KYC_PRD_EVLTN A LEFT OUTER JOIN C_DEP_INFO B ON A.EVLTN_DEPT_ID = B.DEP_ID LEFT OUTER JOIN C_USER C ON A.EVLTN_USER_ID = C.LOGIN_ID LEFT OUTER JOIN ( SELECT M.APP_NO , M.GYLJ_LINE_G_C , M.SNO , M.NUM_SQ , M.SN_CCD , M.APP_DT , M.REG_DT , S.GYLJ_ROLE_ID , ( SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = GYLJ_ROLE_ID ) AS GYLJ_ROLE_NM , M.APPR_ROLE_ID , ( SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.APPR_ROLE_ID ) AS APPR_ROLE_NM , M.TARGET_ROLE_ID , ( SELECT C.ROLE_NM FROM C_ROLE C WHERE C.ROLE_ID = M.TARGET_ROLE_ID ) AS TARGET_ROLE_NM FROM AML_APPR M , C_GYLJ_D S WHERE S.GYLJ_LINE_G_C IN ('PRD02','RA5') AND S.GYLJ_LINE_G_C = M.GYLJ_LINE_G_C AND S.SNO = M.SNO AND ( M.APP_NO, M.NUM_SQ ) IN ( SELECT /*+ IDEX(M PK_AML_APPR) */ T.APP_NO , MAX(T.NUM_SQ) FROM AML_APPR T WHERE T.APP_NO = M.APP_NO AND T.GYLJ_LINE_G_C IN ('PRD02','RA5') GROUP BY T.APP_NO ) ) P ON ( A.APP_NO = P.APP_NO ) WHERE 1=1
AND A.PRD_CTGR_CD = #{PRD_CTGR_CD}
AND A.PRD_TP_CD = #{PRD_TP_CD}
AND A.EVLTN_PRF_DT >= #{EVLTN_SD_DT} AND A.EVLTN_PRF_DT <= #{EVLTN_ED_DT}
