Q) FROM AML_APPR T WHERE T.APP_NO = M.APP_NO AND T.GYLJ_LINE_G_C = 'PRD02' GROUP BY T.APP_NO ) ) P ON ( A.APP_NO = P.APP_NO ) WHERE 1=1
AND A.PRD_CTGR_CD = #{PRD_CTGR_CD}
