 		  FROM C_DEP_INFO
		 WHERE DEP_DESC = #{DEP_DESC}

SELECT GDS_TYP /* 상품유형 */ , PRDT_ALIS /* 상품별칭(상품코드) */ , PRDT_NM /* 상품명 */ , PCPR_ID /* 상품ID */ , DTBR_CODE /* 부지점코드(상품등록부서) */ , (SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = DTBR_CODE) AS DTBR_CODE_NM , EMPY_NAME /* 사원명 */ , EMPY_NO /* 사원번호 */ , RTNG_APLY_DATE /* 등급적용일자(상품등록일) */ , ALIAS_PRDT_ALIS /* 상품별칭(평가일련번호) */ , RTNG_AGNY_RTNG_VALU /* 평가사등급값(위험등급코드) */ , PRD_EVLTN_ID /* 임시평가일련번호 */ , PRD_NM /* 임시평가명 */ , RSK_GRD /* 위험등급 */ , RSK_GRD_NM /* 위험등급명 */ , EVLTN_DEPT_ID /* 평가부서ID */ , EVLTN_USER_ID /* 평가자ID */ , EVLTN_PRF_DT /* 평가일자 */ FROM ( SELECT CASE WHEN D.PRDT_ALIS_TYPE_CODE = 'SFDC' THEN '펀드' WHEN D.PRDT_ALIS_TYPE_CODE = 'WSCD' THEN '랩' END AS GDS_TYP /* 상품유형 */ , D.PRDT_ALIS /* 상품별칭(상품코드) */ , (SELECT PRDT_NAME FROM SID.IDO_A_UUP_PRODUCT_NAME WHERE PRDT_ID = B.PRDT_ID AND PRDT_NAME_TYPE_CODE = 'NAME' AND LANG_CODE = 'KO') AS PRDT_NM /* 상품명 */ , B.PCPR_ID /* 상품ID */ , (SELECT DTBR_CODE FROM SID.IDO_A_UWA_USER X , SID.IDO_A_UUE_SAMSUNG_DPRT Y WHERE X.DTBR_ENTY_ID = Y.ENTY_ID AND X.USER_ID = TRIM(B.PCPR_ID)) AS DTBR_CODE /* 부지점코드(상품등록부서) */ , (SELECT USER_NAME FROM SID.IDO_A_UWA_USER WHERE USER_ID = TRIM(B.PCPR_ID)) AS EMPY_NAME /* 사원명 */ , (SELECT USER_ID FROM SID.IDO_A_UWA_USER WHERE USER_ID = TRIM(B.PCPR_ID)) AS EMPY_NO /* 사원번호 */ , A.RTNG_APLY_DATE /* 등급적용일자(상품등록일) */ , RTRIM(B.PRDT_ALIS) AS ALIAS_PRDT_ALIS /* 상품별칭(평가일련번호) */ , RTRIM(A.RTNG_AGNY_RTNG_VALU) AS RTNG_AGNY_RTNG_VALU /* 평가사등급값(위험등급코드) */ , C.PRD_EVLTN_ID /* 임시평가일련번호 */ , C.PRD_NM /* 임시평가명 */ , C.RSK_GRD /* 위험등급 */ , CASE WHEN C.RSK_GRD = '30103' AND C.RSNB_EDD_YN = 'Y' THEN '당연고위험' WHEN C.RSK_GRD = '30103' THEN '고위험' WHEN C.RSK_GRD = '30102' THEN '중위험' WHEN C.RSK_GRD = '30101' THEN '저위험' END AS RSK_GRD_NM , C.EVLTN_DEPT_ID /* 평가부서ID */ , C.EVLTN_USER_ID /* 평가자ID */ , C.EVLTN_PRF_DT /* 평가일자 */ FROM SID.IDO_A_UUM_RATING A , SID.IDO_A_UUP_PRODUCT_ALIAS B , SSQ.KYC_PRD_EVLTN C , SID.IDO_A_UUP_PRODUCT_ALIAS D WHERE B.PRDT_ID = A.PRDT_ID AND 'PE00' || SUBSTR(B.PRDT_ALIS,5,1) = C.PRD_EVLTN_ID AND B.PRDT_ID = D.PRDT_ID AND TRIM(B.PRDT_ALIS_TYPE_CODE) = 'FLVS' /* 상품별칭유형코드 (FLVS:자금세탁평가번호) */ AND A.ENTY_PRDT_TYPE_CODE = 'PRDT' /* 엔티티상품유형코드 (PRDT:상품) */ AND A.VLTN_SCHM_CODE = 'FLRT' /* 평가스키마코드 (FLRT:자금세탁위험등급) */ AND B.PRDT_ALIS LIKE 'TEMP%' AND D.PRDT_ALIS_TYPE_CODE IN ('SFDC', 'WSCD') AND A.RTNG_APLY_DATE BETWEEN #{REG_SD_DT} AND #{REG_ED_DT} ) WHERE 1=1
AND DTBR_CODE = #{BRN_CD_tab}
ORDER BY RTNG_APLY_DATE DESC

SELECT CASE WHEN ROW_NUMBER() OVER (PARTITION BY PRD_TP_NM, PRD_EVLTN_ID ORDER BY BA_PRCE_DATE_TIME DESC) = 1 THEN PRD_TP_NM ELSE NULL END AS PRD_TP_NM /* 상품유형 */ , CASE WHEN ROW_NUMBER() OVER (PARTITION BY PRD_TP_NM, PRD_EVLTN_ID ORDER BY BA_PRCE_DATE_TIME DESC) = 1 THEN PRD_EVLTN_ID ELSE NULL END AS PRD_EVLTN_ID /* 평가일련번호 */ , CASE WHEN ROW_NUMBER() OVER (PARTITION BY PRD_TP_NM, PRD_EVLTN_ID ORDER BY BA_PRCE_DATE_TIME DESC) = 1 THEN PRD_NM ELSE NULL END AS PRD_NM /* 상품서비스명 */ , CASE WHEN ROW_NUMBER() OVER (PARTITION BY PRD_TP_NM, PRD_EVLTN_ID ORDER BY BA_PRCE_DATE_TIME DESC) = 1 THEN RSK_GRD ELSE NULL END AS RSK_GRD /* 위험등급 */ , CASE WHEN ROW_NUMBER() OVER (PARTITION BY PRD_TP_NM, PRD_EVLTN_ID ORDER BY BA_PRCE_DATE_TIME DESC) = 1 THEN RSK_GRD_NM ELSE NULL END AS RSK_GRD_NM /* 위험등급명 */ , CASE WHEN ROW_NUMBER() OVER (PARTITION BY PRD_TP_NM, PRD_EVLTN_ID ORDER BY BA_PRCE_DATE_TIME DESC) = 1 THEN EVLTN_PRF_DT ELSE NULL END AS EVLTN_PRF_DT /* 평가일자 */ , PRDT_ALIS /* 상품별칭(상품코드) */ , PRDT_ALIS_B /* 상품별칭(상품코드) */ , PCPR_ID /* 상품ID */ , PRDT_NM /* 상품명 */ , DTBR_CODE /* 부지점코드(상품등록부서) */ , (SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = DTBR_CODE) AS DTBR_CODE_NM , EMPY_NO /* 사원번호 */ , EMPY_NAME /* 사원명 */ , PRCE_DATE_TIME /* 상품등록일 */ , BA_PRCE_DATE_TIME , IFMN_LAST_PRCE_DATE_TIME /* 상품등록일 */ , BA_IFMN_LAST_PRCE_DATE_TIME , CONFIRM_YN /* 확인여부 */ , CONFIRM_NM /* 확인여부명 */ , CONFIRM_DT /* 확인일자 */ , CONFIRM_DT2 /* 확인일자 */ FROM ( SELECT TRIM(A.PRDT_ALIS) AS PRDT_ALIS /* 상품별칭(상품코드) */ , B.PRDT_ALIS AS PRDT_ALIS_B /* 상품별칭(상품코드) */ , TRIM(A.PCPR_ID) AS PCPR_ID /* 상품ID */ , (SELECT PRDT_NAME FROM SID.IDO_A_UUP_PRODUCT_NAME WHERE PRDT_ID = B.PRDT_ID AND PRDT_NAME_TYPE_CODE = 'NAME' AND LANG_CODE = 'KO') AS PRDT_NM /* 상품명 */ , (SELECT DTBR_CODE FROM SID.IDO_A_UWA_USER X, SID.IDO_A_UUE_SAMSUNG_DPRT Y WHERE X.DTBR_ENTY_ID = Y.ENTY_ID AND X.USER_ID = TRIM(A.PCPR_ID)) AS DTBR_CODE /* 부지점코드(상품등록부서) */ , (SELECT USER_NAME FROM SID.IDO_A_UWA_USER WHERE USER_ID = TRIM(A.PCPR_ID)) AS EMPY_NAME /* 사원명 */ , (SELECT USER_ID FROM SID.IDO_A_UWA_USER WHERE USER_ID = TRIM(A.PCPR_ID)) AS EMPY_NO /* 사원번호 */ , TO_CHAR(A.PRCE_DATE_TIME, 'YYYYMMDD') AS PRCE_DATE_TIME , A.PRCE_DATE_TIME AS BA_PRCE_DATE_TIME , TO_CHAR(A.IFMN_LAST_PRCE_DATE_TIME, 'YYYYMMDD') AS IFMN_LAST_PRCE_DATE_TIME , A.IFMN_LAST_PRCE_DATE_TIME AS BA_IFMN_LAST_PRCE_DATE_TIME , C.PRD_CTGR_CD /* 상품/서비스 구분 */ , C.PRD_TP_CD /* 상품유형코드 */ , GET_CODE_NAME('P202', C.PRD_TP_CD) AS PRD_TP_NM /* 상품유형명 */ , C.PRD_EVLTN_ID /* 평가일련번호 */ , C.PRD_NM /* 상품/서비스명 */ , C.RSK_GRD /* 위험등급 */ , CASE WHEN C.RSK_GRD = '30103' AND C.RSNB_EDD_YN = 'Y' THEN '당연고위험' WHEN C.RSK_GRD = '30103' THEN '고위험' WHEN C.RSK_GRD = '30102' THEN '중위험' WHEN C.RSK_GRD = '30101' THEN '저위험' END AS RSK_GRD_NM , C.EVLTN_DEPT_ID /* 평가부서ID */ , C.EVLTN_USER_ID /* 평가자ID */ , C.EVLTN_PRF_DT /* 평가일자 */ , CASE WHEN D.CONFIRM_YN = 'E' THEN 'E' ELSE 'N' END CONFIRM_YN /* 확인여부 */ , CASE WHEN D.CONFIRM_YN = 'E' THEN '확인완료' ELSE '미확인' END AS CONFIRM_NM , D.CONFIRM_DT /* 확인일자 */ , TO_CHAR(D.CONFIRM_DT,'YYYY-MM-DD') AS CONFIRM_DT2 FROM SID.IDO_A_UUP_PRODUCT_ALIAS A , SID.IDO_A_UUP_PRODUCT_ALIAS B , KYC_PRD_EVLTN C , DERIVED_PRODUCT D WHERE A.PRDT_ID = B.PRDT_ID AND TRIM(A.PRDT_ALIS) = C.PRD_EVLTN_ID AND TRIM(B.PRDT_ALIS) = D.PRD_EVLTN_ID(+) AND TRIM(A.PRDT_ALIS_TYPE_CODE) = 'FLVS' AND B.PRDT_ALIS_TYPE_CODE IN ('SFDC', 'WSCD') AND A.PRDT_ALIS IN (SELECT PRDT_ALIS FROM SID.IDO_A_UUP_PRODUCT_ALIAS WHERE TRIM(PRDT_ALIS_TYPE_CODE) = 'FLVS' AND PRDT_ALIS NOT LIKE 'TEMP%' GROUP BY PRDT_ALIS HAVING COUNT(*) > 1) ) WHERE 1=1 AND PRCE_DATE_TIME BETWEEN #{REG_SD_DT} AND #{REG_ED_DT}
AND DTBR_CODE = #{BRN_CD_tab}
AND CONFIRM_YN = #{CONFIRM_YN}
ORDER BY PRDT_ALIS DESC, BA_PRCE_DATE_TIME DESC
